-- Poems batch 68
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e4354c00-c83e-43da-9341-7007889dd625','過香積寺','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u4e94\u8a00\u5f8b\u8bd7"]','不知香積寺，數里入雲峰。',48,'全唐诗/poet.tang.6000.json','["不知香積寺，數里入雲峰。", "古木無人逕，深山何處鐘。", "泉聲咽危石，日色冷青松。", "薄暮空潭曲，安禪制毒龍。"]'),
('f9b87c32-b12b-498f-9988-501a50e9d27e','過感化寺曇興上人山院','王維','唐','唐诗','tang','','[]','暮持筇竹杖，相待虎谿頭。',48,'全唐诗/poet.tang.6000.json','["暮持筇竹杖，相待虎谿頭。", "催客聞山響，歸房逐水流。", "野花叢發好，谷鳥一聲幽。", "夜坐空林寂，松風直似秋。"]'),
('fd260e2f-fd85-4464-9589-37744e39c7f8','夏日過青龍寺謁操禪師','王維','唐','唐诗','tang','','[]','龍鍾一老翁，徐步謁禪宮。',48,'全唐诗/poet.tang.6000.json','["龍鍾一老翁，徐步謁禪宮。", "欲問義心義，遙知空病空。", "山河天眼裏，世界法身中。", "莫怪銷炎熱，能生大地風。"]'),
('0acfb9ff-839d-46d5-81cb-248a546da7e0','登辨覺寺','王維','唐','唐诗','tang','','[]','竹徑從初地，蓮峰出化城。',48,'全唐诗/poet.tang.6000.json','["竹徑從初地，蓮峰出化城。", "窗中三楚盡，林上九江平。", "軟草承趺坐，長松響梵聲。", "空居法雲外，觀世得無生。"]'),
('3a21432b-5303-4025-af6a-92c04037393c','喜祖三至留宿','王維','唐','唐诗','tang','','[]','門前洛陽客，下馬拂征衣。',48,'全唐诗/poet.tang.6000.json','["門前洛陽客，下馬拂征衣。", "不枉故人駕，平生多掩扉。", "行人返深巷，積雪帶餘暉。", "早歲同袍者，高車何處歸。"]'),
('71bdf7b5-493f-41e8-b0cf-6f1acd7bb8ea','黎拾遺昕裴秀才迪見過秋夜對雨之作','王維','唐','唐诗','tang','','[]','促織鳴已急，輕衣行向重。',48,'全唐诗/poet.tang.6000.json','["促織鳴已急，輕衣行向重。", "寒燈坐高館，秋雨聞疎鐘。", "白法調狂象，玄言問老龍。", "何人顧蓬徑，空愧求羊蹤。"]'),
('b5b56a19-8b98-4755-ad3a-a0da6b6612da','慕容承攜素饌見過','王維','唐','唐诗','tang','','[]','紗帽烏皮几，閑居懶賦詩。',48,'全唐诗/poet.tang.6000.json','["紗帽烏皮几，閑居懶賦詩。", "門看五柳識，年筭六身知。", "靈壽君王賜，彫胡弟子炊。", "空勞酒食饌，持底解人頤。"]'),
('a47c06ac-69d2-4395-953d-e56efcfc4eb3','晚春嚴少尹與諸公見過','王維','唐','唐诗','tang','','[]','松菊荒三逕，圖書共五車。',48,'全唐诗/poet.tang.6000.json','["松菊荒三逕，圖書共五車。", "烹葵邀上客，看竹到貧家。", "鵲乳先春草，鶯啼過落花。", "自憐黃髪暮，一倍惜年華。"]'),
('d2d687a3-fdce-4d68-93dd-ce9195d5925e','鄭果州相過','王維','唐','唐诗','tang','','[]','麗日照殘春，初晴草木新。',48,'全唐诗/poet.tang.6000.json','["麗日照殘春，初晴草木新。", "牀前磨鏡客，樹下灌園人。", "五馬驚窮巷，雙童逐老身。", "中廚辦麤飯，當恕阮家貧。"]'),
('00f12a19-bb96-4980-a4f5-11a1b9d604dd','山居秋暝','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5c71\u6c34", "\u5199\u666f", "\u79cb\u96e8", "\u4e94\u8a00\u5f8b\u8bd7", "\u5199\u4eba"]','空山新雨後，天氣晚來秋。',48,'全唐诗/poet.tang.6000.json','["空山新雨後，天氣晚來秋。", "明月松間照，清泉石上流。", "竹喧歸浣女，蓮動下漁舟。", "隨意春芳歇，王孫自可留。"]'),
('6d098c75-038d-45f4-8f86-73976c355e44','終南別業','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u7530\u56ed", "\u6292\u60c5", "\u4e94\u8a00\u5f8b\u8bd7", "\u5c71", "\u5199\u4eba"]','中歲頗好道，晚家南山陲。',48,'全唐诗/poet.tang.6000.json','["中歲頗好道，晚家南山陲。", "興來每獨往，勝事空自知。", "行到水窮處，坐看雲起時。", "偶然值林叟，談笑無還期。"]'),
('40cd6eec-c6ce-4659-a225-61063cd210e9','歸嵩山作','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5c71\u6c34", "\u5199\u666f", "\u6292\u60c5", "\u4e94\u8a00\u5f8b\u8bd7"]','清川帶長薄，車馬去閑閑。',48,'全唐诗/poet.tang.6000.json','["清川帶長薄，車馬去閑閑。", "流水如有意，暮禽相與還。", "荒城臨古渡，落日滿秋山。", "迢遞嵩高下，歸來且閉關。"]'),
('6146d9b1-b526-4c8e-86be-ea0be3c72375','歸輞川作','王維','唐','唐诗','tang','','[]','谷口疎鐘動，漁樵稍欲稀。',48,'全唐诗/poet.tang.6000.json','["谷口疎鐘動，漁樵稍欲稀。", "悠然遠山暮，獨向白雲歸。", "菱蔓弱難定，楊花輕易飛。", "東臯春草色，惆悵掩柴扉。"]'),
('142d78a3-2f2b-4652-8cd0-e8ef74aef212','韋給事山居','王維','唐','唐诗','tang','','[]','幽尋得此地，詎有一人曾。',48,'全唐诗/poet.tang.6000.json','["幽尋得此地，詎有一人曾。", "大壑隨階轉，羣山入戶登。", "庖廚出深竹，印綬隔垂藤。", "即事辭軒冕，誰云病未能。"]'),
('304699b5-7b28-445c-8e97-1b3c4431e69d','山居即事','王維','唐','唐诗','tang','','[]','寂寞掩柴扉，蒼茫對落暉。',48,'全唐诗/poet.tang.6000.json','["寂寞掩柴扉，蒼茫對落暉。", "鶴巢松樹遍，人訪蓽門稀。", "綠竹含新粉，紅蓮落故衣。", "渡頭煙火起，處處采菱歸。"]'),
('a5b1f5c9-1ba7-4533-b497-55b1d4af1bbb','終南山','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u7ec8\u5357\u5c71", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u4e94\u8a00\u5f8b\u8bd7", "\u9ad8\u4e2d\u53e4\u8bd7", "\u63cf\u5199\u5c71"]','太乙近天都，連山接海隅。',48,'全唐诗/poet.tang.6000.json','["太乙近天都，連山接海隅。", "白雲迴望合，青靄入看無。", "分野中峰變，陰晴衆壑殊。", "欲投人處宿，隔水問樵夫。"]'),
('2323f730-4046-4aad-a753-14425c7f0c3c','輞川閑居','王維','唐','唐诗','tang','','[]','一從歸白社，不復到青門。',48,'全唐诗/poet.tang.6000.json','["一從歸白社，不復到青門。", "時倚檐前樹，遠看原上村。", "青菰臨水拔，白鳥向山翻。", "寂寞於陵子，桔槔方灌園。"]'),
('90d959e3-5b1e-4ff5-b7a5-468290a2e7fc','春園即事','王維','唐','唐诗','tang','','["\u6625\u5929", "\u7530\u56ed", "\u5199\u666f"]','宿雨乘輕屐，春寒著弊袍。',48,'全唐诗/poet.tang.6000.json','["宿雨乘輕屐，春寒著弊袍。", "開畦分白水，間柳發紅桃。", "草際成棋局，林端舉桔槔。", "還持鹿皮几，日暮隱蓬蒿。"]'),
('cb402b16-d987-453e-9a95-4130ee43abab','淇上田園即事','王維','唐','唐诗','tang','','[]','屏居淇水上，東野曠無山。',48,'全唐诗/poet.tang.6000.json','["屏居淇水上，東野曠無山。", "日隱桑柘外，河明閭井間。", "牧童望村去，獵犬隨人還。", "靜者亦何事，荆扉乘晝關。"]'),
('d8c1b2ae-8f64-464a-bb2b-e8a675236f64','涼州郊外遊望','王維','唐','唐诗','tang','','[]','野老纔三戶，邊村少四鄰。',48,'全唐诗/poet.tang.6000.json','["野老纔三戶，邊村少四鄰。", "婆娑依里社，簫鼓賽田神。", "灑酒澆芻狗，焚香拜木人。", "女巫紛屢舞，羅襪自生塵。"]'),
('f66fc9fd-c77f-4c19-b4b5-33784cb612cb','觀獵','王維','唐','唐诗','tang','','["\u51ac\u5929", "\u72e9\u730e"]','風勁角弓鳴，將軍獵渭城。',48,'全唐诗/poet.tang.6000.json','["風勁角弓鳴，將軍獵渭城。", "草枯鷹眼疾，雪盡馬蹄輕。", "忽過新豐市，還歸細柳營。", "迴看射鵰處，千里暮雲平。"]'),
('b994d0ea-2762-4e26-88cd-b6c27cd7cef3','春日上方即事','王維','唐','唐诗','tang','','[]','好讀高僧傳，時看辟穀方。',48,'全唐诗/poet.tang.6000.json','["好讀高僧傳，時看辟穀方。", "鳩形將刻杖，龜殼用支牀。", "柳色春山暎，梨花夕鳥藏。", "北窗桃李下，閑坐但焚香。"]'),
('9080a103-2750-4b9b-a4fa-1167cd670a0c','漢江臨汎','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5c71\u6c34", "\u6292\u60c5", "\u4e94\u8a00\u5f8b\u8bd7"]','楚塞三湘接，荆門九派通。',48,'全唐诗/poet.tang.6000.json','["楚塞三湘接，荆門九派通。", "江流天地外，山色有無中。", "郡邑浮前浦，波瀾動遠空。", "襄陽好風日，留醉與山翁。"]'),
('ea78eb6a-3e1f-4193-9ec0-974c12a4491a','汎前陂','王維','唐','唐诗','tang','','[]','秋空自明迥，況復遠人間。',48,'全唐诗/poet.tang.6000.json','["秋空自明迥，況復遠人間。", "暢以沙際鶴，兼之雲外山。", "澄波澹將夕，清月皓方閑。", "此夜任孤櫂，夷猶殊未還。"]'),
('a7bedc82-2f58-414a-b3b3-c1576c1d4083','登河北城樓作','王維','唐','唐诗','tang','','[]','井邑傅巖上，客亭雲霧間。',48,'全唐诗/poet.tang.6000.json','["井邑傅巖上，客亭雲霧間。", "高城眺落日，極浦暎蒼山。", "岸火孤舟宿，漁家夕鳥還。", "寂寥天地暮，心與廣川閑。"]'),
('92c0add0-13ab-4368-921a-721e16eda7db','千塔主人','王維','唐','唐诗','tang','','[]','逆旅逢佳節，征帆未可前。',48,'全唐诗/poet.tang.6000.json','["逆旅逢佳節，征帆未可前。", "窗臨汴河水，門渡楚人船。", "雞犬散墟落，桑榆蔭遠田。", "所居人不見，枕席生雲煙。"]'),
('8ec59c80-46dc-4916-b069-a25ed8f144ec','使至塞上','王維','唐','唐诗','tang','','["\u6218\u58eb", "\u5199\u666f", "\u521d\u4e2d\u53e4\u8bd7", "\u8fb9\u585e", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5185)", "\u8d5e\u7f8e"]','單車欲問邊，屬國過居延。',48,'全唐诗/poet.tang.6000.json','["單車欲問邊，屬國過居延。", "征蓬出漢塞，歸雁入胡天。", "大漠孤煙直，長河落日圓。", "蕭關逢候吏，都護在燕然。"]'),
('8d9fabc0-2285-4a7d-84f0-c12f22b6d57b','使至塞上','王維','唐','唐诗','tang','','["\u6218\u58eb", "\u5199\u666f", "\u521d\u4e2d\u53e4\u8bd7", "\u8fb9\u585e", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5185)", "\u8d5e\u7f8e"]','銜命辭天闕，單車欲問邊。',48,'全唐诗/poet.tang.6000.json','["銜命辭天闕，單車欲問邊。", "征蓬出漢塞，歸雁入胡天。", "大漠孤煙直，長河落日圓。", "蕭關逢候吏，都護在燕然。"]'),
('fba8b6f6-0707-4e45-a7f1-d8667adf4083','晚春歸思','王維','唐','唐诗','tang','','[]','新妝可憐色，落日卷羅帷。',48,'全唐诗/poet.tang.6000.json','["新妝可憐色，落日卷羅帷。", "鑪氣清珍簟，牆陰上玉墀。", "春蟲飛網戶，暮雀隱花枝。", "向晚多愁思，閑窗桃李時。"]'),
('292c8f22-de30-4826-8ab0-29963317adbf','戲題示蕭氏甥','王維','唐','唐诗','tang','','[]','憐爾解臨池，渠爺未學詩。',48,'全唐诗/poet.tang.6000.json','["憐爾解臨池，渠爺未學詩。", "老夫何足似，弊宅倘因之。", "蘆筍穿荷葉，菱花罥雁兒。", "郗公不易勝，莫著外家欺。"]'),
('c2320ab0-98b1-405f-bf9b-8a3774e793fc','秋夜獨坐','王維','唐','唐诗','tang','','["\u79cb\u5929", "\u96e8\u591c", "\u611f\u6000"]','獨坐悲雙鬢，空堂欲二更。',48,'全唐诗/poet.tang.6000.json','["獨坐悲雙鬢，空堂欲二更。", "雨中山果落，燈下草蟲鳴。", "白髮終難變，黃金不可成。", "欲知除老病，唯有學無生。"]'),
('7852c87b-2870-4e6d-be75-94d4c658e07c','待儲光羲不至','王維','唐','唐诗','tang','','["\u53cb\u60c5"]','重門朝已啓，起坐聽車聲。',48,'全唐诗/poet.tang.6000.json','["重門朝已啓，起坐聽車聲。", "要欲聞清佩，方將出戶迎。", "晚鐘鳴上苑，疎雨過春城。", "了自不相顧，臨堂空復情。"]'),
('9c9edd1a-6db7-4657-a804-02e0c2c75daa','聽宮鶯','王維','唐','唐诗','tang','','[]','春樹遶宮牆，宮鶯囀曙光。',48,'全唐诗/poet.tang.6000.json','["春樹遶宮牆，宮鶯囀曙光。", "忽驚啼暫斷，移處弄還長。", "隱葉棲承露，攀花出未央。", "遊人未應返，爲此始思鄉。"]'),
('2e7c3681-1817-45f3-b25b-ad027640e921','雜詩','王維','唐','唐诗','tang','','[]','雙燕初命子，五桃新作花。',48,'全唐诗/poet.tang.6000.json','["雙燕初命子，五桃新作花。", "王昌是東舍，宋玉次西家。", "小小能織綺，時時出浣紗。", "親勞使君問，南陌駐香車。"]'),
('daa10a71-7423-4830-96cf-8db885e4bbe5','留別錢起','王維','唐','唐诗','tang','','[]','卑栖却得性，每與白雲歸。',48,'全唐诗/poet.tang.6000.json','["卑栖却得性，每與白雲歸。", "徇祿仍懷橘，看山免採薇。", "暮禽先去馬，新月待開扉。", "霄漢時回首，知音青瑣闈。"]'),
('f0327a66-a977-4c02-8f5d-df22f136603a','留別丘爲','王維','唐','唐诗','tang','','[]','歸鞍白雲外，繚繞出前山。',48,'全唐诗/poet.tang.6000.json','["歸鞍白雲外，繚繞出前山。", "今日又明日，自知心不閑。", "親勞簪組送，欲趂鶯花還。", "一步一迴首，遲遲向近關。"]'),
('9875d4ea-304f-4fef-9f68-41c4bbb89e0a','愚公谷三首 一','王維','唐','唐诗','tang','','[]','愚谷與誰去，唯將黎子同。',48,'全唐诗/poet.tang.6000.json','["愚谷與誰去，唯將黎子同。", "非須一處住，不那兩心空。", "寧問春將夏，誰論西復東。", "不知吾與子，若箇是愚公。"]'),
('8be21612-23b0-4edb-8675-6ff0a5cb0b24','愚公谷三首 二','王維','唐','唐诗','tang','','[]','吾家愚谷裏，此谷本來平。',48,'全唐诗/poet.tang.6000.json','["吾家愚谷裏，此谷本來平。", "雖則行無跡，還能響應聲。", "不隨雲色暗，只待日光明。", "緣底名愚谷，都由愚所成。"]'),
('99a434dd-4a05-45a7-88d9-cc3bb92c8025','愚公谷三首 三','王維','唐','唐诗','tang','','[]','借問愚公谷，與君聊一尋。',48,'全唐诗/poet.tang.6000.json','["借問愚公谷，與君聊一尋。", "不尋翻到谷，此谷不離心。", "行處曾無險，看時豈有深。", "寄言塵世客，何處欲歸臨。"]'),
('721f092d-4087-411c-a29e-3ee51bf59e7e','酬慕容十一','王維','唐','唐诗','tang','','[]','行行西陌返，駐幰問車公。',48,'全唐诗/poet.tang.6000.json','["行行西陌返，駐幰問車公。", "挾轂雙官騎，應門五尺僮。", "老年如塞北，強起離牆東。", "爲報壺丘子，來人道姓蒙。"]'),
('f7146947-bf34-4321-a154-e99b91de984c','過始皇墓','王維','唐','唐诗','tang','','[]','古墓成蒼嶺，幽宮象紫臺。',48,'全唐诗/poet.tang.6000.json','["古墓成蒼嶺，幽宮象紫臺。", "星辰七曜隔，河漢九泉開。", "有海人寧渡，無春雁不廻。", "更聞松韻切，疑是大夫哀。"]'),
('7e6ed758-443d-4266-a4f9-33a05d295be2','恭懿太子挽歌五首 一','王維','唐','唐诗','tang','','[]','何悟藏環早，纔知拜璧年。',48,'全唐诗/poet.tang.6000.json','["何悟藏環早，纔知拜璧年。", "翀天王子去，對日聖君憐。", "樹轉宮猶出，笳悲馬不前。", "雖蒙絕馳道，京兆別開阡。"]'),
('8a9ef331-f84a-491a-b61b-2f913365bbc2','恭懿太子挽歌五首 二','王維','唐','唐诗','tang','','[]','蘭殿新恩切，椒宮夕臨幽。',48,'全唐诗/poet.tang.6000.json','["蘭殿新恩切，椒宮夕臨幽。", "白雲隨鳳管，明月在龍樓。", "人向青山哭，天臨渭水愁。", "雞鳴常問膳，今恨玉京留。"]'),
('af6d46a3-23d7-4dcc-bc3f-a188098d5228','恭懿太子挽歌五首 三','王維','唐','唐诗','tang','','[]','騎吹凌霜發，旌旗夾路陳。',48,'全唐诗/poet.tang.6000.json','["騎吹凌霜發，旌旗夾路陳。", "凱容金節護，冊命玉符新。", "傅母悲香褓，君家擁畫輪。", "射熊今夢帝，秤象問何人。"]'),
('649732ca-310d-4000-b6ca-299fc070468e','恭懿太子挽歌五首 四','王維','唐','唐诗','tang','','[]','蒼舒留帝寵，子晉有仙才。',48,'全唐诗/poet.tang.6000.json','["蒼舒留帝寵，子晉有仙才。", "五歲過人智，三天使鶴催。", "心悲陽祿館，目斷望思臺。", "若道長安近，何爲更不來。"]'),
('ea79dfc0-f0e6-4323-9427-3d5569d006ab','恭懿太子挽歌五首 五','王維','唐','唐诗','tang','','[]','西望昆池闊，東瞻下杜平。',48,'全唐诗/poet.tang.6000.json','["西望昆池闊，東瞻下杜平。", "山朝豫章館，樹轉鳳凰城。", "五校連旗色，千門疊鼓聲。", "金環如有驗，還向畫堂生。"]'),
('74da7ff1-46dd-425a-b52d-9bff2a31332b','故太子太師徐公挽歌四首 一','王維','唐','唐诗','tang','','[]','功德冠羣英，彌綸有大名。',48,'全唐诗/poet.tang.6000.json','["功德冠羣英，彌綸有大名。", "軒皇用風后，傅說是星精。", "就第優遺老，來朝詔不名。", "留侯常辟穀，何苦不長生。"]'),
('ce798dc5-d0ff-458d-8d4b-6723ff5f497d','故太子太師徐公挽歌四首 二','王維','唐','唐诗','tang','','[]','謀猷爲相國，翊戴奉宸輿。',48,'全唐诗/poet.tang.6000.json','["謀猷爲相國，翊戴奉宸輿。", "劒履升前殿，貂蟬託後車。", "齊侯疏土宇，漢室賴圖書。", "僻處留田宅，仍纔十頃餘。"]'),
('4e1e5489-c5f8-4486-ab8e-f89fef41c9dc','故太子太師徐公挽歌四首 三','王維','唐','唐诗','tang','','[]','舊里趨庭日，新年置酒辰。',50,'全唐诗/poet.tang.6000.json','["舊里趨庭日，新年置酒辰。", "聞詩鸞渚客，獻賦鳳樓人。", "北首辭明主，東堂哭大臣。", "猶思御朱輅，不惜[汙]車茵。"]'),
('4dcba919-7a6d-4d13-b3a4-bf84d63d840a','故太子太師徐公挽歌四首 四','王維','唐','唐诗','tang','','[]','久踐中台座，終登上將壇。',48,'全唐诗/poet.tang.6000.json','["久踐中台座，終登上將壇。", "誰言斷車騎，空憶盛衣冠。", "風日咸陽慘，笳簫渭水寒。", "無人當便闕，應罷太師官。"]'),
('3cc058ac-75ae-429f-a5c4-9a2821158574','故西河郡杜太守挽歌三首 一','王維','唐','唐诗','tang','','[]','天上去西征，雲中護北平。',48,'全唐诗/poet.tang.6000.json','["天上去西征，雲中護北平。", "生擒白馬將，連破黑鵰城。", "忽見芻靈苦，徒聞竹使榮。", "空留左氏傳，誰繼卜商名。"]'),
('3688e0ff-705f-4319-b147-9a30bf7cd064','故西河郡杜太守挽歌三首 二','王維','唐','唐诗','tang','','[]','返葬金符守，同歸石窌妻。',48,'全唐诗/poet.tang.6000.json','["返葬金符守，同歸石窌妻。", "卷衣悲畫翟，持翣待鳴雞。", "容衞都人慘，山川駟馬嘶。", "猶聞隴上客，相對哭征西。"]'),
('34227689-02b7-4228-a8c3-6ab9598fd3e4','故西河郡杜太守挽歌三首 三','王維','唐','唐诗','tang','','[]','塗芻去國門，祕器出東園。',48,'全唐诗/poet.tang.6000.json','["塗芻去國門，祕器出東園。", "太守留金印，夫人罷錦軒。", "旌旗轉衰木，簫鼓上寒原。", "墳樹應西靡，長思魏闕恩。"]'),
('aff8ddda-07ac-45a4-8305-419bc0c6ec35','故南陽夫人樊氏挽歌','王維','唐','唐诗','tang','','[]','錦衣餘翟茀，繡轂罷魚軒。',48,'全唐诗/poet.tang.6000.json','["錦衣餘翟茀，繡轂罷魚軒。", "淑女詩長在，夫人法尚存。", "凝笳隨曉斾，行哭向秋原。", "歸去將何見，誰能返戟門。"]'),
('02875e90-84dc-47cf-81cd-edc3377d5a66','達奚侍郎夫人寇氏挽詞二首 一','王維','唐','唐诗','tang','','[]','束帶將朝日，鳴環映牖辰。',36,'全唐诗/poet.tang.6000.json','["束帶將朝日，鳴環映牖辰。", "能令諫明主，相勸識賢人。", "遺挂空留壁，廻文日覆塵。"]'),
('6ac17fcb-2c1d-4508-a632-89c7c8f54ada','達奚侍郎夫人寇氏挽詞二首 二','王維','唐','唐诗','tang','','[]','女史悲彤管，夫人罷錦軒。',48,'全唐诗/poet.tang.6000.json','["女史悲彤管，夫人罷錦軒。", "卜塋占二室，行哭度千門。", "秋日光能淡，寒川波自翻。", "一朝成萬古，松柏暗平原。"]'),
('153323dd-8a38-45a0-a2c8-f687152e5ed5','送孫秀才','王維','唐','唐诗','tang','','[]','帝城風日好，況復建平家。',48,'全唐诗/poet.tang.6000.json','["帝城風日好，況復建平家。", "玉枕雙文簟，金盤五色瓜。", "山中無魯酒，松下飯胡麻。", "莫厭田家苦，歸期遠復賒。"]'),
('1c48c29a-98fd-41d7-a8c4-758015a12af1','奉和聖製慶玄元皇帝玉像之作應制','王維','唐','唐诗','tang','','[]','明君夢帝先，寶命上齊天。',72,'全唐诗/poet.tang.6000.json','["明君夢帝先，寶命上齊天。", "秦后徒聞樂，周王恥卜年。", "玉京移大像，金籙會羣仙。", "承露調天供，臨空敞御筵。", "斗廻迎壽酒，山近起鑪煙。", "願奉無爲化，齋心學自然。"]'),
('13a6108b-14b9-4a92-9f12-5445f794814b','奉和聖製與太子諸王三月三日龍池春禊應制','王維','唐','唐诗','tang','','[]','故事修春禊，新宮展豫遊。',72,'全唐诗/poet.tang.6000.json','["故事修春禊，新宮展豫遊。", "明君移鳳輦，太子出龍樓。", "賦掩陳王作，桮如洛水流。", "金人來捧劒，畫鷁去回舟。", "苑樹浮宮闕，天池照冕旒。", "宸章在雲表，垂象滿皇州。"]'),
('619ac57c-25f0-4f6d-84f2-1319ecfabfaf','奉和聖製上巳於望春亭觀禊飲應制','王維','唐','唐诗','tang','','["\u9ec4\u5c71"]','長樂青門外，宜春小苑東。',72,'全唐诗/poet.tang.6000.json','["長樂青門外，宜春小苑東。", "樓開萬井上，輦過百花中。", "畫鷁移仙妓，金貂列上公。", "清歌邀落日，妙舞向春風。", "渭水明秦甸，黃山入漢宮。", "君王來祓禊，灞滻亦朝宗。"]'),
('5f58d6b2-6a7c-4563-869c-46713cd2d196','奉和聖製暮春送朝集使歸郡應制','王維','唐','唐诗','tang','','[]','萬國仰宗周，衣冠拜冕旒。',72,'全唐诗/poet.tang.6000.json','["萬國仰宗周，衣冠拜冕旒。", "玉乘迎大客，金節送諸侯。", "祖席傾三省，褰帷向九州。", "楊花飛上路，槐色蔭通溝。", "來預鈞天樂，歸分漢主憂。", "宸章類河漢，垂象滿中州。"]'),
('c8684b9f-6eb9-40db-9cbf-bd87fb3dee50','三月三日曲江侍宴應制','王維','唐','唐诗','tang','','[]','萬乘親齋祭，千官喜豫遊。',72,'全唐诗/poet.tang.6000.json','["萬乘親齋祭，千官喜豫遊。", "奉迎從上苑，祓禊向中流。", "草樹連容衞，山河對冕旒。", "畫旗搖浦漵，春服滿汀洲。", "仙籞龍媒下，神臯鳳蹕留。", "從今億萬歲，天寶紀春秋。"]'),
('a1001ba3-9f0f-405b-b837-ad0014601838','奉和聖製重陽節宰臣及羣官上壽應制','王維','唐','唐诗','tang','','[]','四海方無事，三秋大有年。',72,'全唐诗/poet.tang.6000.json','["四海方無事，三秋大有年。", "百生無此日，萬壽願齊天。", "芍藥和金鼎，茱萸插玳筵。", "玉堂開右个，天樂動宮懸。", "御柳疎秋景，城鴉拂曙煙。", "無窮菊花節，長奉柏梁篇。"]'),
('8930cd67-9812-429b-86c0-1278d91b2c08','三月三日勤政樓侍宴應制','王維','唐','唐诗','tang','','[]','綵仗連宵合，瓊樓拂曙通。',72,'全唐诗/poet.tang.6000.json','["綵仗連宵合，瓊樓拂曙通。", "年光三月裏，宮殿百花中。", "不數秦王日，誰將洛水同。", "酒筵嫌落絮，舞袖怯春風。", "天保無爲德，人歡不戰功。", "仍臨九衢宴，更達四門聰。"]'),
('a195930e-c593-46ba-83a3-695da669f5aa','奉和聖製十五夜然燈繼以酺宴應制','王維','唐','唐诗','tang','','[]','上路笙歌滿，春城漏刻長。',96,'全唐诗/poet.tang.6000.json','["上路笙歌滿，春城漏刻長。", "遊人多晝日，明月讓燈光。", "魚鑰通翔鳳，龍輿出建章。", "九衢陳廣樂，百福透名香。", "仙伎來金殿，都人遶玉堂。", "定應偷妙舞，從此學新妝。", "奉引迎三事，司儀列萬方。", "願將天地壽，同以獻君王。"]'),
('46088148-cd2f-42f5-aa17-1499e658a3ca','奉和聖製幸玉真公主山莊因題石壁十韻之作應制','王維','唐','唐诗','tang','','[]','碧落風煙外，瑤臺道路賒。',120,'全唐诗/poet.tang.6000.json','["碧落風煙外，瑤臺道路賒。", "如何連帝苑，別自有仙家。", "此地回鸞駕，緣谿轉翠華。", "洞中開日月，窗裏發雲霞。", "庭養沖天鶴，溪流上漢查。", "種田生白玉，泥竈化丹砂。", "谷靜泉逾響，山深日易斜。", "御羹和石髓，香飯進胡麻。", "大道今無外，長生詎有涯。", "還瞻九霄上，來往五雲車。"]'),
('27d4ad2d-99e7-47d0-bef4-6644d8e30f3e','春日直門下省早朝','王維','唐','唐诗','tang','','[]','騎省直明光，雞鳴謁建章。',72,'全唐诗/poet.tang.6000.json','["騎省直明光，雞鳴謁建章。", "遙聞侍中珮，闇識令君香。", "玉漏隨銅史，天書拜夕郎。", "旌旗暎閶闔，歌吹滿昭陽。", "官舍梅初紫，宮門柳欲黃。", "願將遲日意，同與聖恩長。"]'),
('ed02514c-ebc4-4324-97c6-c7381edf7271','和僕射晉公扈從溫湯','王維','唐','唐诗','tang','','[]','天子幸新豐，旌旗渭水東。',120,'全唐诗/poet.tang.6000.json','["天子幸新豐，旌旗渭水東。", "寒山天仗外，溫谷幔城中。", "奠玉羣仙座，焚香太乙宮。", "出遊逢牧馬，罷獵見非熊。", "上宰無爲化，明時太古同。", "靈芝三秀紫，陳粟萬箱紅。", "王禮奠儒教，天兵小戰功。", "謀猶歸哲匠，詞賦屬文宗。", "司諫方無闕，陳詩且未工。", "長吟吉甫頌，朝夕仰清風。"]'),
('ad472842-1792-451c-826d-311acb8d8b21','和宋中丞夏日遊福賢觀天長寺寺即陳左相宅所施之作','王維','唐','唐诗','tang','','[]','已相殷王國，空餘尚父谿。',72,'全唐诗/poet.tang.6000.json','["已相殷王國，空餘尚父谿。", "釣磯開月殿，築道出雲梯。", "積水浮香象，深山鳴白雞。", "虛空陳伎樂，衣服製虹霓。", "墨點三千界，丹飛六一泥。", "桃源勿遽返，再訪恐君迷。"]'),
('1ff40801-4e65-4862-9a7c-f0315445d357','和陳監四郎秋雨中思從弟據','王維','唐','唐诗','tang','','[]','嫋嫋秋風動，淒淒煙雨繁。',96,'全唐诗/poet.tang.6000.json','["嫋嫋秋風動，淒淒煙雨繁。", "聲連鳷鵲觀，色暗鳳凰原。", "細柳疎高閣，輕槐落洞門。", "九衢行欲斷，萬井寂無喧。", "忽有愁霖唱，更陳多露言。", "平原思令弟，康樂謝賢昆。", "逸興方三接，衰顏強七奔。", "相如今老病，歸守茂陵園。"]'),
('b55431ec-7de2-4f5a-86e1-79103eabe5bc','上張令公','王維','唐','唐诗','tang','','[]','珥筆趨丹陛，垂璫上玉除。',132,'全唐诗/poet.tang.6000.json','["珥筆趨丹陛，垂璫上玉除。", "步檐青瑣闥，方幰畫輪車。", "市閱千金字，朝聞五色書。", "致君光帝典，薦士滿公車。", "伏奏回金駕，橫經重石渠。", "從茲罷角觝，且復幸儲胥。", "天統知堯後，王章笑魯初。", "匈奴遙俯伏，漢相儼簪裾。", "賈生非不遇，汲黯自堪疎。", "學易思求我，言詩或起予。", "當從大夫後，何惜隸人餘。"]'),
('311e0be8-6a88-4869-a44a-25bce2030cbf','贈焦道士','王維','唐','唐诗','tang','','[]','海上遊三島，淮南預八公。',72,'全唐诗/poet.tang.6000.json','["海上遊三島，淮南預八公。", "坐知千里外，跳向一壺中。", "縮地朝珠闕，行天使玉童。", "飲人聊割酒，送客乍分風。", "天老能行氣，吾師不養空。", "謝君徒雀躍，無可問鴻濛。"]'),
('2348b914-3a21-4d5b-ac83-79d4da3071b1','贈東嶽焦鍊師','王維','唐','唐诗','tang','','["\u6cf0\u5c71"]','先生千歲餘，五嶽遍曾居。',108,'全唐诗/poet.tang.6000.json','["先生千歲餘，五嶽遍曾居。", "遙識齊侯鼎，新過王母廬。", "不能師孔墨，何事問長沮。", "玉管時來鳳，銅盤即釣魚。", "竦身空裏語，明目夜中書。", "自有還丹術，時論太素初。", "頻蒙露版詔，時降軟輪車。", "山靜泉逾響，松高枝轉疎。", "搘頤問樵客，世上復何如。"]'),
('f8854216-82aa-41a8-84ae-39b3ddd2d999','送祕書晁監還日本國','王維','唐','唐诗','tang','','["\u9001\u522b"]','積水不可極，安知滄海東。',72,'全唐诗/poet.tang.6000.json','["積水不可極，安知滄海東。", "九州何處遠，萬里若乘空。", "向國唯看日，歸帆但信風。", "鰲身暎天黑，魚眼射波紅。", "鄉樹扶桑外，主人孤島中。", "別離方異域，音信若爲通。"]'),
('d7f08677-8042-4aff-98dd-d5381a58163a','送禰郎中','王維','唐','唐诗','tang','','[]','東郊春草色，驅馬去悠悠。',72,'全唐诗/poet.tang.6000.json','["東郊春草色，驅馬去悠悠。", "況復鄉山外，猿啼湘水流。", "島夷傳露版，江館候鳴騶。", "卉服爲諸吏，珠官拜本州。", "孤鸎吟遠墅，野杏發山郵。", "早晚方歸奏，南中纔忌秋。"]'),
('a886fd41-799c-46e4-993f-205f9963d008','送李太守赴上洛','王維','唐','唐诗','tang','','[]','商山包楚鄧，積翠藹沈沈。',72,'全唐诗/poet.tang.6000.json','["商山包楚鄧，積翠藹沈沈。", "驛路飛泉灑，關門落照深。", "野花開古戍，行客響空林。", "板屋春多雨，山城晝欲陰。", "丹泉通虢略，白羽抵荆岑。", "若見西山爽，應知黃綺心。"]'),
('0b572a44-2a64-4b87-9961-edaf9fdc2f75','送熊九赴任安陽','王維','唐','唐诗','tang','','[]','魏國應劉後，寂寥文雅空。',60,'全唐诗/poet.tang.6000.json','["魏國應劉後，寂寥文雅空。", "漳河如舊日，之子繼清風。", "阡陌銅臺下，閭閻金虎中。", "送車盈灞上，輕騎出關東。", "相去千餘里，西園明月同。"]'),
('1c55121d-027e-4f20-a99d-fa2e7e7ef03c','山中示弟','王維','唐','唐诗','tang','','[]','山林吾喪我，冠帶爾成人。',60,'全唐诗/poet.tang.6000.json','["山林吾喪我，冠帶爾成人。", "莫學嵇康懶，且安原憲貧。", "山陰多北戶，泉水在東鄰。", "緣合妄相有，性空無所親。", "安知廣成子，不是老夫身。"]'),
('506d9295-9855-4fe2-9c8b-d459ccb95a63','青龍寺曇璧上人兄院集','王維','唐','唐诗','tang','','[]','高處敞招提，虛空詎有倪。',60,'全唐诗/poet.tang.6000.json','["高處敞招提，虛空詎有倪。", "坐看南陌騎，下聽秦城雞。", "眇眇孤煙起，芊芊遠樹齊。", "青山萬井外，落日五陵西。", "眼界今無染，心空安可迷。"]'),
('972307bb-ce93-4a37-aae3-f548363da1a8','濟州過趙叟家宴','王維','唐','唐诗','tang','','[]','雖與人境接，閉門成隱居。',72,'全唐诗/poet.tang.6000.json','["雖與人境接，閉門成隱居。", "道言莊叟事，儒行魯人餘。", "深巷斜暉靜，閑門高柳疎。", "荷鋤修藥圃，散帙曝農書。", "上客搖芳翰，中廚饋野蔬。", "夫君第高飲，景晏出林閭。"]'),
('20fd7a4d-5374-4023-a410-b4bac9aec316','春過賀遂員外藥園','王維','唐','唐诗','tang','','[]','前年槿籬故，新作藥欄成。',72,'全唐诗/poet.tang.6000.json','["前年槿籬故，新作藥欄成。", "香草爲君子，名花是長卿。", "水穿盤石透，藤繫古松生。", "畫畏開廚走，來蒙到屣迎。", "蔗漿菰米飯，蒟醬露葵羹。", "頗識灌園意，於陵不自輕。"]'),
('5f315492-8086-4bbd-9249-8bc4c7bc06bf','過盧四員外宅看飯僧共題七韻','王維','唐','唐诗','tang','','[]','三賢異七賢，青眼慕青蓮。',84,'全唐诗/poet.tang.6000.json','["三賢異七賢，青眼慕青蓮。", "乞飯從香積，裁衣學水田。", "上人飛錫杖，檀越施金錢。", "趺作檐前日，焚香竹下煙。", "寒空法雲地，秋色淨居天。", "身逐因緣法，心過次第禪。", "不須愁日暮，自有一燈然。"]'),
('fc0d15fb-1479-47a0-a82e-9ca99e5f26de','河南嚴尹弟見宿弊廬訪別人賦十韻','王維','唐','唐诗','tang','','[]','上客能論道，吾生學養蒙。',120,'全唐诗/poet.tang.6000.json','["上客能論道，吾生學養蒙。", "貧交世情外，才子古人中。", "冠上方簪豸，車邊已畫熊。", "拂衣迎五馬，垂手憑雙童。", "花醥和松屑，茶香透竹叢。", "薄霜澄夜月，殘雪帶春風。", "古壁蒼苔黑，寒山遠燒紅。", "眼看東候別，心事北川同。", "爲學輕先輩，何能訪老翁。", "欲知今日後，不樂爲車公。"]'),
('c710c26f-cd79-4723-be6f-29aa96aa5359','投道一師蘭若宿','王維','唐','唐诗','tang','','[]','一公棲太白，高頂出風煙。',96,'全唐诗/poet.tang.6000.json','["一公棲太白，高頂出風煙。", "梵流諸壑遍，花雨一峰偏。", "跡爲無心隱，名因立教傳。", "鳥來還語法，客去更安禪。", "晝涉松路盡，暮投蘭若邊。", "洞房隱深竹，清夜聞遙泉。", "向是雲霞裏，今成枕席前。", "豈唯暫留宿，服事將窮年。"]'),
('4bf5acf2-6ad4-478d-a43a-1f8ef0bf7753','遊感化寺','王維','唐','唐诗','tang','','[]','翡翠香煙合，琉璃寶地平。',120,'全唐诗/poet.tang.6000.json','["翡翠香煙合，琉璃寶地平。", "龍宮連棟宇，虎穴傍檐楹。", "谷靜唯松響，山深無鳥聲。", "瓊峰當戶拆，金澗透林明。", "郢路雲端逈，秦川雨外晴。", "鴈王銜果獻，鹿女踏花行。", "抖擻辭貧里，歸依宿化城。", "繞籬生野蕨，空館發山櫻。", "香飯青菰米，嘉蔬綠笋莖。", "誓陪清梵末，端坐學無生。"]'),
('d39f419a-021e-401f-b79d-d6964815d6bc','遊悟真寺','王維','唐','唐诗','tang','','[]','聞道黃金地，仍開白玉田。',144,'全唐诗/poet.tang.6000.json','["聞道黃金地，仍開白玉田。", "擲山移巨石，呪嶺出飛泉。", "猛虎同三逕，愁猿學四禪。", "買香然綠桂，乞火踏紅蓮。", "草色搖霞上，松聲汎月邊。", "山河窮百二，世界接三千。", "梵宇聊憑視，王城遂渺然。", "灞陵纔出樹，渭水欲連天。", "遠縣分諸郭，孤村起白煙。", "望雲思聖主，披霧隱羣賢。", "薄宦慚尸素，終身擬尚玄。", "誰知草菴客，曾和柏梁篇。"]'),
('2982d4a8-9d3b-40e3-bfac-8958d2f3b70e','與蘇盧二員外期遊方丈寺而蘇不至因有是作','王維','唐','唐诗','tang','','[]','共仰頭陀行，能忘世諦情。',72,'全唐诗/poet.tang.6000.json','["共仰頭陀行，能忘世諦情。", "回看雙鳳闕，相去一牛鳴。", "法向空林說，心隨寶地平。", "手巾花氎淨，香帔稻畦成。", "聞道邀同舍，相期宿化城。", "安知不來往，翻得似無生。"]'),
('1811e946-63d4-4ddd-b580-2c972beeb82e','曉行巴峽','王維','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u5199\u666f"]','際曉投巴峽，餘春憶帝京。',72,'全唐诗/poet.tang.6000.json','["際曉投巴峽，餘春憶帝京。", "晴江一女浣，朝日衆雞鳴。", "水國舟中市，山橋樹杪行。", "登高萬井出，眺迥二流明。", "人作殊方語，鸎爲故國聲。", "賴多山水趣，稍解別離情。"]'),
('6f2659f3-d735-4ddd-8f72-d30137a55255','清如玉壺冰','王維','唐','唐诗','tang','','[]','玉壺何用好，偏許素冰居。',72,'全唐诗/poet.tang.6000.json','["玉壺何用好，偏許素冰居。", "未共銷丹日，還同照綺疏。", "抱明中不隱，含淨外疑虛。", "氣似庭霜積，光言砌月餘。", "曉凌飛鵲鏡，宵暎聚螢書。", "若向夫君比，清心尚不如。"]'),
('0a27e70d-a681-4031-8b7e-5f411f00fb49','賦得秋日懸清光','王維','唐','唐诗','tang','','["\u4e50\u89c2", "\u79cb\u5929", "\u5199\u666f", "\u79ef\u6781"]','寥廓涼天靜，晶明白日秋。',72,'全唐诗/poet.tang.6000.json','["寥廓涼天靜，晶明白日秋。", "圓光含萬象，碎影入閑流。", "迥與青冥合，遙同江甸浮。", "晝陰殊衆木，斜影下危樓。", "宋玉登高怨，張衡望遠愁。", "餘輝如可託，雲路豈悠悠。"]'),
('b73fdaf7-eb78-46bc-88b0-f85faad3aed4','東谿玩月','王維','唐','唐诗','tang','','[]','月從斷山口，遙吐柴門端。',72,'全唐诗/poet.tang.6000.json','["月從斷山口，遙吐柴門端。", "萬木分空霽，流陰中夜攢。", "光連虛象白，氣與風露寒。", "谷靜秋泉響，巖深青靄殘。", "清燈入幽夢，破影抱空巒。", "恍惚琴窗裏，松谿曉思難。"]'),
('69e71ade-05dd-4118-a040-bfe449a37260','田家','王維','唐','唐诗','tang','','[]','舊穀行將盡，良苗未可希。',84,'全唐诗/poet.tang.6000.json','["舊穀行將盡，良苗未可希。", "老年方愛粥，卒歲且無衣。", "雀乳青苔井，雞鳴白板扉。", "柴車駕羸牸，草屩牧豪狶。", "夕雨紅榴拆，新秋綠芋肥。", "餉田桑下憩，旁舍草中歸。", "住處名愚谷，何煩問是非。"]'),
('626ba0c1-f8e9-47fb-94db-b97264d014d9','沈十四拾遺新竹生讀經處同諸公之作','王維','唐','唐诗','tang','','[]','閑居日清靜，修竹自檀欒。',60,'全唐诗/poet.tang.6000.json','["閑居日清靜，修竹自檀欒。", "嫩節留餘籜，新叢出舊闌。", "細枝風響亂，疎影月光寒。", "樂府裁龍笛，漁家伐釣竿。", "何如道門裏，青翠拂仙壇。"]'),
('04e3592c-e41d-4555-ba96-221070a2c5ae','雜詩','王維','唐','唐诗','tang','','[]','朝因折楊柳，相見洛陽隅。',60,'全唐诗/poet.tang.6000.json','["朝因折楊柳，相見洛陽隅。", "楚國無如妾，秦家自有夫。", "對人傳玉腕，暎燭解羅襦。", "人見東方騎，皆言夫壻殊。", "持謝金吾子，煩君提玉壺。"]'),
('4be7de82-296f-46c1-a7a5-313953bd12a0','哭褚司馬','王維','唐','唐诗','tang','','[]','妄識皆心累，浮生定死媒。',72,'全唐诗/poet.tang.6000.json','["妄識皆心累，浮生定死媒。", "誰言老龍吉，未免伯牛災。", "故有求仙藥，仍餘遯俗杯。", "山川秋樹苦，窗戶夜泉哀。", "尚憶青騾去，寧知白馬來。", "漢臣修史記，莫蔽褚生才。"]'),
('223cc8ea-0fe5-4699-be56-196276a6f493','過沈居士山居哭之','王維','唐','唐诗','tang','','[]','楊朱來此哭，桑扈返於真。',96,'全唐诗/poet.tang.6000.json','["楊朱來此哭，桑扈返於真。", "獨自成千古，依然舊四鄰。", "閑簷喧鳥鵲，故榻滿埃塵。", "曙月孤鶯囀，空山五柳春。", "野花愁對客，泉水咽迎人。", "善卷明時隱，黔婁在日貧。", "逝川嗟爾命，丘井歎吾身。", "前後徒言隔，相悲詎幾晨。"]'),
('40c43c40-99b9-49b1-849b-556135031e1b','哭祖六自虛','王維','唐','唐诗','tang','','[]','否極嘗聞泰，嗟君獨不然。',288,'全唐诗/poet.tang.6000.json','["否極嘗聞泰，嗟君獨不然。", "憫凶纔稚齒，羸疾主中年。", "餘力文章秀，生知禮樂全。", "翰留天帳覽，詞入帝宮傳。", "國訝終軍少，人知賈誼賢。", "公卿盡虛左，朋識共推先。", "不恨依窮轍，終期濟巨川。", "才雄望羔雁，壽促背貂蟬。", "福善聞前錄，殲良昧上玄。", "何辜鎩鸞翮，底事碎龍泉。", "鵩起長沙賦，麟終曲阜編。", "域中君道廣，海內我情偏。", "乍失疑猶見，沈思悟絕緣。", "生前不忍別，死後向誰宣。", "爲此情難盡，彌令憶更纏。", "本家清渭曲，歸葬舊塋邊。", "永去長安道，徒聞京兆阡。", "旌車出郊甸，鄉國隱雲天。", "定作無期別，寧同舊日旋。", "候門家屬苦，行路國人憐。", "送客哀難進，征途泥復前。", "贈言爲挽曲，奠席是離筵。", "念昔同攜手，風期不暫捐。", "南山俱隱逸，東洛類神仙。"]'),
('ce71032a-c075-492c-9554-51eb080348a5','奉和聖製從蓬萊向興慶閣道中留春雨中春望之作應制','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9ec4\u5c71", "\u5e94\u5236", "\u4e03\u8a00\u5f8b\u8bd7"]','渭水自縈秦塞曲，黃山舊遶漢宮斜。',64,'全唐诗/poet.tang.6000.json','["渭水自縈秦塞曲，黃山舊遶漢宮斜。", "鑾輿迥出千門柳，閣道廻看上苑花。", "雲裏帝城雙鳳闕，雨中春樹萬人家。", "爲乘陽氣行時令，不是宸遊玩物華。"]'),
('3019a6aa-b32d-4a57-bd78-90c0dbe35453','大同殿柱產玉芝龍池上有慶雲神光照殿百官共覩聖恩便賜宴樂敢書即事','王維','唐','唐诗','tang','','[]','欲笑周文歌宴鎬，遙輕漢武樂橫汾。',64,'全唐诗/poet.tang.6000.json','["欲笑周文歌宴鎬，遙輕漢武樂橫汾。", "豈知玉殿生三秀，詎有銅池出五雲。", "陌上堯樽傾北斗，樓前舜樂動南薰。", "共歡天意同人意，萬歲千秋奉聖君。"]'),
('a69d95f9-9598-4ebe-9532-84b3c5c8cd82','敕賜百官櫻桃','王維','唐','唐诗','tang','','[]','芙蓉闕下會千官，紫禁朱櫻出上[蘭]。',66,'全唐诗/poet.tang.6000.json','["芙蓉闕下會千官，紫禁朱櫻出上[蘭]。", "纔是寢園春薦後，非關御苑鳥銜殘。", "歸鞍競帶青絲籠，中使頻傾赤玉盤。", "飽食不須愁內熱，大官還有蔗漿寒。"]'),
('40dd7d52-88ca-4f10-b5b4-b8f98e9a668c','敕借岐王九成宮避暑應教','王維','唐','唐诗','tang','','["\u5c71\u6c34", "\u7530\u56ed"]','帝子遠辭丹鳳闕，天書遙借翠微宮。',64,'全唐诗/poet.tang.6000.json','["帝子遠辭丹鳳闕，天書遙借翠微宮。", "隔窗雲霧生衣上，卷幔山泉入鏡中。", "林下水聲喧語笑，巖間樹色隱房櫳。", "仙家未必能勝此，何事吹笙向碧空。"]'),
('a364504e-3cfc-44c6-9203-173856452cdd','和賈舍人早朝大明宮之作','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bab\u5ef7", "\u4e03\u8a00\u5f8b\u8bd7", "\u65e9\u671d"]','絳幘雞人送曉籌，尚衣方進翠雲裘。',64,'全唐诗/poet.tang.6000.json','["絳幘雞人送曉籌，尚衣方進翠雲裘。", "九天閶闔開宮殿，萬國衣冠拜冕旒。", "日色纔臨仙掌動，香煙欲傍衮龍浮。", "朝罷須裁五色詔，佩聲歸向鳳池頭。"]'),
('837dbd82-f524-41e5-9f9f-38838ac3f41c','和太常韋主簿五郎溫湯寓目之作','王維','唐','唐诗','tang','','[]','漢主離宮接露臺，秦川一半夕陽開。',64,'全唐诗/poet.tang.6000.json','["漢主離宮接露臺，秦川一半夕陽開。", "青山盡是朱旗繞，碧澗翻從玉殿來。", "新豐樹裏行人度，小苑城邊獵騎廻。", "聞道甘泉能獻賦，懸知獨有子雲才。"]'),
('80a1044e-e0f3-4e29-8c12-b5fe7eb35336','苑舍人能書梵字兼達梵音皆曲盡其妙戲爲之贈','王維','唐','唐诗','tang','','[]','名儒待詔滿公車，才子爲郎典石渠。',64,'全唐诗/poet.tang.6000.json','["名儒待詔滿公車，才子爲郎典石渠。", "蓮花法藏心懸悟，貝葉經文手自書。", "楚詞共許勝楊馬，梵字何人辨魯魚。", "故舊相望在三事，願君莫厭承明廬。"]'),
('5f677b56-89a4-404a-88e2-017e78a1cd5b','重酬苑郎中','王維','唐','唐诗','tang','','[]','何幸含香奉至尊，多慙未報主人恩。',64,'全唐诗/poet.tang.6000.json','["何幸含香奉至尊，多慙未報主人恩。", "草木盡能酬雨露，榮枯安敢問乾坤。", "仙郎有意憐同舍，丞相無私斷埽門。", "揚子解嘲徒自遣，馮唐已老復何論。"]'),
('7950a49f-f51d-4926-9d1e-e5f76b153829','酬郭給事','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u916c\u548c", "\u4e03\u8a00\u5f8b\u8bd7"]','洞門高閣靄餘輝，桃李陰陰柳絮飛。',64,'全唐诗/poet.tang.6000.json','["洞門高閣靄餘輝，桃李陰陰柳絮飛。", "禁裏疎鐘官舍晚，省中啼鳥吏人稀。", "晨搖玉佩趨金殿，夕奉天書拜瑣闈。", "強欲從君無那老，將因臥病解朝衣。"]'),
('a7d807c5-435d-492a-8a17-d77b596f6d12','出塞','王維','唐','唐诗','tang','','["\u8fb9\u585e"]','居延城外獵天驕，白草連山野火燒。',64,'全唐诗/poet.tang.6000.json','["居延城外獵天驕，白草連山野火燒。", "暮雲空磧時驅馬，秋日平原好射鵰。", "護羗校尉朝乘障，破虜將軍夜渡遼。", "玉靶角弓珠勒馬，漢家將賜霍嫖姚。"]'),
('81ae102d-4177-47e4-a93b-f500ba8ad175','既蒙宥罪旋復拜官伏感聖恩竊書鄙意兼奉簡新除使君等諸公','王維','唐','唐诗','tang','','[]','忽蒙漢詔還冠冕，始覺殷王解網羅。',64,'全唐诗/poet.tang.6000.json','["忽蒙漢詔還冠冕，始覺殷王解網羅。", "日比皇明猶自暗，天齊聖壽未云多。", "花迎喜氣皆知笑，鳥識歡心亦解歌。", "聞道百城新佩印，還來雙闕共鳴珂。"]'),
('b23eb216-8b5b-45d2-8c15-0c9dcb4fdd3b','送方尊師歸嵩山','王維','唐','唐诗','tang','','[]','仙官欲往九龍潭，旄節朱幡倚石龕。',64,'全唐诗/poet.tang.6000.json','["仙官欲往九龍潭，旄節朱幡倚石龕。", "山壓天中半天上，洞穿江底出江南。", "瀑布杉松常帶雨，夕陽蒼翠忽成嵐。", "借問迎來雙白鶴，已曾衡嶽送蘇耽。"]'),
('1ce3dd53-b772-4e88-8cd8-080329565416','送楊少府貶郴州','王維','唐','唐诗','tang','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','明到衡山與洞庭，若爲秋月聽猿聲。',64,'全唐诗/poet.tang.6000.json','["明到衡山與洞庭，若爲秋月聽猿聲。", "愁看北渚三湘遠，惡說南風五兩輕。", "青草瘴時過夏口，白頭浪裏出湓城。", "長沙不久留才子，賈誼何須弔屈平。"]'),
('b299afc7-1bde-46c6-9be3-7ffb8c4243e4','過乘如禪師蕭居士嵩丘蘭若','王維','唐','唐诗','tang','','[]','無着天親弟與兄，嵩丘蘭若一峰晴。',64,'全唐诗/poet.tang.6000.json','["無着天親弟與兄，嵩丘蘭若一峰晴。", "食隨鳴磬巢烏下，行踏空林落葉聲。", "迸水定侵香案濕，雨花應共石牀平。", "深洞長松何所有，儼然天竺古先生。"]'),
('80ff4aed-e8e4-459c-963f-659895422def','春日與裴迪過新昌里訪呂逸人不遇','王維','唐','唐诗','tang','','[]','桃源一向絕風塵，柳市南頭訪隱淪。',64,'全唐诗/poet.tang.6000.json','["桃源一向絕風塵，柳市南頭訪隱淪。", "到門不敢題凡鳥，看竹何須問主人。", "城上青山如屋裏，東家流水入西鄰。", "閉戶著書多歲月，種松皆老作龍鱗。"]'),
('0e7afbc5-fa58-41f9-8af4-1b2db6dc3c03','酌酒與裴迪','王維','唐','唐诗','tang','','[]','酌酒與君君自寬，人情翻覆似波瀾。',64,'全唐诗/poet.tang.6000.json','["酌酒與君君自寬，人情翻覆似波瀾。", "白首相知猶按劒，朱門先達笑彈冠。", "草色全經細雨濕，花枝欲動春風寒。", "世事浮雲何足問，不如高臥且加餐。"]'),
('7f6c7690-adb5-4337-bb03-0b60d508e375','輞川別業','王維','唐','唐诗','tang','','["\u5f52\u9690", "\u7530\u56ed"]','不到東山向一年，歸來纔及種春田。',64,'全唐诗/poet.tang.6000.json','["不到東山向一年，歸來纔及種春田。", "雨中草色綠堪染，水上桃花紅欲然。", "優婁比丘經論學，傴僂丈人鄉里賢。", "披衣倒屣且相見，相歡語笑衡門前。"]'),
('10b89f48-445d-4a21-a475-5d978eac5f0b','早秋山中作','王維','唐','唐诗','tang','','["\u79cb\u5929", "\u5199\u666f", "\u95f2\u9002", "\u9690\u5c45"]','無才不敢累明時，思向東谿守故籬。',64,'全唐诗/poet.tang.6000.json','["無才不敢累明時，思向東谿守故籬。", "豈厭尚平婚嫁早，却嫌陶令去官遲。", "草間蛩響臨秋急，山裏蟬聲薄暮悲。", "寂寞柴門人不到，空林獨與白雲期。"]'),
('0949fe2a-aadf-4cd4-b1c3-25fcdaecdb96','積雨輞川莊作','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u7530\u56ed"]','積雨空林煙火遲，蒸藜炊黍餉東菑。',64,'全唐诗/poet.tang.6000.json','["積雨空林煙火遲，蒸藜炊黍餉東菑。", "漠漠水田飛白鷺，陰陰夏木囀黃鸝。", "山中習靜觀朝槿，松下清齋折露葵。", "野老與人爭席罷，海鷗何事更相疑。"]'),
('a1cce991-036e-4212-8ce3-79e2ec09437e','聽百舌鳥','王維','唐','唐诗','tang','','[]','上蘭門外草萋萋，未央宮中花裏栖。',64,'全唐诗/poet.tang.6000.json','["上蘭門外草萋萋，未央宮中花裏栖。", "亦有相隨過御苑，不知若箇向金堤。", "入春解作千般語，拂曙能先百鳥啼。", "萬戶千門應覺曉，建章何必聽鳴雞。"]'),
('4aae89a6-18e5-453d-bfb4-2f3807bdd87c','息夫人','王維','唐','唐诗','tang','','[]','莫以今時寵，難忘舊日恩。',24,'全唐诗/poet.tang.6000.json','["莫以今時寵，難忘舊日恩。", "看花滿眼淚，不共楚王言。"]'),
('9357d459-7d1c-4eed-9fd0-d4b0ce6a2c2a','班婕妤三首 一','王維','唐','唐诗','tang','','[]','玉窗螢影度，金殿人聲絕。',24,'全唐诗/poet.tang.6000.json','["玉窗螢影度，金殿人聲絕。", "秋夜守羅帷，孤燈耿不滅。"]'),
('6f892ec1-3ab6-4630-b5c8-d2bc623f66ea','班婕妤三首 二','王維','唐','唐诗','tang','','[]','宮殿生秋草，君王恩幸疎。',24,'全唐诗/poet.tang.6000.json','["宮殿生秋草，君王恩幸疎。", "那堪聞鳳吹，門外度金輿。"]'),
('2be95663-2cf4-495f-a000-32b4746cd296','班婕妤三首 三','王維','唐','唐诗','tang','','[]','怪來妝閣閉，朝下不相迎。',24,'全唐诗/poet.tang.6000.json','["怪來妝閣閉，朝下不相迎。", "總向春園裏，花間笑語聲。"]'),
('0e955cd6-1201-4583-b05b-629688085383','輞川集 孟城坳','王維','唐','唐诗','tang','','[]','新家孟城口，古木餘衰柳。',24,'全唐诗/poet.tang.6000.json','["新家孟城口，古木餘衰柳。", "來者復爲誰，空悲昔人有。"]'),
('d1114b54-1f47-470d-a9e4-c9c24101d9c2','輞川集 華子岡','王維','唐','唐诗','tang','','[]','飛鳥去不窮，連山復秋色。',24,'全唐诗/poet.tang.6000.json','["飛鳥去不窮，連山復秋色。", "上下華子岡，惆悵情何極。"]'),
('f9b25804-87bf-449c-9a95-ed86e9133ff2','輞川集 文杏館','王維','唐','唐诗','tang','','[]','文杏裁爲梁，香茅結爲宇。',24,'全唐诗/poet.tang.6000.json','["文杏裁爲梁，香茅結爲宇。", "不知棟裏雲，去作人間雨。"]'),
('dff71696-64af-48ec-a90b-273a762752d3','輞川集 斤竹嶺','王維','唐','唐诗','tang','','[]','檀欒暎空曲，青翠漾漣漪。',24,'全唐诗/poet.tang.6000.json','["檀欒暎空曲，青翠漾漣漪。", "暗入商山路，樵人不可知。"]'),
('2e8999a9-9df8-4483-ab1e-0231c3e46320','輞川集 鹿柴','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u5c71", "\u63cf\u5199\u5c71", "\u5199\u5c71", "\u4e94\u8a00\u7edd\u53e5"]','空山不見人，但聞人語響。',24,'全唐诗/poet.tang.6000.json','["空山不見人，但聞人語響。", "返景入深林，復照青苔上。"]'),
('4721c4de-6b7f-4300-86c3-1c28027d0158','輞川集 木蘭柴','王維','唐','唐诗','tang','','[]','秋山斂餘照，飛鳥逐前侶。',24,'全唐诗/poet.tang.6000.json','["秋山斂餘照，飛鳥逐前侶。", "彩翠時分明，夕嵐無處所。"]'),
('59d59574-aae3-463e-83d5-877fee9781be','輞川集 茱萸沜','王維','唐','唐诗','tang','','[]','結實紅且綠，復如花更開。',24,'全唐诗/poet.tang.6000.json','["結實紅且綠，復如花更開。", "山中儻留客，置此芙蓉杯。"]'),
('1cb863ff-de22-479b-94ca-6072ed5ed64d','輞川集 宮槐陌','王維','唐','唐诗','tang','','[]','仄逕蔭宮槐，幽陰多綠苔。',24,'全唐诗/poet.tang.6000.json','["仄逕蔭宮槐，幽陰多綠苔。", "應門但迎埽，畏有山僧來。"]'),
('3c1a9546-02b6-4d89-9159-636dc5991f03','輞川集 臨湖亭','王維','唐','唐诗','tang','','["\u5bb4\u996e", "\u6292\u60c5", "\u5199\u666f"]','輕舸迎上客，悠悠湖上來。',24,'全唐诗/poet.tang.6000.json','["輕舸迎上客，悠悠湖上來。", "當軒對尊酒，四面芙蓉開。"]'),
('ff97c1dc-6555-4269-8cbe-a33ccc29c62b','輞川集 南垞','王維','唐','唐诗','tang','','[]','輕舟南垞去，北垞淼難即。',24,'全唐诗/poet.tang.6000.json','["輕舟南垞去，北垞淼難即。", "隔浦望人家，遙遙不相識。"]'),
('9f4f99a7-0759-42a8-89fb-cb80d33e5f8a','輞川集 欹湖','王維','唐','唐诗','tang','','[]','吹簫凌極浦，日暮送夫君。',24,'全唐诗/poet.tang.6000.json','["吹簫凌極浦，日暮送夫君。", "湖上一回首，青山卷白雲。"]'),
