('68da728b-4d10-4809-a687-5518098a1e0f','少年行四首 三','王維','唐','唐诗','tang','','[]','一身能擘兩雕弧，虜騎千重只似無。',32,'全唐诗/poet.tang.6000.json','["一身能擘兩雕弧，虜騎千重只似無。", "偏坐金鞍調白羽，紛紛射殺五單于。"]'),
('197fcb93-3d7f-4cf9-b6c4-410b48e7de14','少年行四首 四','王維','唐','唐诗','tang','','[]','漢家君臣歡宴終，高議雲臺論戰功。',32,'全唐诗/poet.tang.6000.json','["漢家君臣歡宴終，高議雲臺論戰功。", "天子臨軒賜侯印，將軍佩出明光宮。"]'),
('ed9dd23b-f793-4f7e-bfd8-6ec3ed562883','贈裴旻將軍','王維','唐','唐诗','tang','','[]','腰間寶劒七星文，臂上琱弓百戰勳。',32,'全唐诗/poet.tang.6000.json','["腰間寶劒七星文，臂上琱弓百戰勳。", "見說雲中擒黠虜，始知天上有將軍。"]'),
('6bbd1c2c-8c43-4ffb-b7b3-506d74266cee','九月九日憶山東兄弟','王維','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u601d\u4e61", "\u4e09\u5e74\u7ea7\u4e0a\u518c", "\u91cd\u9633\u8282", "\u5c0f\u5b66\u53e4\u8bd7"]','獨在異鄉爲異客，每逢佳節倍思親。',32,'全唐诗/poet.tang.6000.json','["獨在異鄉爲異客，每逢佳節倍思親。", "遙知兄弟登高處，遍插茱萸少一人。"]'),
('5ec02070-40de-468f-b0bc-398952a3f5e5','送王尊師歸蜀中拜埽','王維','唐','唐诗','tang','','[]','大羅天上神仙客，濯錦江頭花柳春。',32,'全唐诗/poet.tang.6000.json','["大羅天上神仙客，濯錦江頭花柳春。", "不爲碧雞稱使者，唯令白鶴報鄉人。"]'),
('1575c835-1241-4d7b-99dc-6d700549ac65','渭城曲','王維','唐','唐诗','tang','','["\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5916)", "\u53cb\u60c5", "\u5c0f\u5b66\u53e4\u8bd7", "\u9001\u522b", "\u521d\u4e2d\u53e4\u8bd7", "\u4e50\u5e9c"]','渭城朝雨浥輕塵，客舍青青楊柳春。',32,'全唐诗/poet.tang.6000.json','["渭城朝雨浥輕塵，客舍青青楊柳春。", "勸君更盡一杯酒，西出陽關無故人。"]'),
('5f24766a-64cd-46cb-b588-23cb7ed7cd45','齊州送祖二','王維','唐','唐诗','tang','','[]','送君南浦淚如絲，君向東州使我悲。',32,'全唐诗/poet.tang.6000.json','["送君南浦淚如絲，君向東州使我悲。", "爲報故人顦顇盡，如今不似洛陽時。"]'),
('f22070fb-28bc-405a-ba8b-ca5f053796de','送韋評事','王維','唐','唐诗','tang','','["\u60b2\u58ee", "\u5199\u666f", "\u8fb9\u585e"]','欲逐將軍取右賢，沙場走馬向居延。',32,'全唐诗/poet.tang.6000.json','["欲逐將軍取右賢，沙場走馬向居延。", "遙知漢使蕭關外，愁見孤城落日邊。"]'),
('846980bc-1386-4423-9de6-b96299dff005','靈雲池送從弟','王維','唐','唐诗','tang','','[]','金杯緩酌清歌轉，畫舸輕移豔舞回。',32,'全唐诗/poet.tang.6000.json','["金杯緩酌清歌轉，畫舸輕移豔舞回。", "自歎鶺鴒臨水別，不同鴻鴈向池來。"]'),
('231ffdfc-9391-4da4-94e8-e7e9da35925d','送沈子歸江東','王維','唐','唐诗','tang','','["\u601d\u5ff5", "\u9001\u522b", "\u5373\u666f", "\u5bd3\u60c5"]','楊柳渡頭行客稀，罟師盪槳向臨圻。',32,'全唐诗/poet.tang.6000.json','["楊柳渡頭行客稀，罟師盪槳向臨圻。", "唯有相思似春色，江南江北送君歸。"]'),
('cb9611dd-54cd-4786-a742-7f1e83590d47','與盧員外象過崔處士興宗林亭','王維','唐','唐诗','tang','','[]','綠樹重陰蓋四鄰，青苔日厚自無塵。',32,'全唐诗/poet.tang.6000.json','["綠樹重陰蓋四鄰，青苔日厚自無塵。", "科頭箕踞長松下，白眼看他世上人。"]'),
('018f0c47-778c-4bed-b6b3-e177cfc24a4d','寒食汜上作','王維','唐','唐诗','tang','','[]','廣武城邊逢暮春，汶陽歸客淚沾巾。',32,'全唐诗/poet.tang.6000.json','["廣武城邊逢暮春，汶陽歸客淚沾巾。", "落花寂寂啼山鳥，楊柳青青渡水人。"]'),
('c7916293-1cd3-430c-abd7-1cda964d805d','戲題輞川別業','王維','唐','唐诗','tang','','[]','柳條拂地不須折，松樹披雲從更長。',32,'全唐诗/poet.tang.6000.json','["柳條拂地不須折，松樹披雲從更長。", "藤花欲暗藏猱子，柏葉初齊養麝香。"]'),
('3d367cb6-b80e-4650-94d2-c269f0c1c0c5','戲題盤石','王維','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f"]','可憐盤石臨泉水，復有垂楊拂酒杯。',32,'全唐诗/poet.tang.6000.json','["可憐盤石臨泉水，復有垂楊拂酒杯。", "若道春風不解意，何因吹送落花來。"]'),
('07ddc694-2365-4fa8-88ff-51f98c21eb8a','寄河上段十六','王維','唐','唐诗','tang','','[]','與君相見即相親，聞道君家在孟津。',32,'全唐诗/poet.tang.6000.json','["與君相見即相親，聞道君家在孟津。", "爲見行舟試借問，客中時有洛陽人。"]'),
('8d6a0fe6-6ba6-46e7-b9ec-a946e34f4451','菩提寺禁裴迪來相看說逆賊等凝碧池上作音樂供奉人等舉聲便一時淚下私成口號誦示裴迪','王維','唐','唐诗','tang','','[]','萬戶傷心生野煙，百僚何日更朝天。',32,'全唐诗/poet.tang.6000.json','["萬戶傷心生野煙，百僚何日更朝天。", "秋槐葉落空宮裏，凝碧池頭奏管弦。"]'),
('f213838d-b51a-46aa-bbac-938e97a130ca','涼州賽神','王維','唐','唐诗','tang','','[]','涼州城外少行人，百尺峰頭望虜塵。',32,'全唐诗/poet.tang.6000.json','["涼州城外少行人，百尺峰頭望虜塵。", "健兒擊鼓吹羌笛，共賽城東越騎神。"]'),
('0ad30318-2c99-4071-9cca-554ec9b3b714','劇嘲史寰','王維','唐','唐诗','tang','','[]','清風細雨濕梅花，驟馬先過碧玉家。',32,'全唐诗/poet.tang.6000.json','["清風細雨濕梅花，驟馬先過碧玉家。", "正值楚王宮裏至，門前初下七香車。"]'),
('d87b6c44-9bb7-476f-84a5-8b61f9b6a897','歎白髪','王維','唐','唐诗','tang','','[]','宿昔朱顏成暮齒，須臾白髮變垂髫。',32,'全唐诗/poet.tang.6000.json','["宿昔朱顏成暮齒，須臾白髮變垂髫。", "一生幾許傷心事，不向空門何處銷。"]'),
('9467ebe1-1199-4266-8bab-19a36e802528','伊州歌','王維','唐','唐诗','tang','','["\u601d\u5ff5", "\u5973\u5b50"]','清風明月苦相思，蕩子從戎十載餘。',32,'全唐诗/poet.tang.6000.json','["清風明月苦相思，蕩子從戎十載餘。", "征人去日慇懃囑，歸鴈來時數附書。"]'),
('c19bb4cf-209a-41e1-976e-12ebd5cf80c9','送殷四葬','王維','唐','唐诗','tang','','[]','送君返葬石樓山，松栢蒼蒼賓馭還。',32,'全唐诗/poet.tang.6000.json','["送君返葬石樓山，松栢蒼蒼賓馭還。", "埋骨白雲長已矣，空餘流水向人間。"]'),
('b127c5e6-e6b6-4add-8498-ea680b6777c9','疑夢','王維','唐','唐诗','tang','','[]','莫驚寵辱空憂喜，莫計恩讐浪苦辛。',32,'全唐诗/poet.tang.6000.json','["莫驚寵辱空憂喜，莫計恩讐浪苦辛。", "黃帝孔丘何處問？安知不是夢中身。"]'),
('769d0ad2-d240-43b1-a515-1a26982fcb1e','句','王維','唐','唐诗','tang','','[]','人家在仙掌，雲氣欲生衣。',12,'全唐诗/poet.tang.6000.json','["人家在仙掌，雲氣欲生衣。"]'),
('6eb8ccd6-e133-49ef-b72d-b6cab287a82c','古離別','王縉','唐','唐诗','tang','','[]','下階欲離別，相對映蘭叢。',48,'全唐诗/poet.tang.6000.json','["下階欲離別，相對映蘭叢。", "含辭未及吐，淚落蘭叢中。", "高堂靜秋日，羅衣飄暮風。", "誰能待明月，迴首見牀空。"]'),
('0981a458-9ce7-48cf-a772-7bfcf02dac07','青雀歌','王縉','唐','唐诗','tang','','[]','林間青雀兒，來往翩翩繞一枝。',30,'全唐诗/poet.tang.6000.json','["林間青雀兒，來往翩翩繞一枝。", "莫言不解銜環報，但聞君恩今若爲。"]'),
('8e1a16be-f7f7-4427-906a-f50539d1d660','同王昌齡裴迪游青龍寺曇壁上人兄院集和兄維','王縉','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','林中空寂舍，階下終南山。',60,'全唐诗/poet.tang.6000.json','["林中空寂舍，階下終南山。", "高臥一牀上，迴看六合間。", "浮雲幾處滅，飛鳥何時還？", "問義天人接，無心世界閑。", "誰知大隱者，兄弟自追攀。"]'),
('d7c1ef67-0a2d-4e29-9f2b-eb708b1d0e3c','別輞川別業','王縉','唐','唐诗','tang','','[]','山月曉仍在，林風涼不絕。',24,'全唐诗/poet.tang.6000.json','["山月曉仍在，林風涼不絕。", "殷勤如有情，惆悵令人別。"]'),
('ce266c4c-8ea4-4881-8e99-b47e875f57fb','與盧員外象過崔處士興宗林亭','王縉','唐','唐诗','tang','','[]','身名不問十年餘，老大誰能更讀書。',32,'全唐诗/poet.tang.6000.json','["身名不問十年餘，老大誰能更讀書。", "林中獨酌鄰家酒，門外時聞長者車。"]'),
('3ed9907e-4a5b-47d6-871a-e44d3a12e110','九日作','王縉','唐','唐诗','tang','','[]','莫將邊地比京都，八月嚴霜草已枯。',32,'全唐诗/poet.tang.6000.json','["莫將邊地比京都，八月嚴霜草已枯。", "今日登高樽酒裏，不知能有菊花無。"]'),
('d9653d68-6f76-49ee-886d-79be414e16aa','送孫秀才','王縉','唐','唐诗','tang','','[]','帝城風日好，況復建平家。',48,'全唐诗/poet.tang.6000.json','["帝城風日好，況復建平家。", "玉枕雙紋簟，金盤五色瓜。", "山中無魯酒，松下飯胡麻。", "莫厭田家苦，歸期遠復賒。"]'),
('dfc624c2-9767-465d-a4f8-0ebdf0a5d84e','游悟真寺','王縉','唐','唐诗','tang','','[]','聞道黃金地，仍開白玉田。',144,'全唐诗/poet.tang.6000.json','["聞道黃金地，仍開白玉田。", "擲山移巨石，呪嶺出飛泉。", "猛虎同三徑，愁猨學四禪。", "買香然綠桂，乞火蹈紅蓮。", "草色搖霞上，松聲泛月邊。", "山河窮百二，世界接三千。", "梵宇聊憑視，王城遂渺然。", "灞陵纔出樹，渭水欲連天。", "遠縣分朱郭，孤村起白煙。", "望雲思聖主，披霧憶羣賢。", "薄宦慚尸素，終身擬尚玄。", "誰知草菴客，曾和柏梁篇。"]'),
('4b90d9ee-d6fb-4542-b97a-4103f36cf0dc','青龍寺曇壁上人院集','裴迪','唐','唐诗','tang','','[]','靈境信爲絕，法堂出塵氛。',60,'全唐诗/poet.tang.6000.json','["靈境信爲絕，法堂出塵氛。", "自然成高致，向下看浮雲。", "迤邐峯岫列，參差閭井分。", "林端遠堞見，風末疎鐘聞。", "吾師久禪寂，在世超人羣。"]'),
('ade16151-3b5d-4df6-9651-ccea2ded6697','青雀歌','裴迪','唐','唐诗','tang','','[]','動息自適性，不曾妄與燕雀羣。',30,'全唐诗/poet.tang.6000.json','["動息自適性，不曾妄與燕雀羣。", "幸忝鵷鸞早相識，何時提攜致青雲。"]'),
('67603c99-bce1-498b-8942-e6c9414fbfff','游感化寺曇興上人山院','裴迪','唐','唐诗','tang','','[]','不遠灞陵邊，安居向十年。',48,'全唐诗/poet.tang.6000.json','["不遠灞陵邊，安居向十年。", "入門穿竹徑，留客聽山泉。", "鳥囀深林裏，心閑落照前。", "浮名竟何益，從此願棲禪。"]'),
('a4119211-2b4f-4c92-ad5b-c66316617f7d','夏日過青龍寺謁操禪師','裴迪','唐','唐诗','tang','','[]','安禪一室內，左右竹亭幽。',48,'全唐诗/poet.tang.6000.json','["安禪一室內，左右竹亭幽。", "有法知不染，無言誰敢酬。", "鳥飛爭向夕，蟬噪已先秋。", "煩暑自茲適，清涼何所求。"]'),
('fce06ca0-8b8f-4ce9-b83b-425e062ecbce','春日與王右丞過新昌里訪呂逸人不遇','裴迪','唐','唐诗','tang','','[]','恨不逢君出荷簑，青松白屋更無他。',64,'全唐诗/poet.tang.6000.json','["恨不逢君出荷簑，青松白屋更無他。", "陶令五男曾不有，蔣生三徑枉相過。", "芙蓉曲沼春流滿，薜荔成帷晚靄多。", "聞說桃源好迷客，不如高臥眄庭柯。"]'),
('b34a9b93-5468-4d42-8ba3-31d96800e35f','輞川集二十首 孟城坳','裴迪','唐','唐诗','tang','','[]','結廬古城下，時登古城上。',24,'全唐诗/poet.tang.6000.json','["結廬古城下，時登古城上。", "古城非疇昔，今人自來往。"]'),
('83826cc8-6c57-4077-99a5-229fbf535242','輞川集二十首 華子岡','裴迪','唐','唐诗','tang','','[]','落日松風起，還家草露晞。',24,'全唐诗/poet.tang.6000.json','["落日松風起，還家草露晞。", "雲光侵履跡，山翠拂人衣。"]'),
('7793742e-91e5-4b24-8c53-5acb9abf40c3','輞川集二十首 文杏館','裴迪','唐','唐诗','tang','','[]','迢迢文杏館，躋攀日已屢。',24,'全唐诗/poet.tang.6000.json','["迢迢文杏館，躋攀日已屢。", "南嶺與北湖，前看復迴顧。"]'),
('c8a8c0bc-de30-42bf-855c-580ead6cb836','輞川集二十首 斤竹嶺','裴迪','唐','唐诗','tang','','[]','明流紆且直，綠篠密復深。',24,'全唐诗/poet.tang.6000.json','["明流紆且直，綠篠密復深。", "一徑通山路，行歌望舊岑。"]'),
('c8fd9bf2-7c9b-4e6e-8d7b-efc201215317','輞川集二十首 鹿柴','裴迪','唐','唐诗','tang','','[]','日夕見寒山，便爲獨往客。',24,'全唐诗/poet.tang.6000.json','["日夕見寒山，便爲獨往客。", "不知深林事，但有麏麚跡。"]'),
('1094b0eb-6b7d-44a6-9163-4d0c20a2735a','輞川集二十首 木蘭柴','裴迪','唐','唐诗','tang','','[]','蒼蒼落日時，鳥聲亂谿水。',24,'全唐诗/poet.tang.6000.json','["蒼蒼落日時，鳥聲亂谿水。", "緣谿路轉深，幽興何時已。"]'),
('4a4900ec-5231-484d-937a-1beca1a5dfa9','輞川集二十首 茱萸沜','裴迪','唐','唐诗','tang','','[]','飄香亂椒桂，布葉間檀欒。',24,'全唐诗/poet.tang.6000.json','["飄香亂椒桂，布葉間檀欒。", "雲日雖迴照，森沈猶自寒。"]'),
('f9b59f8b-649e-4454-a94a-75bc4d135c11','輞川集二十首 宮槐陌','裴迪','唐','唐诗','tang','','[]','門前宮槐陌，是向欹湖道。',24,'全唐诗/poet.tang.6000.json','["門前宮槐陌，是向欹湖道。", "秋來山雨多，落葉無人掃。"]'),
('59b3c1c3-f8ab-40a7-a063-026cfc36ed1b','輞川集二十首 臨湖亭','裴迪','唐','唐诗','tang','','[]','當軒彌滉漾，孤月正裴回。',24,'全唐诗/poet.tang.6000.json','["當軒彌滉漾，孤月正裴回。", "谷口猨聲發，風傳入戶來。"]'),
('efcb469c-0c7a-4ba9-9d04-cdbbddf7dcce','輞川集二十首 南垞','裴迪','唐','唐诗','tang','','[]','孤舟信一泊，南垞湖水岸。',24,'全唐诗/poet.tang.6000.json','["孤舟信一泊，南垞湖水岸。", "落日下崦嵫，清波殊淼漫。"]'),
('de2f613f-be2f-4a1d-96fd-f65d062ad782','輞川集二十首 欹湖','裴迪','唐','唐诗','tang','','[]','空闊湖水廣，青熒天色同。',24,'全唐诗/poet.tang.6000.json','["空闊湖水廣，青熒天色同。", "艤舟一長嘯，四面來清風。"]'),
('90de5ee8-abdd-480a-98bd-0e1605fa462c','輞川集二十首 柳浪','裴迪','唐','唐诗','tang','','[]','映池同一色，逐吹散如絲。',24,'全唐诗/poet.tang.6000.json','["映池同一色，逐吹散如絲。", "結陰既得地，何謝陶家時。"]'),
('a5860521-866e-4429-b55b-0b5ec10e4ceb','輞川集二十首 欒家瀨','裴迪','唐','唐诗','tang','','[]','瀨聲喧極浦，沿涉向南津。',24,'全唐诗/poet.tang.6000.json','["瀨聲喧極浦，沿涉向南津。", "汎汎鷗鳧渡，時時欲近人。"]'),
('323950c1-288d-4ace-a2a5-a9e5cb106a23','輞川集二十首 金屑泉','裴迪','唐','唐诗','tang','','[]','縈渟澹不流，金碧如可拾。',24,'全唐诗/poet.tang.6000.json','["縈渟澹不流，金碧如可拾。", "迎晨含素華，獨往事朝汲。"]'),
('6ab0ff23-712e-4e47-9125-189ecc4a97b6','輞川集二十首 白石灘','裴迪','唐','唐诗','tang','','[]','跂石復臨水，弄波情未極。',24,'全唐诗/poet.tang.6000.json','["跂石復臨水，弄波情未極。", "日下川上寒，浮雲澹無色。"]'),
('50dfe307-13f1-4119-9c17-c250160ce72c','輞川集二十首 北垞','裴迪','唐','唐诗','tang','','[]','南山北垞下，結宇臨欹湖。',24,'全唐诗/poet.tang.6000.json','["南山北垞下，結宇臨欹湖。", "每欲采樵去，扁舟出菰蒲。"]'),
('c9c85878-f0a0-4883-8b30-193c1023ca56','輞川集二十首 竹里館','裴迪','唐','唐诗','tang','','[]','來過竹里館，日與道相親。',24,'全唐诗/poet.tang.6000.json','["來過竹里館，日與道相親。", "出入唯山鳥，幽深無世人。"]'),
('a6ddecc2-6f13-492c-bf3c-84f31d6ca5ad','輞川集二十首 辛夷塢','裴迪','唐','唐诗','tang','','[]','綠堤春草合，王孫自留玩/。',25,'全唐诗/poet.tang.6000.json','["綠堤春草合，王孫自留玩/。", "況有辛夷花，色與芙蓉亂。"]'),
('c5897a87-badf-4b3f-9ae3-e78e8b372711','輞川集二十首 漆園','裴迪','唐','唐诗','tang','','[]','好閑早成性，果此諧宿諾。',24,'全唐诗/poet.tang.6000.json','["好閑早成性，果此諧宿諾。", "今日漆園游，還同莊叟樂。"]'),
('b2ea3aae-b19b-45fc-aa75-3b2d82dea855','輞川集二十首 椒園','裴迪','唐','唐诗','tang','','[]','丹刺罥人衣，芳香留過客。',24,'全唐诗/poet.tang.6000.json','["丹刺罥人衣，芳香留過客。", "幸堪調鼎用，願君垂采摘。"]'),
('235f7fe7-c38e-4ae3-a6b1-61dc243d70e9','輞口遇雨憶終南山因獻王維','裴迪','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','積雨晦空曲，平沙滅浮彩。',24,'全唐诗/poet.tang.6000.json','["積雨晦空曲，平沙滅浮彩。", "輞水去悠悠，南山復何在。"]'),
('80fe70cd-6e63-48eb-9c1e-ab26330d45d9','崔九欲往南山馬上口號與別','裴迪','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u79bb\u522b", "\u4e94\u8a00\u7edd\u53e5", "\u89c4\u529d"]','歸山深淺去，須盡丘壑美。',24,'全唐诗/poet.tang.6000.json','["歸山深淺去，須盡丘壑美。", "莫學武陵人，暫游桃源裏。"]'),
('d167e7a6-27cd-4e62-896c-4f370d0f1ac0','與盧員外象過崔處士興宗林亭','裴迪','唐','唐诗','tang','','[]','喬柯門裏自成陰，散髪窗中曾不簪。',32,'全唐诗/poet.tang.6000.json','["喬柯門裏自成陰，散髪窗中曾不簪。", "逍遙且喜從吾事，榮寵從來非我心。"]'),
('2800ce85-c57a-44f4-97a2-7556f4ef6599','西塔寺陸羽茶泉','裴迪','唐','唐诗','tang','','[]','竟陵西塔寺，蹤跡尚空虛。',48,'全唐诗/poet.tang.6000.json','["竟陵西塔寺，蹤跡尚空虛。", "不獨支公住，曾經陸羽居。", "草堂荒產蛤，茶井冷生魚。", "一汲清泠水，高風味有餘。"]'),
('4341fe0b-1ecc-42bd-9ba1-1f8e5747487a','同王右丞送瑗公南歸','崔興宗','唐','唐诗','tang','','[]','行苦神亦秀，泠然谿上松。',48,'全唐诗/poet.tang.6000.json','["行苦神亦秀，泠然谿上松。", "銅瓶與竹杖，來自祝融峯。", "常願入靈嶽，藏經訪遺蹤。", "南歸見長老，且爲說心胸。"]'),
('aea66f01-b52d-4465-a4fc-957be819260f','青雀歌','崔興宗','唐','唐诗','tang','','[]','青扈繞青林，翩翾陋體一微禽。',30,'全唐诗/poet.tang.6000.json','["青扈繞青林，翩翾陋體一微禽。", "不應常在藩籬下，他日凌雲誰見心。"]'),
('eccc5785-e6b3-4163-97cd-220197deb69f','和王維敕賜百官櫻桃','崔興宗','唐','唐诗','tang','','[]','未央朝謁正逶迤，天上櫻桃錫此時。',64,'全唐诗/poet.tang.6000.json','["未央朝謁正逶迤，天上櫻桃錫此時。", "朱實初傳九華殿，繁花舊雜萬年枝。", "未勝晏子江南橘，莫比潘家大谷梨。", "聞道令人好顏色，神農本草自應知。"]'),
('2da5559c-7539-479d-b13b-6d75c85666e7','留別王維','崔興宗','唐','唐诗','tang','','[]','駐馬欲分襟，清寒御溝上。',24,'全唐诗/poet.tang.6000.json','["駐馬欲分襟，清寒御溝上。", "前山景氣佳，獨往還惆悵。"]'),
('e28c6884-bd9c-454d-afe6-8a25ade368c1','酬王維盧象見過林亭','崔興宗','唐','唐诗','tang','','[]','窮巷空林常閉關，悠然獨臥對前山。',32,'全唐诗/poet.tang.6000.json','["窮巷空林常閉關，悠然獨臥對前山。", "今朝忽枉嵇生駕，倒屣開門遙解顏。"]'),
('b267adc5-95ed-480d-aa91-4fbbcd274037','送大理正攝御史判涼州別駕','苑咸','唐','唐诗','tang','','[]','天子念西疆，咨君去不遑。',48,'全唐诗/poet.tang.6000.json','["天子念西疆，咨君去不遑。", "垂銀棘庭印，持斧柏臺綱。", "雪下天山白，泉枯塞草黃。", "佇聞河隴外，還繼海沂康。"]'),
('39657608-2f0c-4348-b4bb-f2fd51107487','酬王維','苑咸','唐','唐诗','tang','','[]','蓮花梵字本從天，華省仙郎早悟禪。',64,'全唐诗/poet.tang.6000.json','["蓮花梵字本從天，華省仙郎早悟禪。", "三點成伊猶有想，一觀如幻自忘筌。", "爲文已變當時體，入用還推間氣賢。", "應同羅漢無名欲，故作馮唐老歲年。"]'),
('10a0aedc-4b39-494b-a36c-28c6df28a668','尋西山隱者不遇','丘爲','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u53cb\u60c5"]','絕頂一茅茨，直[上]三十里。',98,'全唐诗/poet.tang.6000.json','["絕頂一茅茨，直[上]三十里。", "扣關無僮僕，窺室唯案几。", "若非巾柴車，應是釣秋水。", "差池不相見，黽勉空仰止。", "草色新雨中，松聲晚牕裏。", "及茲契幽絕，自足蕩心耳。", "雖無賓主意，頗得清淨理。", "興盡方下山，何必待之子。"]'),
('9aeb5732-c7ee-479b-9d29-0db95e051ddd','題農父廬舍','丘爲','唐','唐诗','tang','','["\u6625\u5929", "\u751f\u6d3b", "\u519c\u6c11"]','東風何時至，已綠湖上山。',48,'全唐诗/poet.tang.6000.json','["東風何時至，已綠湖上山。", "湖上春已早，田家日不閑。", "溝塍流水處，耒耜平蕪間。", "薄暮飯牛罷，歸來還閉關。"]'),
('eb438c61-efde-4ba3-80ea-a90d58368f72','泛若耶谿','丘爲','唐','唐诗','tang','','[]','結廬若耶裏，左右若耶水。',96,'全唐诗/poet.tang.6000.json','["結廬若耶裏，左右若耶水。", "無日不釣魚，有時向城市。", "溪中水流急，渡口水流寬。", "每得樵風便，往來殊不難。", "一川草長綠，四時那得辨。", "短褐衣妻兒，餘糧及雞犬。", "日暮鳥雀稀，稚子呼牛歸。", "住處無鄰里，柴門獨掩扉。"]'),
('6e77adaa-1c48-4a70-9214-b4be3c39ce41','湖中寄王侍御','丘爲','唐','唐诗','tang','','[]','日日湖水上，好登湖上樓。',120,'全唐诗/poet.tang.6000.json','["日日湖水上，好登湖上樓。", "終年不向郭，過午始梳頭。", "嘗自愛桮酒，得無相獻酬。", "小僮能膾鯉，少妾事蓮舟。", "每有南浦信，仍期後月遊。", "方春轉搖蕩，孤興時淹留。", "驄馬真傲吏，翛然無所求。", "晨趨玉階下，心許滄江流。", "少別如昨日，何言經數秋。", "應知方外事，獨往非悠悠。"]'),
('bcbfee0c-818c-4c2d-9f42-5473a2d25457','登潤州城','丘爲','唐','唐诗','tang','','[]','天末江城晚，登臨客望迷。',48,'全唐诗/poet.tang.6000.json','["天末江城晚，登臨客望迷。", "春潮平島嶼，殘雨隔虹蜺。", "鳥與孤帆遠，煙和獨樹低。", "鄉山何處是？目斷廣陵西。"]'),
('8d4ccd4d-33e5-467a-9590-053ae27a1289','尋廬山崔徵君','丘爲','唐','唐诗','tang','','["\u5e90\u5c71"]','日高雞犬靜，門掩向寒塘。',48,'全唐诗/poet.tang.6000.json','["日高雞犬靜，門掩向寒塘。", "夜竹深茅宇，秋亭冷石牀。", "住山年已遠，服藥壽偏長。", "虛棄浮生者，相逢益自傷。"]'),
('1876768c-2bb3-4589-a6e4-ade42d5d28ce','留別王維','丘爲','唐','唐诗','tang','','[]','歸鞍白雲外，繚繞出前山。',48,'全唐诗/poet.tang.6000.json','["歸鞍白雲外，繚繞出前山。", "今日又明日，自知心不閑。", "親勞簪組送，欲趂鶯花還。", "一步一回首，遲遲向近關。"]'),
('cc73e0d8-14e1-4dcb-9c58-b41c46396b59','竹下殘雪','丘爲','唐','唐诗','tang','','[]','一點消未盡，孤月在竹陰。',48,'全唐诗/poet.tang.6000.json','["一點消未盡，孤月在竹陰。", "晴光夜轉瑩，寒氣曉仍深。", "還對讀書牖，且關乘興心。", "已能依此地，終不傍瑤琴。"]'),
('1391ad55-9a12-4b97-aad5-9cce3b49c785','送閻校書之越','丘爲','唐','唐诗','tang','','[]','南入剡中路，草雲應轉微。',60,'全唐诗/poet.tang.6000.json','["南入剡中路，草雲應轉微。", "湖邊好花照，山口細泉飛。", "此地饒古跡，世人多忘歸。", "經年松雪在，永日世情稀。", "芸閣應相望，芳時不可違。"]'),
('eb0a4da3-927c-4575-8591-438f17253756','省試夏日可畏','丘爲','唐','唐诗','tang','','[]','赫赫溫風扇，炎炎夏日徂。',72,'全唐诗/poet.tang.6000.json','["赫赫溫風扇，炎炎夏日徂。", "火威馳迥野，畏景爍遙途。", "勢矯翔陽翰，功分造化爐。", "禁城千品燭，黃道一輪孤。", "落照頻空簟，餘暉卷夕梧。", "如何倦遊子，中路獨踟躕。"]'),
('6bb164b4-b9d3-4d23-b54b-e71e3535ddc7','左掖梨花','丘爲','唐','唐诗','tang','','["\u7231\u56fd", "\u541b\u4e3b", "\u68a8\u82b1"]','冷豔全欺雪，餘香乍入衣。',24,'全唐诗/poet.tang.6000.json','["冷豔全欺雪，餘香乍入衣。", "春風且莫定，吹向玉階飛。"]'),
('288561f3-ad9b-4a2d-a311-8db418792aae','渡漢江','丘爲','唐','唐诗','tang','','[]','漾舟漢江上，挂席候風生。',72,'全唐诗/poet.tang.6000.json','["漾舟漢江上，挂席候風生。", "臨汎何容與，愛此江水清。", "蘆洲隱遙嶂，露日隱孤城。", "自顧疎野性，難忘鷗鳥情。", "聊復與時顧，暫欲解塵纓。", "跋涉非吾願，虛懷浩已盈。"]'),
('fff7158d-1a9d-4eb0-9851-66a5098ef74b','冬至下寄舍弟時應赴入京','丘爲','唐','唐诗','tang','','[]','去去知未遠，依依甚初別。',102,'全唐诗/poet.tang.6000.json','["去去知未遠，依依甚初別。", "他鄉至下心，昨夜堦前雪。", "終日讀書仍少孤，家貧兄弟未當途。", "適遠纔過宿舂料，相隨惟一平頭奴。", "男兒出門事四海，立身世業文章在。", "莫漫憶柴扉，駟馬高車朝紫微。", "江南驛使不曾斷，迎前爲爾非春衣。"]'),
('269ffb18-fb0e-4dfc-88d8-afbf8456335c','送晁補闕歸日本國','趙驊','唐','唐诗','tang','','[]','西掖承休澣，東隅返故林。',48,'全唐诗/poet.tang.6000.json','["西掖承休澣，東隅返故林。", "來稱郯子學，歸是越人吟。", "馬上秋郊遠，舟中曙海陰。", "知君懷魏闕，萬里獨搖心。"]'),
('fa7fda27-632a-4003-a2ca-8ae208ebe088','古遊俠呈軍中諸將','崔顥','唐','唐诗','tang','','["\u5199\u4eba", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','少年負膽氣，好勇復知機。',96,'全唐诗/poet.tang.6000.json','["少年負膽氣，好勇復知機。", "仗劍出門去，孤城逢合圍。", "殺人遼水上，走馬漁陽歸。", "錯落金鎖甲，蒙茸貂鼠衣。", "還家行且獵，弓矢速如飛。", "地迥鷹犬疾，草深狐兔肥。", "腰間帶兩綬，轉盼生光輝。", "顧謂今日戰，何如隨建威。"]'),
('caf365b6-0a8a-4942-855a-604245683caa','贈輕車','崔顥','唐','唐诗','tang','','[]','悠悠遠行歸，經春涉長道。',72,'全唐诗/poet.tang.6000.json','["悠悠遠行歸，經春涉長道。", "幽冀桑始青，洛陽蠶欲老。", "憶昨戎馬地，別時心草草。", "烽火從北來，邊城閉常早。", "平生少相遇，未得展懷抱。", "今日杯酒間，見君交情好。"]'),
('b4f8fa89-5d72-40d7-94a7-d437e0a5169f','贈王威古','崔顥','唐','唐诗','tang','','[]','三十羽林將，出身常事邊。',108,'全唐诗/poet.tang.6000.json','["三十羽林將，出身常事邊。", "春風吹淺草，獵騎何翩翩。", "插羽兩相顧，鳴弓新上弦。", "射麋入深谷，飲馬投荒泉。", "馬上共傾酒，野中聊割鮮。", "相看未及飲，雜虜寇幽燕。", "烽火去不息，胡塵高際天。", "長驅救東北，戰解城亦全。", "報國行赴難，古來皆共然。"]'),
('4abcebca-f810-4eeb-bf45-d5727af37353','贈懷一上人','崔顥','唐','唐诗','tang','','[]','法師東南秀，世實豪家子。',288,'全唐诗/poet.tang.6000.json','["法師東南秀，世實豪家子。", "削髮十二年，誦經峨眉裏。", "自此照羣蒙，卓然爲道雄。", "觀生盡入妄，悟有皆成空。", "淨體無衆染，苦心歸妙宗。", "一朝敕書至，召入承明宮。", "說法金殿裏，焚香清禁中。", "傳燈遍都邑，杖錫遊王公。", "天子揖妙道，羣僚趨下風。", "我法本無著，時來出林壑。", "因心得化城，隨病皆與藥。", "上啓黃屋心，下除蒼生縛。", "一從入君門，說法無朝昏。", "帝作轉輪王，師爲持戒尊。", "軒風灑甘露，佛雨生慈根。", "但有滅度理，而生開濟恩。", "復聞江海曲，好殺成風俗。", "帝曰我上人，爲除羶腥欲。", "是日發西秦，東南至蘄春。", "風將衡桂接，地與吳楚鄰。", "舊少清信士，實多漁獵人。", "一聞吾師至，捨網江湖濱。", "作禮懺前惡，潔誠期後因。", "因成日既久，事濟身不守。"]'),
('2912b483-5f2b-43a7-babf-98a67cac7662','遊天竺寺','崔顥','唐','唐诗','tang','','[]','晨登天竺山，山殿朝陽曉。',108,'全唐诗/poet.tang.6000.json','["晨登天竺山，山殿朝陽曉。", "厓泉爭噴薄，江岫相縈繞。", "直上孤頂高，平看衆峰小。", "南州十二月，地暖冰雪少。", "青翠滿寒山，藤蘿覆冬沼。", "花龕瀑布側，青壁石林杪。", "鳴鐘集人天，施飯聚猨鳥。", "洗意歸清淨，澄心悟空了。", "始知世上人，萬物一何擾。"]'),
('b48414ae-ff62-4084-8e48-0afdb1ec5f92','入若耶溪','崔顥','唐','唐诗','tang','','[]','輕舟去何疾，已到雲林境。',48,'全唐诗/poet.tang.6000.json','["輕舟去何疾，已到雲林境。", "起坐魚鳥間，動搖山水影。", "巖中響自答，溪裏言彌靜。", "事事令人幽，停橈向餘景。"]'),
('62a772c1-f4b3-4e81-a9c9-fd8289d9bbd0','雜詩','崔顥','唐','唐诗','tang','','[]','可憐青銅鏡，挂在白玉堂。',48,'全唐诗/poet.tang.6000.json','["可憐青銅鏡，挂在白玉堂。", "玉堂有美女，嬌弄明月光。", "羅袖拂金鵲，綵屏點紅妝。", "妝罷含情坐，春風桃李香。"]'),
('086c86b3-f7dc-46a1-abc1-79b1a7cd5c8d','結定襄郡獄效陶體','崔顥','唐','唐诗','tang','','[]','我在河東時，使往定襄里。',132,'全唐诗/poet.tang.6000.json','["我在河東時，使往定襄里。", "定襄諸小兒，爭訟紛城市。", "長老莫敢言，太守不能理。", "謗書盈几案，文墨相填委。", "牽引肆中翁，追呼田家子。", "我來折此獄，五聽辨疑似。", "小大必以情，未嘗施鞭箠。", "是時三月暮，遍野農桑起。", "里巷鳴春鳩，田園引流水。", "此鄉多雜俗，戎夏殊音旨。", "顧問邊塞人，勞情曷云已。"]'),
('626e8a4f-da45-45a2-9846-192bfd74b29d','長安道','崔顥','唐','唐诗','tang','','[]','長安甲第高入雲，誰家居住霍將軍。',80,'全唐诗/poet.tang.6000.json','["長安甲第高入雲，誰家居住霍將軍。", "日晚朝迴擁賓從，路傍揖拜何紛紛。", "莫言炙手手可熱，須臾火盡灰亦滅。", "莫言貧賤即可欺，人生富貴自有時。", "一朝天子賜眼色，世上悠悠應始知。"]'),
('caae3e7c-229e-4620-be4f-3a541d27d10d','行路難','崔顥','唐','唐诗','tang','','[]','君不見建章宮中金明枝，萬萬長條拂地垂。',163,'全唐诗/poet.tang.6000.json','["君不見建章宮中金明枝，萬萬長條拂地垂。", "二月三月花如霰，九重幽深君不見。", "豔彩朝含四寶宮，香風旦入朝雲殿。", "漢家宮女春未闌，愛此芳香朝暮看。", "看來看去心不忘，攀折將安鏡臺上。", "雙雙素手剪不成，兩兩紅妝笑相向。", "建章昨夜起春風，一花飛落長信宮。", "長信麗人見花泣，憶此珍樹何嗟及。", "我昔初在昭陽時，朝攀暮折登玉墀。", "只言歲歲長相對，不悟今朝遙相思。"]'),
('870e3d7e-233c-4ceb-99ba-f71702a0a809','孟門行','崔顥','唐','唐诗','tang','','[]','黃雀銜黃花，翩翩傍簷隙。',104,'全唐诗/poet.tang.6000.json','["黃雀銜黃花，翩翩傍簷隙。", "本擬報君恩，如何反彈射。", "金罍美酒滿座春，平原愛才多衆賓。", "滿堂盡是忠義士，何意得有讒諛人。", "諛言反覆那可道，能令君心不自保。", "北園新栽桃李枝，根株未固何轉移。", "成陰結實君自取，若問傍人那得知。"]'),
('fed02b0e-1351-48cd-aa27-b14f6231b6de','渭城少年行','崔顥','唐','唐诗','tang','','[]','洛陽三月梨花飛，秦地行人春憶歸。',240,'全唐诗/poet.tang.6000.json','["洛陽三月梨花飛，秦地行人春憶歸。", "揚鞭走馬城南陌，朝逢驛使秦川客。", "驛使前日發章臺，傳道長安春早來。", "棠梨宮中燕初至，葡萄館裏花正開。", "念此使人歸更早，三月便達長安道。", "長安道上春可憐，搖風蕩日曲江邊。", "萬戶樓臺臨渭水，五陵花柳滿秦川。", "秦川寒食盛繁華，遊子春來不見家。", "鬬雞下杜塵初合，走馬章臺日半斜。", "章臺帝城稱貴里，青樓日晚歌鐘起。", "貴里豪家白馬驕，五陵年少不相饒。", "雙雙挾彈來金市，兩兩鳴鞭上渭橋。", "渭城橋頭酒新熟，金鞍白馬誰家宿。", "可憐錦瑟箏琵琶，玉壺清酒就倡家。", "小婦春來不解羞，嬌歌一曲楊柳花。"]'),
('bc702506-923c-4555-a124-a12b9c4bfb04','盧姬篇','崔顥','唐','唐诗','tang','','[]','盧姬少小魏王家，綠鬢紅脣桃李花。',112,'全唐诗/poet.tang.6000.json','["盧姬少小魏王家，綠鬢紅脣桃李花。", "魏王綺樓十二重，水晶簾箔繡芙蓉。", "白玉欄干金作柱，樓上朝朝學歌舞。", "前堂後堂羅袖人，南窗北窗花發春。", "翠幌珠簾鬬絲管，一彈一奏雲欲斷。", "君王日晚下朝歸，鳴環佩玉生光輝。", "人生今日得嬌貴，誰道盧姬身細微。"]'),
('9b0d1abc-7a10-4a1d-bf12-b8bf9be0f9a0','江畔老人愁','崔顥','唐','唐诗','tang','','[]','江南年少十八九，乘舟欲渡青溪口。',304,'全唐诗/poet.tang.6000.json','["江南年少十八九，乘舟欲渡青溪口。", "青溪口邊一老翁，鬢眉皓白已衰朽。", "自言家代仕梁陳，垂朱拖紫三十人。", "兩朝出將復入相，五世疊鼓乘朱輪。", "父兄三葉皆尚主，子女四代爲妃嬪。", "南山賜田接御苑，北宮甲第連紫宸。", "直言榮華未休歇，不覺山崩海將竭。", "兵戈亂入建康城，煙火連燒未央闕。", "衣冠士子陷鋒刃，良將名臣盡埋沒。", "山川改易失市朝，衢路縱橫填白骨。", "老人此時尚少年，脫身走得投海邊。", "罷兵歲餘未敢出，去鄉三載方來旋。", "蓬蒿忘却五城宅，草木不識青谿田。", "雖然得歸到鄉土，零丁貧賤長辛苦。", "采樵屢入歷陽山，刈稻常過新林浦。", "少年欲知老人歲，豈知今年一百五。", "君今少壯我已衰，我昔少年君不睹。", "人生貴賤各有時，莫見羸老相輕欺。", "感君相問爲君說，說罷不覺令人悲。"]'),
('d4aa078e-4ffc-4198-9110-6019fa6fe7ee','邯鄲宮人怨','崔顥','唐','唐诗','tang','','[]','邯鄲陌上三月春，暮行逢見一婦人。',384,'全唐诗/poet.tang.6000.json','["邯鄲陌上三月春，暮行逢見一婦人。", "自言鄉里本燕趙，少小隨家西入秦。", "母兄憐愛無儔侶，五歲名爲阿嬌女。", "七歲丰茸好顏色，八歲黠惠能言語。", "十三兄弟教詩書，十五青樓學歌舞。", "我家青樓臨道傍，紗窗綺幔暗聞香。", "日暮笙歌君駐馬，春日妝梳妾斷腸。", "不用城南使君壻，本求三十侍中郎。", "何知漢帝好容色，玉輦攜登歸建章。", "建章宮殿不知數，萬戶千門深且長。", "百堵塗椒接青瑣，九華閣道連洞房。", "水晶簾箔雲母扇，琉璃窗牖玳瑁牀。", "歲歲年年奉歡宴，嬌貴榮華誰不羨。", "恩情莫比陳皇后，寵愛全勝趙飛燕。", "瑤房侍寢世莫知，金屋更衣人不見。", "誰言一朝復一日，君王棄世市朝變。", "宮車出葬茂陵田，賤妾獨留長信殿。", "一朝太子升至尊，宮中人事如掌翻。", "同時侍女見讒毀，後來新人莫敢言。", "兄弟印綬皆被奪，昔年賞賜不復存。", "一旦放歸舊鄉里，乘車垂淚還入門。", "父母愍我曾富貴，嫁與西舍金王孫。", "念此翻覆復何道，百年盛衰誰能保。", "憶昨尚如春日花，悲今已作秋時草。"]'),
('5d60c870-b3f3-4a18-8d5e-584533f24e9e','川上女','崔顥','唐','唐诗','tang','','[]','川上女，晚妝鮮。',56,'全唐诗/poet.tang.6000.json','["川上女，晚妝鮮。", "日落青渚試輕檝，汀長花滿正迴船。", "暮來浪起風轉緊，自言此去橫塘近。", "綠江無伴夜獨行，獨行心緒愁無盡。"]'),
('2d5567c6-a8c1-4531-a2ef-f0e9531061bb','鴈門胡人歌','崔顥','唐','唐诗','tang','','["\u751f\u6d3b", "\u8fb9\u585e"]','高山代郡東接燕，鴈門胡人家近邊。',64,'全唐诗/poet.tang.6000.json','["高山代郡東接燕，鴈門胡人家近邊。", "解放胡鷹逐塞鳥，能將代馬獵秋田。", "山頭野火寒多燒，雨裏孤峰濕作煙。", "聞道遼西無鬬戰，時時醉向酒家眠。"]'),
('d0f5cd79-3d6f-4958-abc5-ab19729fccab','代閨人答輕薄少年','崔顥','唐','唐诗','tang','','[]','妾家近隔鳳凰池，粉壁紗窗楊柳垂。',160,'全唐诗/poet.tang.6000.json','["妾家近隔鳳凰池，粉壁紗窗楊柳垂。", "本期漢代金吾壻，誤嫁長安遊俠兒。", "兒家夫壻多輕薄，借客探丸重然諾。", "平明挾彈入新豐，日晚揮鞭出長樂。", "青絲白馬冶遊園，能使行人駐馬看。", "自矜陌上繁華盛，不念閨中花鳥闌。", "花間陌上春將晚，走馬鬬雞猶未返。", "三時出望無消息，一去那知行近遠。", "桃李花開覆井欄，朱樓落日捲簾看。", "愁來欲奏相思曲，抱得秦箏不忍彈。"]'),
('2702a1f6-bbac-4c86-90c1-1436804046b8','七夕','崔顥','唐','唐诗','tang','','[]','長安城中月如練，家家此夜持針線。',64,'全唐诗/poet.tang.6000.json','["長安城中月如練，家家此夜持針線。", "仙裙玉佩空自知，天上人間不相見。", "長信深陰夜轉幽，瑤堦金閣數螢流。", "班姬此夕愁無限，河漢三更看斗牛。"]'),
('d3e4b2ee-f3fe-466f-a391-964efd13eb0b','長門怨','崔顥','唐','唐诗','tang','','[]','君王寵初歇，棄妾長門宮。',48,'全唐诗/poet.tang.6000.json','["君王寵初歇，棄妾長門宮。", "紫殿青苔滿，高樓明月空。", "夜愁生枕席，春意罷簾櫳。", "泣盡無人問，容華落鏡中。"]'),
('e084dced-a458-4721-aca9-f7c668a0e5a7','王家少婦','崔顥','唐','唐诗','tang','','[]','十五嫁王昌，盈盈入畫堂。',48,'全唐诗/poet.tang.6000.json','["十五嫁王昌，盈盈入畫堂。", "自矜年最少，復倚壻爲郎。", "舞愛前谿綠，歌憐子夜長。", "閑來鬬百草，度日不成妝。"]'),
('7939cb25-46f7-4c07-80f4-e38cea026602','岐王席觀妓','崔顥','唐','唐诗','tang','','[]','二月春來半，宮中日漸長。',48,'全唐诗/poet.tang.6000.json','["二月春來半，宮中日漸長。", "柳垂金屋煖，花發玉樓香。", "拂匣先臨鏡，調笙更炙簧。", "還將歌舞態，只擬奉君王。"]'),
('e3b557f1-e7f7-4522-9eac-b3045ef4de2a','上巳','崔顥','唐','唐诗','tang','','[]','巳日帝城春，傾都祓禊晨。',48,'全唐诗/poet.tang.6000.json','["巳日帝城春，傾都祓禊晨。", "停車須傍水，奏樂要驚塵。", "弱柳障行騎，浮橋擁看人。", "猶言日尚早，更向九龍津。"]'),
('117aeb95-316c-4841-95fa-99fe405f5bb8','贈梁州張都督','崔顥','唐','唐诗','tang','','[]','聞君爲漢將，虜騎罷南侵。',48,'全唐诗/poet.tang.6000.json','["聞君爲漢將，虜騎罷南侵。", "出塞清沙漠，還家拜羽林。", "風霜臣節苦，歲月主恩深。", "爲語西河使，知余報國心。"]'),
('04a613bf-b268-4b75-9b4d-77bf3490f1c9','贈盧八象','崔顥','唐','唐诗','tang','','[]','客從巴水渡，傳爾泝行舟。',48,'全唐诗/poet.tang.6000.json','["客從巴水渡，傳爾泝行舟。", "是日風波霽，高堂雨半收。", "青山滿蜀道，綠水向荆州。", "不作書相問，誰能慰別愁。"]'),
('6b8258d9-5cc5-4bde-9768-94b3e9e9ef39','題潼關樓','崔顥','唐','唐诗','tang','','[]','客行逢雨霽，歇馬上津樓。',48,'全唐诗/poet.tang.6000.json','["客行逢雨霽，歇馬上津樓。", "山勢雄三輔，關門扼九州。", "川從陝路去，河遶華陰流。", "向晚登臨處，風煙萬里愁。"]'),
('b6646529-868b-4b18-85b2-0e39c7171005','題沈隱侯八詠樓','崔顥','唐','唐诗','tang','','[]','梁日東陽守，爲樓望越中。',48,'全唐诗/poet.tang.6000.json','["梁日東陽守，爲樓望越中。", "綠窗明月在，青史古人空。", "江靜聞山狖，川長數塞鴻。", "登臨白雲晚，流恨此遺風。"]'),
('7f7c00be-7da2-42b5-8465-806de1d0414b','晚入汴水','崔顥','唐','唐诗','tang','','[]','昨晚南行楚，今朝北泝河。',48,'全唐诗/poet.tang.6000.json','["昨晚南行楚，今朝北泝河。", "客愁能幾日，鄉路漸無多。", "晴景搖津樹，春風起棹歌。", "長淮亦已盡，寧復畏潮波。"]'),
('d374479f-b077-4bcb-baea-30b804709138','發錦沙村','崔顥','唐','唐诗','tang','','[]','北上途未半，南行歲已闌。',48,'全唐诗/poet.tang.6000.json','["北上途未半，南行歲已闌。", "孤舟下建德，江水入新安。", "海近山常雨，谿深地早寒。", "行行泊不可，須及子陵灘。"]'),
('89873bcc-ae02-40f3-a288-583573acfc96','送單于裴都護赴西河','崔顥','唐','唐诗','tang','','["\u9001\u522b", "\u795d\u613f", "\u8fb9\u585e"]','征馬去翩翩，城秋月正圓。',48,'全唐诗/poet.tang.6000.json','["征馬去翩翩，城秋月正圓。", "單于莫近塞，都護欲臨邊。", "漢驛通煙火，胡沙乏井泉。", "功成須獻捷，未必去經年。"]'),
('2188f98e-d5f0-4740-b94b-e1497a3619ee','黃鶴樓','崔顥','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9ec4\u9e64\u697c", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u516b\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u5199\u666f"]','昔人已乘白雲去，此地空餘黃鶴樓。',64,'全唐诗/poet.tang.6000.json','["昔人已乘白雲去，此地空餘黃鶴樓。", "黃鶴一去不復返，白雲千載空悠悠。", "晴川歷歷漢陽樹，春草萋萋鸚鵡洲。", "日暮鄉關何處是，煙波江上使人愁。"]'),
('39b2954c-04df-4561-ad6e-f4ddbae0db1e','行經華陰','崔顥','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u6000\u53e4", "\u5c71\u6c34"]','岧嶤太華俯咸京，天外三峰削不成。',64,'全唐诗/poet.tang.6000.json','["岧嶤太華俯咸京，天外三峰削不成。", "武帝祠前雲欲散，仙人掌上雨初晴。", "河山北枕秦關險，驛樹西連漢畤平。", "借問路傍名利客，無如此處學長生。"]'),
('6ab6d4a2-cebc-4d9b-994c-f3e95fb6e98a','相逢行','崔顥','唐','唐诗','tang','','[]','妾年初二八，家住洛橋頭。',72,'全唐诗/poet.tang.6000.json','["妾年初二八，家住洛橋頭。", "玉戶臨馳道，朱門近御溝。", "使君何假問，夫壻大長秋。", "女弟新承寵，諸兄近拜侯。", "春生百子殿，花發五城樓。", "出入千門裏，年年樂未休。"]'),
('228cc6fa-c659-4ee8-a9c9-9242ae570970','遼西作','崔顥','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e"]','燕郊芳歲晚，殘雪凍邊城。',72,'全唐诗/poet.tang.6000.json','["燕郊芳歲晚，殘雪凍邊城。", "四月青草合，遼陽春水生。", "胡人正牧馬，漢將日徵兵。", "露重寶刀濕，沙虛金鼓鳴。", "寒衣著已盡，春服與誰成。", "寄語洛陽使，爲傳邊塞情。"]'),
('c115c820-4001-45ac-8612-c7b58d4a86f9','奉和許給事夜直簡諸公','崔顥','唐','唐诗','tang','','[]','西掖黃樞近，東曹紫禁連。',96,'全唐诗/poet.tang.6000.json','["西掖黃樞近，東曹紫禁連。", "地因才子拜，人用省郎遷。", "夜直千門靜，河明萬象懸。", "建章宵漏急，閶闔曉鐘傳。", "寵列貂蟬位，恩深侍從年。", "九重初起草，五夜即成篇。", "顧己無官次，循涯但自憐。", "遠陪蘭署作，空此仰神仙。"]'),
('ed672ad2-1a5b-4bc5-b0e1-5ed1ea49dc1e','舟行入剡','崔顥','唐','唐诗','tang','','[]','鳴棹下東陽，回舟入剡鄉。',72,'全唐诗/poet.tang.6000.json','["鳴棹下東陽，回舟入剡鄉。", "青山行不盡，綠水去何長。", "地氣秋仍濕，江風晚漸涼。", "山梅猶作雨，谿橘未知霜。", "謝客文逾盛，林公未可忘。", "多慚越中好，流恨閱時芳。"]'),
('40c9280d-c221-4d4e-bc63-86c853be15bf','澄水如鑑','崔顥','唐','唐诗','tang','','[]','聖賢將立喻，上善貯情深。',72,'全唐诗/poet.tang.6000.json','["聖賢將立喻，上善貯情深。", "潔白依全德，澄清有片心。", "澆浮知不撓，濫濁固難侵。", "方寸懸高鑑，生涯詎陸沈。", "對泉能自誡，如鏡靜相臨。", "廉慎傳家政，流芳合古今。"]'),
('c39225f9-16b2-4713-a11c-d7030ec3b1c9','長干曲四首 一','崔顥','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5b64\u72ec", "\u5973\u5b50", "\u601d\u4e61", "\u4e50\u5e9c"]','君家何處住？妾住在橫塘。',24,'全唐诗/poet.tang.6000.json','["君家何處住？妾住在橫塘。", "停船暫借問，或恐是同鄉。"]'),
('4a732464-35a5-4ffc-94d0-37d653eef2a1','長干曲四首 二','崔顥','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bb6\u4e61", "\u5973\u5b50", "\u70ed\u7231", "\u4e50\u5e9c"]','家臨九江水，來去九江側。',24,'全唐诗/poet.tang.6000.json','["家臨九江水，來去九江側。", "同是長干人，自小不相識。"]'),
('88c46a8d-d2b8-415d-9bae-1de77f2bfddd','長干曲四首 三','崔顥','唐','唐诗','tang','','[]','下渚多風浪，蓮舟漸覺稀。',24,'全唐诗/poet.tang.6000.json','["下渚多風浪，蓮舟漸覺稀。", "那能不相待，獨自逆潮歸。"]'),
('9f5f18e9-b433-48c2-9a89-fa1056b74e3a','長干曲四首 四','崔顥','唐','唐诗','tang','','[]','三江潮水急，五湖風浪湧。',24,'全唐诗/poet.tang.6000.json','["三江潮水急，五湖風浪湧。", "由來花性輕，莫畏蓮舟重。"]'),
('8d0784dc-e386-4237-8022-d24d8ae96d05','維揚送友還蘇州','崔顥','唐','唐诗','tang','','[]','長安南下幾程途，得到邗溝弔綠蕪。',32,'全唐诗/poet.tang.6000.json','["長安南下幾程途，得到邗溝弔綠蕪。", "渚畔鱸魚舟上釣，羨君歸老向東吳。"]'),
('fcde35d4-d776-498b-aee7-8f7f178df255','古意二首 一','祖詠','唐','唐诗','tang','','[]','夫差日淫放，舉國求妃嬪。',96,'全唐诗/poet.tang.6000.json','["夫差日淫放，舉國求妃嬪。", "自謂得王寵，代間無美人。", "碧羅象天閣，坐輦乘芳春。", "宮女數千騎，常遊江水濱。", "年深玉顏老，時薄花妝新。", "拭淚下金殿，嬌多不顧身。", "生前妬歌舞，死後同灰塵。", "冢墓令人哀，哀於銅雀臺。"]'),
('8ea0f553-cc8f-46b8-9a68-d1a80a71939d','古意二首 二','祖詠','唐','唐诗','tang','','[]','楚王竟何去，獨自留巫山。',72,'全唐诗/poet.tang.6000.json','["楚王竟何去，獨自留巫山。", "偏使世人見，迢迢江漢間。", "駐舟春谿裏，誓願拜靈顏。", "夢寐覩神女，金沙鳴珮環。", "閑豔絕世姿，令人氣力微。", "含笑默不語，化作朝雲飛。"]'),
('7d75943b-6a3a-4b5b-9aa7-bf78d26be182','渡淮河寄平一','祖詠','唐','唐诗','tang','','[]','天色混波濤，岸陰匝村墅。',36,'全唐诗/poet.tang.6000.json','["天色混波濤，岸陰匝村墅。", "微微漢祖廟，隱隱江陵渚。", "雲樹森已重，時明鬱相拒。"]'),
('7e6fcfbc-5fa7-49b3-b34d-82006fa958e5','歸汝墳山莊留別盧象','祖詠','唐','唐诗','tang','','[]','淹留歲將[晏]，久廢南山期。',62,'全唐诗/poet.tang.6000.json','["淹留歲將[晏]，久廢南山期。", "舊業不見棄，還山從此辭。", "漚麻入南澗，刈麥向東菑。", "對酒雞黍熟，閉門風雪時。", "非君一延首，誰慰遙相思。"]'),
('af12f90e-1f84-4b72-aacb-0a85933f67d8','夕次圃田店','祖詠','唐','唐诗','tang','','[]','前路入鄭郊，尚經百餘里。',48,'全唐诗/poet.tang.6000.json','["前路入鄭郊，尚經百餘里。", "馬煩時欲歇，客歸程未已。", "落日桑柘陰，遙村煙火起。", "西還不遑宿，中夜渡涇水。"]'),
('39893b55-0af2-4090-98b9-c7eea69663df','田家即事','祖詠','唐','唐诗','tang','','[]','舊居東臯上，左右俯荒村。',96,'全唐诗/poet.tang.6000.json','["舊居東臯上，左右俯荒村。", "樵路前傍嶺，田家遙對門。", "歡娛始披拂，愜意在郊原。", "餘霽蕩川霧，新秋仍晝昏。", "攀條憩林麓，引水開泉源。", "稼穡豈云倦，桑麻今正繁。", "方求靜者賞，偶與潛夫論。", "雞黍何必具，吾心知道尊。"]'),
('cfcc81e1-e1a5-4138-87c4-a58eac0c0076','扈從御宿池','祖詠','唐','唐诗','tang','','[]','君王既巡狩，輦道入秦京。',48,'全唐诗/poet.tang.6000.json','["君王既巡狩，輦道入秦京。", "遠樹低槍壘，孤峯入幔城。", "寒疎清禁漏，夜警羽林兵。", "誰念迷方客，長懷魏闕情。"]'),
('a0606067-a985-4ce7-b1a4-7a2764e78ee8','贈苗發員外','祖詠','唐','唐诗','tang','','[]','宿雨朝來歇，空山天氣清。',48,'全唐诗/poet.tang.6000.json','["宿雨朝來歇，空山天氣清。", "盤雲雙鶴下，隔水一蟬鳴。", "古道黃花落，平蕪赤燒生。", "茂陵雖有病，猶得伴君行。"]'),
('85f22040-1449-4dd7-bfe5-9674db1faa0a','答王維留宿','祖詠','唐','唐诗','tang','','[]','四年不相見，相見復何爲。',48,'全唐诗/poet.tang.6000.json','["四年不相見，相見復何爲。", "握手言未畢，却令傷別離。", "升堂還駐馬，酌醴便呼兒。", "語嘿自相對，安用傍人知。"]'),
('7b6ae1ac-edf2-4c8b-867f-cbcf098a45a5','長樂驛留別盧象裴總','祖詠','唐','唐诗','tang','','[]','朝來已握手，宿別更傷心。',48,'全唐诗/poet.tang.6000.json','["朝來已握手，宿別更傷心。", "灞水行人渡，商山驛路深。", "故情君且足，謫宦我難任。", "直道皆如此，誰能淚滿襟。"]'),
('12ed2359-fa68-40fa-aeac-a00e3189892d','送劉高郵棁使入都','祖詠','唐','唐诗','tang','','[]','常聞積歸思，昨夜又兼秋。',48,'全唐诗/poet.tang.6000.json','["常聞積歸思，昨夜又兼秋。", "鄉路京華遠，王程江水流。", "吳歌喧兩岸，楚客醉孤舟。", "漸覺潮初上，悽然多暮愁。"]'),
('de5e4d03-d660-4da2-bf4e-1db97a7ab281','宴吳王宅','祖詠','唐','唐诗','tang','','[]','吳王承國寵，列第禁城東。',48,'全唐诗/poet.tang.6000.json','["吳王承國寵，列第禁城東。", "連夜徵詞客，當春試舞童。", "砌分池水岸，牕度竹林風。", "更待西園月，金尊樂未終。"]'),
('669c6ad1-70fa-48e9-9a54-35d35610c204','觀華嶽','祖詠','唐','唐诗','tang','','["\u534e\u5c71"]','西入秦關口，南瞻驛路連。',48,'全唐诗/poet.tang.6000.json','["西入秦關口，南瞻驛路連。", "彩雲生闕下，松樹到祠邊。", "作鎮當官道，雄都俯大川。", "蓮峯徑上處，彷彿有神仙。"]'),
('875a466e-3eca-4713-9bbc-de9355c4ede3','泗上馮使君南樓作','祖詠','唐','唐诗','tang','','[]','井邑連淮泗，南樓向晚過。',48,'全唐诗/poet.tang.6000.json','["井邑連淮泗，南樓向晚過。", "望灘沙鷺起，尋岸浴童歌。", "近海雲偏出，兼秋雨更多。", "明晨擬回棹，鄉思恨風波。"]'),
('094290fb-5df1-4277-a3e5-a9d321fdfc1e','蘇氏別業','祖詠','唐','唐诗','tang','','[]','別業居幽處，到來生隱心。',48,'全唐诗/poet.tang.6000.json','["別業居幽處，到來生隱心。", "南山當戶牖，灃水映園林。", "屋覆經冬雪，庭昏未夕陰。", "寥寥人境外，閑坐聽春禽。"]'),
('90652c8c-0dbc-4eae-8e27-edd71d621b92','汝墳別業','祖詠','唐','唐诗','tang','','[]','失路農爲業，移家到汝墳。',48,'全唐诗/poet.tang.6000.json','["失路農爲業，移家到汝墳。", "獨愁常廢卷，多病久離羣。", "鳥雀垂窻柳，虹霓出澗雲。", "山中無外事，樵唱有時聞。"]'),
('d397f8cb-15aa-4f2f-b219-701143cc8a8d','陸渾水亭','祖詠','唐','唐诗','tang','','[]','晝眺伊川曲，巖間霽色明。',48,'全唐诗/poet.tang.6000.json','["晝眺伊川曲，巖間霽色明。", "淺沙平有路，流水漫無聲。", "浴鳥沿波聚，潛魚觸釣驚。", "更憐春岸綠，幽意滿前楹。"]'),
('f5c208b5-2519-4f27-bbc7-b40989770878','過鄭曲','祖詠','唐','唐诗','tang','','[]','路向榮川谷，晴來望盡通。',48,'全唐诗/poet.tang.6000.json','["路向榮川谷，晴來望盡通。", "細煙生水上，圓月在舟中。", "岸勢迷行客，秋聲亂草蟲。", "旅懷勞自慰，淅淅有涼風。"]'),
('20e22daf-a545-4517-98ae-ded485dde817','宿陳留李少府揆廳','祖詠','唐','唐诗','tang','','[]','相知有叔卿，訟簡夜彌清。',48,'全唐诗/poet.tang.6000.json','["相知有叔卿，訟簡夜彌清。", "旅泊倦愁臥，堂空聞曙更。", "風簾搖燭影，秋雨帶蟲聲。", "歸思那堪說，悠悠限洛城。"]'),
('0656e444-ea22-4f09-a0aa-397e204ea5a9','題韓少府水亭','祖詠','唐','唐诗','tang','','[]','梅福幽棲處，佳期不忘還。',48,'全唐诗/poet.tang.6000.json','["梅福幽棲處，佳期不忘還。", "鳥吟當戶竹，花繞傍池山。", "水氣侵階冷，松陰覆座閑。", "寧知武陵趣，宛在市朝間。"]'),
('019312e6-a9e8-4ba7-a66e-2e11838403f3','題遠公經臺','祖詠','唐','唐诗','tang','','[]','蘭若無人到，真僧出復稀。',48,'全唐诗/poet.tang.6000.json','["蘭若無人到，真僧出復稀。", "苔侵行道席，雲濕坐禪衣。", "澗鼠緣香案，山蟬噪竹扉。", "世間長不見，寧止暫忘歸。"]'),
('5d79e014-ba3f-430a-b0c2-a5224d032904','中峯居喜見苗發','祖詠','唐','唐诗','tang','','[]','自得中峰住，深林亦閉關。',48,'全唐诗/poet.tang.6000.json','["自得中峰住，深林亦閉關。", "經秋無客到，入夜有僧還。", "暗澗泉聲小，荒岡樹影閑。", "高窻不可望，星月滿空山。"]'),
('076912b3-7157-481a-a955-2bf4f35c928c','江南旅情','祖詠','唐','唐诗','tang','','["\u6c5f\u5357", "\u601d\u5ff5", "\u5bb6\u4e61", "\u666f\u8272"]','楚山不可極，歸路但蕭條。',48,'全唐诗/poet.tang.6000.json','["楚山不可極，歸路但蕭條。", "海色晴看雨，江聲夜聽潮。", "劒留南斗近，書寄北風遙。", "爲報空潭橘，無媒寄洛橋。"]'),
('9b188774-5b9b-47e3-b91a-2df0e8b60a7c','泊揚子津','祖詠','唐','唐诗','tang','','[]','纔入維揚郡，鄉關此路遙。',48,'全唐诗/poet.tang.6000.json','["纔入維揚郡，鄉關此路遙。", "林藏初過雨，風退欲歸潮。", "江火明沙岸，雲帆礙浦橋。", "客衣今日薄，寒氣近來饒。"]'),
('e5bf3b92-7b85-462f-ad14-2a46edc0e73e','晚泊金陵水亭','祖詠','唐','唐诗','tang','','[]','江亭當廢國，秋景倍蕭騷。',48,'全唐诗/poet.tang.6000.json','["江亭當廢國，秋景倍蕭騷。", "夕照明殘壘，寒潮漲古濠。", "就田看鶴大，隔水見僧高。", "無限前朝事，醒吟易覺勞。"]'),
('a28adab8-eaed-46eb-862b-7768e8c7079e','七夕','祖詠','唐','唐诗','tang','','[]','閨女求天女，更闌意未闌。',48,'全唐诗/poet.tang.6000.json','["閨女求天女，更闌意未闌。", "玉庭開粉席，羅袖捧金盤。", "向月穿針易，臨風整線難。", "不知誰得巧，明旦試相看。"]'),
('6beb5cc2-ae49-4e23-952a-1cb92fa11512','望薊門','祖詠','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u51ac\u5929", "\u8fb9\u585e"]','燕臺一望客心驚，簫鼓喧喧漢將營。',64,'全唐诗/poet.tang.6000.json','["燕臺一望客心驚，簫鼓喧喧漢將營。", "萬里寒光生積雪，三邊曙色動危旌。", "沙場烽火連胡月，海畔雲山擁薊城。", "少小雖非投筆吏，論功還欲請長纓。"]'),
('b458b829-a8a7-4325-82f2-678e0c93fb7f','家園夜坐寄郭微','祖詠','唐','唐诗','tang','','[]','前堦微雨歇，開戶散窺林。',72,'全唐诗/poet.tang.6000.json','["前堦微雨歇，開戶散窺林。", "月出夜方淺，水涼池更深。", "餘風生竹樹，清露薄衣襟。", "遇物遂遙歎，懷人滋遠心。", "依稀成夢想，影響絕徽音。", "誰念窮居者，明時嗟陸沈。"]'),
('53de2321-a23d-49b9-84d6-822713c3dee4','酬汴州李別駕贈','祖詠','唐','唐诗','tang','','[]','秋風多客思，行旅厭艱辛。',72,'全唐诗/poet.tang.6000.json','["秋風多客思，行旅厭艱辛。", "自洛非才子，遊梁得主人。", "文章參末議，榮賤豈同倫。", "歎逝逢三演，懷賢憶四真。", "情因恩舊好，契託死生親。", "所媿能投贈，清言益潤身。"]'),
('82f66261-c88c-4823-b28e-0ef5b1b291cd','清明宴司勳劉郎中別業','祖詠','唐','唐诗','tang','','[]','田家復近臣，行樂不違親。',72,'全唐诗/poet.tang.6000.json','["田家復近臣，行樂不違親。", "霽日園林好，清明煙火新。", "以文長會友，唯德自成鄰。", "池照窻陰晚，杯香藥味春。", "簷前花覆地，竹外鳥窺人。", "何必桃源裏，深居作隱淪。"]'),
('57431a69-8bd2-493d-a83c-53e7449f6834','汝墳秋同仙州王長史翰聞百舌鳥','祖詠','唐','唐诗','tang','','[]','秋天聞好鳥，驚起出簾帷。',120,'全唐诗/poet.tang.6000.json','["秋天聞好鳥，驚起出簾帷。", "却念殊方月，能鳴已後時。", "遷喬誠可早，出谷此何遲。", "顧影慙無對，懷羣空所思。", "淒涼歲欲晚，蕭索燕將辭。", "留聽未終曲，彌令心獨悲。", "高飛憑力致，巧囀任天姿。", "返覆知而靜，間關斷若遺。", "花繁上林路，霜落汝川湄。", "且長凌風翮，乘春自有期。"]'),
('9f597a8a-e251-4c46-8079-8270f24cd34c','送丘爲下第','祖詠','唐','唐诗','tang','','[]','滄江一身客，獻賦空十年。',60,'全唐诗/poet.tang.6000.json','["滄江一身客，獻賦空十年。", "明主豈能好，今人誰舉賢。", "國門稅征駕，旅食謀歸旋。", "皦日媚春水，綠蘋香客船。", "無媒既不達，予亦思歸田。"]'),
('58f5c1c1-fe8d-4475-b394-c68013ebd2ff','贈苗發員外','祖詠','唐','唐诗','tang','','[]','朱戶敞高扉，青槐礙落暉。',72,'全唐诗/poet.tang.6000.json','["朱戶敞高扉，青槐礙落暉。", "八龍乘慶重，三虎遞朝歸。", "坐竹人聲絕，橫琴鳥語稀。", "花慙潘岳貌，年稱老萊衣。", "葉暗朱櫻熟，絲長粉蝶飛。", "應憐魯儒賤，空與故山違。"]'),
('491be4cd-418f-423a-94bf-cf97fba6fea7','寄王長史','祖詠','唐','唐诗','tang','','[]','汝潁俱宿好，往來託層巒。',24,'全唐诗/poet.tang.6000.json','["汝潁俱宿好，往來託層巒。", "終日何寂寞，繞籬生蕙蘭。"]'),
('5eae5172-49fa-46f0-89a9-fa4261f928f1','別怨','祖詠','唐','唐诗','tang','','[]','送別到中流，秋船倚渡頭。',24,'全唐诗/poet.tang.6000.json','["送別到中流，秋船倚渡頭。", "相看尚不遠，未可即回舟。"]'),
('b4780bd1-1703-4bce-a801-d5ed566826b5','終南望餘雪','祖詠','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u96ea", "\u51ac\u5929", "\u5199\u666f", "\u96ea", "\u51ac"]','終南陰嶺秀，積雪浮雲端。',24,'全唐诗/poet.tang.6000.json','["終南陰嶺秀，積雪浮雲端。", "林表明霽色，城中增暮寒。"]'),
('9fda363f-0256-488d-bf60-a1a7250aee6c','句','祖詠','唐','唐诗','tang','','[]','不知疊嶂夜來雨，清曉石楠花亂流。',16,'全唐诗/poet.tang.6000.json','["不知疊嶂夜來雨，清曉石楠花亂流。"]'),
('c28945b1-db29-432b-85ce-ddc66101a12d','湘夫人','李頎','唐','唐诗','tang','','[]','九嶷日已暮，三湘雲復愁。',36,'全唐诗/poet.tang.6000.json','["九嶷日已暮，三湘雲復愁。", "窅靄羅袂色，潺湲江水流。", "佳期來北渚，捐佩在芳洲。"]'),
('bdf3a5d1-3079-43a7-93eb-b77bdff46f9d','塞下曲','李頎','唐','唐诗','tang','','[]','黃雲雁門郡，日暮風沙裏。',48,'全唐诗/poet.tang.6000.json','["黃雲雁門郡，日暮風沙裏。", "千騎黑貂裘，皆稱羽林子。", "金笳吹朔雪，鐵馬嘶雲水。", "帳下飲蒲萄，平生寸心是。"]'),
('752d1ba0-6bc4-408e-b07a-757fcc653f7b','古塞下曲','李頎','唐','唐诗','tang','','["\u8fb9\u585e"]','行人朝走馬，直指薊城傍。',72,'全唐诗/poet.tang.6000.json','["行人朝走馬，直指薊城傍。", "薊城通漠北，萬里別吾鄉。", "海上千烽火，沙中百戰場。", "軍書發上郡，春色度河陽。", "褭褭漢宮柳，青青胡地桑。", "琵琶出塞曲，橫笛斷君腸。"]'),
('5667797f-6e78-4ef2-b041-6af59b44a0c2','漁父歌','李頎','唐','唐诗','tang','','[]','白首何老人，蓑笠蔽其身。',96,'全唐诗/poet.tang.6000.json','["白首何老人，蓑笠蔽其身。", "避世長不仕，釣魚清江濱。", "浦沙明濯足，山月靜垂綸。", "寓宿湍與瀨，行歌秋復春。", "持竿湘岸竹，爇火蘆洲薪。", "綠水飯香稻，青荷包紫鱗。", "於中還自樂，所欲全吾真。", "而笑獨醒者，臨流多苦辛。"]'),
('6f460078-ac6f-47bf-b189-abb2bdc73ef9','東京寄萬楚','李頎','唐','唐诗','tang','','[]','濩落久無用，隱身甘采薇。',120,'全唐诗/poet.tang.6000.json','["濩落久無用，隱身甘采薇。", "仍聞薄宦者，還事田家衣。", "潁水日夜流，故人相見稀。", "春山不可望，黃鳥東南飛。", "濯足豈長往，一樽聊可依。", "了然潭上月，適我胷中機。", "在昔同門友，如今出處非。", "優遊白虎殿，偃息青瑣闈。", "且有薦君表，當看攜手歸。", "寄書不待面，蘭茝空芳菲。"]'),
('4cc5bce5-f928-4b20-b197-10a45c33e94a','寄焦鍊師','李頎','唐','唐诗','tang','','[]','得道凡百歲，燒丹惟一身。',72,'全唐诗/poet.tang.6000.json','["得道凡百歲，燒丹惟一身。", "悠悠孤峰頂，日見三花春。", "白鶴翠微裏，黃精幽澗濱。", "始知世上客，不及山中人。", "仙境若在夢，朝雲如可親。", "何由覩顏色，揮手謝風塵。"]'),
('96b9e04a-62fc-4192-af6b-71b7dddb3fc5','望鳴臯山白雲寄洛陽盧主簿','李頎','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','飲馬伊水中，白雲鳴臯上。',120,'全唐诗/poet.tang.6000.json','["飲馬伊水中，白雲鳴臯上。", "氛氳山絕頂，行子時一望。", "照日龍虎姿，攢空冰雪狀。", "嵡嵸殊未已，崚嶒忽相向。", "皎皎橫綠林，霏霏澹青嶂。", "遠映村更失，孤高鶴來傍。", "勝氣欣有逢，仙遊且難訪。", "故人吏京劇，每事多閑放。", "室畫峨眉峯，心格洞庭浪。", "惜哉清興裏，不見予所尚。"]'),
('a83f4910-6850-485d-afb8-4fd181db58e7','寄萬齊融','李頎','唐','唐诗','tang','','[]','名高不擇仕，委世隨虛舟。',120,'全唐诗/poet.tang.6000.json','["名高不擇仕，委世隨虛舟。", "小邑常歎屈，故鄉行可遊。", "青楓半村戶，香稻盈田疇。", "爲政日清淨，何人同海鷗。", "搖巾北林夕，把菊東山秋。", "對酒池雲滿，向家湖水流。", "岸陰止鳴鵠，山色映潛虯。", "靡靡俗中理，蕭蕭川上幽。", "昔年至吳郡，常隱臨江樓。", "我有一書札，因之芳杜洲。"]'),
('b319c3ce-bca6-48c0-b619-ab9ec41aab54','贈張旭','李頎','唐','唐诗','tang','','["\u592a\u6e56"]','張公性嗜酒，豁達無所營。',144,'全唐诗/poet.tang.6000.json','["張公性嗜酒，豁達無所營。", "皓首窮草隸，時稱太湖精。", "露頂據胡牀，長呌三五聲。", "興來灑素壁，揮筆如流星。", "下舍風蕭條，寒草滿戶庭。", "問家何所有，生事如浮萍。", "左手持蟹螯，右手執丹經。", "瞪目視霄漢，不知醉與醒。", "諸賓且方坐，旭日臨東城。", "荷葉裹江魚，白甌貯香秔。", "微祿心不屑，放神於八紘。", "時人不識者，即是安期生。"]'),
('e51a3ce2-cc8f-424a-a54c-43b4052eb172','贈蘇明府','李頎','唐','唐诗','tang','','[]','蘇君年幾許，狀貌如玉童。',120,'全唐诗/poet.tang.6000.json','["蘇君年幾許，狀貌如玉童。", "采藥傍梁宋，共言隨日翁。", "常辭小縣宰，一往東山東。", "不復有家室，悠悠人世中。", "子孫皆老死，相識悲轉蓬。", "髮白還更黑，身輕行若風。", "汎然無所繫，心與孤雲同。", "出入雖一杖，安然知始終。", "願聞素女事，去采山花叢。", "誘我爲弟子，逍遙尋葛洪。"]'),
('f244e07a-9f1b-4bf2-957f-8c2ae2d78809','登首陽山謁夷齊廟','李頎','唐','唐诗','tang','','["\u9ec4\u6cb3"]','古人已不見，喬木竟誰過。',108,'全唐诗/poet.tang.6000.json','["古人已不見，喬木竟誰過。", "寂寞首陽山，白雲空復多。", "蒼苔歸地骨，皓首采薇歌。", "畢命無怨色，成仁其若何。", "我來入遺廟，時候微清和。", "落日弔山鬼，回風吹女蘿。", "石崖向西豁，引領望黃河。", "千里一飛鳥，孤光東逝波。", "驅車層城路，惆悵此巖阿。"]'),
('8563597c-df86-421a-9aa8-03e029995e2c','謁張果先生','李頎','唐','唐诗','tang','','[]','先生谷神者，甲子焉能計。',240,'全唐诗/poet.tang.6000.json','["先生谷神者，甲子焉能計。", "自說軒轅師，于今幾千歲。", "寓遊城郭裏，浪跡希夷際。", "應物雲無心，逢時舟不繫。", "餐霞斷火粒，野服兼荷製。", "白雪淨肌膚，青松養身世。", "韜精殊豹隱，鍊骨同蟬蛻。", "忽去不知誰，偶來寧有契。", "二儀齊壽考，六合隨休憩。", "彭耼猶嬰孩，松期且微細。", "嘗聞穆天子，更憶漢皇帝。", "親屈萬乘尊，將窮四海裔。", "車徒徧草木，錦帛招談說。", "八駿空往還，三山轉虧蔽。", "吾君感至德，玄老欣來詣。", "受籙金殿開，清齋玉堂閉。", "笙歌迎拜首，羽帳崇嚴衞。", "禁柳垂香鑪，宮花拂仙袂。", "祈年寶祚廣，致福蒼生惠。", "何必待龍髯，鼎成方取濟。"]'),
('26953709-a8f3-4944-863e-cb446b59e85f','光上座廊下衆山五韻','李頎','唐','唐诗','tang','','[]','名嶽在廡下，吾師居一牀。',60,'全唐诗/poet.tang.6000.json','["名嶽在廡下，吾師居一牀。", "每聞楞伽經，只對清翠光。", "百谷聚雪色，莓苔侵屋梁。", "氣盤古壁轉，勢引幽堦長。", "願遊薜葉下，日見金鑪香。"]'),
('8ab5c0f7-3552-47db-972c-966aef096c68','九月九日劉十八東堂集','李頎','唐','唐诗','tang','','[]','風俗尚九日，此情安可忘。',72,'全唐诗/poet.tang.6000.json','["風俗尚九日，此情安可忘。", "菊花辟惡酒，湯餅茱萸香。", "雲入授衣假，風吹閑宇涼。", "主人盡歡意，林景晝微茫。", "清切晚砧動，東西歸鳥行。", "淹留悵爲別，日醉秋雲光。"]'),
('9b92e0d6-89ed-4d59-b017-cea38d70ac1d','宋少府東谿泛舟','李頎','唐','唐诗','tang','','[]','登岸還入舟，水禽驚笑語。',36,'全唐诗/poet.tang.6000.json','["登岸還入舟，水禽驚笑語。", "晚葉低衆色，濕雲帶殘暑。", "落日乘醉歸，溪流復幾許。"]'),
('084dd7b8-1ae4-44c7-af74-7890a1d8b817','與諸公遊濟瀆泛舟','李頎','唐','唐诗','tang','','[]','濟水出王屋，其源來不窮。',240,'全唐诗/poet.tang.6000.json','["濟水出王屋，其源來不窮。", "洑泉數眼沸，平地流清通。", "皇帝崇祀典，詔書視三公。", "分官禱靈廟，奠璧沈河宮。", "神應每如荅，松篁氣葱蘢。", "蒼螭送飛雨，赤鯉噴迴風。", "灑酒布瑤席，吹簫下玉童。", "玄冥掌陰事，祝史告年豐。", "百谷趨潭底，三光懸鏡中。", "淺深露沙石，蘋藻生虛空。", "晚景臨汎美，亭臯輕靄紅。", "晴山傍舟楫，白鷺驚絲桐。", "我本家潁北，開門見維嵩。", "焉知松峰外，又有天壇東。", "左手正接䍦，浩歌眄青穹。", "夷猶傲清吏，偃仰狎漁翁。", "對此川上閑，非君誰與同。", "霜凝遠村渚，月靜蒹葭叢。", "茲境信難遇，爲歡殊未終。", "淹留悵言別，煙嶼夕微濛。"]'),
('913eeddf-2223-49e4-b04a-6d266420b8b4','送綦毋三謁房給事','李頎','唐','唐诗','tang','','[]','夫子大名下，家無鍾石儲。',120,'全唐诗/poet.tang.6000.json','["夫子大名下，家無鍾石儲。", "惜哉湖海上，曾校蓬萊書。", "外物非本意，此生空澹如。", "所思但乘興，遠適唯單車。", "高道時坎坷，故交願吹噓。", "徒言青瑣闥，不愛承明廬。", "百里人戶滿，片言爭訟疎。", "手持蓮花經，目送飛鳥餘。", "晚景南路別，炎雲中伏初。", "此行儻不遂，歸食蘆洲魚。"]'),
('5d1a07c5-1b42-4e2d-8e4e-bfcd0205fb5d','送劉四','李頎','唐','唐诗','tang','','[]','愛君少岐嶷，高視白雲鄉。',144,'全唐诗/poet.tang.6000.json','["愛君少岐嶷，高視白雲鄉。", "九歲能屬文，謁帝遊明光。", "奉詔赤墀下，拜爲童子郎。", "爾來屢遷易，三度尉洛陽。", "洛陽十二門，官寺鬱相望。", "青槐羅四面，淥水貫中央。", "聽訟破秋毫，應物利干將。", "辭滿如脫屣，立言無否臧。", "歲暮風雪暗，秦中川路長。", "行人飲臘酒，立馬帶晨霜。", "生事豈須問，故園寒草荒。", "從今署右職，莫笑在農桑。"]'),
('c882b85c-c30f-4170-818c-6aaca98c2c56','送裴騰','李頎','唐','唐诗','tang','','[]','養德爲衆許，森然此丈夫。',120,'全唐诗/poet.tang.6000.json','["養德爲衆許，森然此丈夫。", "放情白雲外，爽氣連虯鬚。", "衡鏡合知子，公心誰謂無。", "還令不得意，單馬遂長驅。", "桑野蠶忙時，憐君久踟躕。", "新晴荷卷葉，孟夏雉將雛。", "令弟爲縣尹，高城汾水隅。", "相將簿領閑，倚望恆峰孤。", "香露團百草，紫梨分萬株。", "歸來授衣假，莫使故園蕪。"]'),
('1d8a6b43-688d-4ba7-8086-84896e70fd46','送司農崔丞','李頎','唐','唐诗','tang','','[]','黃鸝鳴官寺，香草色未已。',120,'全唐诗/poet.tang.6000.json','["黃鸝鳴官寺，香草色未已。", "同時皆省郎，而我獨留此。", "維監太倉粟，常對府小史。", "清陰羅廣庭，政事如流水。", "奉使往長安，今承朝野歡。", "宰臣應記識，明主必遷官。", "塞外貔將虎，池中鴛與鸞。", "詞人洞簫賦，公子鵕䴊冠。", "邑里春方晚，昆明花欲闌。", "行行取高位，當使路傍看。"]'),
('33fae014-571f-48d1-87c4-9d5c95e3fd99','送崔侍御赴京','李頎','唐','唐诗','tang','','[]','綠槐蔭長路，駿馬垂青絲。',96,'全唐诗/poet.tang.6000.json','["綠槐蔭長路，駿馬垂青絲。", "柱史謁承明，翩翩將有期。", "千官大朝日，奏事臨赤墀。", "肅肅儀仗裏，風生鷹隼姿。", "一從登甲科，三拜皆憲司。", "按俗又如此，爲郎何太遲。", "送君暮春月，花落城南陲。", "惜別醉芳草，前山勞夢思。"]'),
('cce21b17-efea-42eb-8fc8-37ae7799efb7','春送從叔遊襄陽','李頎','唐','唐诗','tang','','[]','言別恨非一，棄置我宗英。',120,'全唐诗/poet.tang.6000.json','["言別恨非一，棄置我宗英。", "向用五經笥，今爲千里行。", "裹糧顧庭草，羸馬詰朝鳴。", "斗酒對寒食，雜花宜晚晴。", "春衣采洲路，夜飲南陽城。", "客夢峴山曉，漁歌江水清。", "楚俗少相知，遠遊難稱情。", "同人應館穀，刺史在郊迎。", "只合侍丹扆，翻令辭上京。", "時方春欲暮，歎息向流鶯。"]'),
('bd82a5d7-3a57-4e23-9241-de29fe14e4a6','贈別高三十五','李頎','唐','唐诗','tang','','[]','五十無產業，心輕百萬資。',170,'全唐诗/poet.tang.6000.json','["五十無產業，心輕百萬資。", "屠酤亦與羣，不問君是誰。", "飲酒或垂釣，狂歌兼詠詩。", "焉知漢高士，莫識越鴟夷。", "寄跡棲霞山，蓬頭睢水湄。", "忽然辟命下，衆謂趨丹墀。", "沐浴著賜衣，西來馬行遲。", "能令相府重，且有函關期。", "僶俛從寸祿，舊遊梁宋時。", "皤皤邑中叟，相候鬢如絲。", "官舍柳林靜，河梁杏葉滋。", "摘芳雲景[晏]，把手秋蟬悲。", "小縣情未愜，折腰君莫辭。", "吾觀主人意，不久召京師。"]'),
('fd7cd1a8-1b91-42b9-99e8-86be0d63f433','崔五宅送劉跂入京','李頎','唐','唐诗','tang','','[]','行人惜寸景，繫馬暫留歡。',120,'全唐诗/poet.tang.6000.json','["行人惜寸景，繫馬暫留歡。", "昨日辭小沛，何時到長安。", "鄉中飲酒禮，客裏行路難。", "清洛雲鴻度，故關風日寒。", "維將道可樂，不念身無官。", "生事東山遠，田園芳歲闌。", "東歸余謝病，西去子加餐。", "宋伯非徒爾，明時正可干。", "躬耕守貧賤，失計在林端。", "宿昔奉顏色，慙無雙玉盤。"]'),
('262f0dbe-9391-437d-aac3-26afc0fb0733','送馬錄事赴永陽','李頎','唐','唐诗','tang','','[]','子爲郡從事，主印清淮邊。',120,'全唐诗/poet.tang.6000.json','["子爲郡從事，主印清淮邊。", "談笑一州裏，從容羣吏先。", "手持三尺令，遣決如流泉。", "太守既相許，諸公誰不然。", "孤城連海樹，萬室帶山烟。", "春日谿湖淨，芳洲葭菼連。", "炊秔蟹螯熟，下筯鱸魚鮮。", "野鶴宿簷際，楚雲飛面前。", "聽歌送離曲，且駐木蘭船。", "贈爾八行字，當聞佳政傳。"]'),
('ea33eb99-eb29-4334-b8f4-a88622fc8c1e','臨別送張諲入蜀','李頎','唐','唐诗','tang','','[]','出門便爲客，惘然悲徒御。',120,'全唐诗/poet.tang.6000.json','["出門便爲客，惘然悲徒御。", "四海維一身，茫茫欲何去？", "經山復歷水，百恨將千慮。", "劒閣望梁州，是君斷腸處。", "孤雲傷客心，落日感君深。", "夢裏蒹葭渚，天邊橘柚林。", "蜀江流不測，蜀路險難尋。", "木有相思號，猿多愁苦音。", "莫向愚山隱，愚山地非近。", "故鄉可歸來，眼見芳菲盡。"]'),
('ddb67b2a-3bbe-4547-b7e0-01ccfa746cea','送王昌齡','李頎','唐','唐诗','tang','','[]','漕水東去遠，送君多暮情。',84,'全唐诗/poet.tang.6000.json','["漕水東去遠，送君多暮情。", "淹留野寺出，向背孤山明。", "前望數千里，中無蒲稗生。", "夕陽滿舟檝，但愛微波清。", "舉酒林月上，解衣沙鳥鳴。", "夜來蓮花界，夢裏金陵城。", "歎息此離別，悠悠江海行。"]'),
('0f58192e-1519-4c9d-a66b-278395c4869d','留別王盧二拾遺','李頎','唐','唐诗','tang','','[]','此別不可道，此心當報誰。',48,'全唐诗/poet.tang.6000.json','["此別不可道，此心當報誰。", "春風灞水上，飲馬桃花時。", "誤作好文士，只令遊宦遲。", "留書下朝客，我有故山期。"]'),
('03edf446-52b4-4ede-baeb-d5f484388a9c','贈別穆元林','李頎','唐','唐诗','tang','','[]','貳職久辭滿，藏名三十年。',120,'全唐诗/poet.tang.6000.json','["貳職久辭滿，藏名三十年。", "丹墀策頻獻，白首官不遷。", "明主日徵士，吏曹何忽賢。", "空懷濟世業，欲棹滄浪船。", "舉酒洛門外，送君春海邊。", "彼鄉有令弟，小邑試烹鮮。", "轉浦雲壑媚，涉江花島連。", "綠芳暗楚水，白鳥飛吳烟。", "贈贐亦奚貴，流亂期早旋。", "金閨會通籍，生事豈徒然。"]'),
('d6b908f8-4a90-4fc9-8ba7-cab0ca3a9525','不調歸東川別業','李頎','唐','唐诗','tang','','[]','寸祿言可取，託身將見遺。',120,'全唐诗/poet.tang.6000.json','["寸祿言可取，託身將見遺。", "慙無匹夫志，悔與名山辭。", "紱冕謝知己，林園多後時。", "葛巾方濯足，蔬食但垂帷。", "十室對河岸，漁樵祗在茲。", "青郊香杜若，白水映茅茨。", "晝景徹雲樹，夕陰澄古逵。", "渚花獨開晚，田鶴靜飛遲。", "且復樂生事，前賢爲我師。", "清歌聊鼓楫，永日望佳期。"]'),
('2a8c0c7d-a5e6-4b75-bc91-27db46d10514','晚歸東園','李頎','唐','唐诗','tang','','[]','出郭喜見山，東行亦未遠。',48,'全唐诗/poet.tang.6000.json','["出郭喜見山，東行亦未遠。", "夕陽帶歸路，靄靄秋稼晚。", "樵者乘霽歸，野夫及星飯。", "請謝朱輪客，垂竿不復返。"]'),
('030bc8a8-cd23-4ef6-892f-bd7bf9b9f574','龍門西峰曉望劉十八不至','李頎','唐','唐诗','tang','','[]','春臺臨永路，跂足望行子。',48,'全唐诗/poet.tang.6000.json','["春臺臨永路，跂足望行子。", "片片雲觸峯，離離鳥渡水。", "叢林遠山上，霽景雜花裏。", "不見攜手人，下山采綠芷。"]'),
('6aa7fd69-3fcb-4563-89bf-36b03deb963f','裴尹東溪別業','李頎','唐','唐诗','tang','','[]','公才廊廟器，官亞河南守。',120,'全唐诗/poet.tang.6000.json','["公才廊廟器，官亞河南守。", "別墅臨都門，驚湍激前後。", "舊交與羣從，十日一攜手。", "幅巾望寒山，長嘯對高柳。", "清歡信可尚，散吏亦何有。", "岸雪清城陰，水光遠林首。", "閑觀野人筏，或飲川上酒。", "幽雲澹徘徊，白鷺飛左右。", "庭竹垂臥內，村烟隔南阜。", "始知物外情，簪紱同芻狗。"]'),
('4919a496-5692-4730-9364-f49584465567','無盡上人東林禪居','李頎','唐','唐诗','tang','','[]','草堂每多暇，時謁山僧門。',120,'全唐诗/poet.tang.6000.json','["草堂每多暇，時謁山僧門。", "所對但羣木，終朝無一言。", "我心愛流水，此地臨清源。", "含吐山上日，蔽虧松外村。", "孤峯隔身世，百衲老寒暄。", "禪戶積朝雪，花龕來暮猿。", "顧余守耕稼，十載隱田園。", "蘿篠慰舂汲，巖潭恣討論。", "洩雲豈知限，至道莫探元。", "且願啓關鎖，於焉微尚存。"]'),
('e33894c8-b607-4ee3-a08b-94ce8e159a47','題綦毋校書別業','李頎','唐','唐诗','tang','','[]','常稱挂冠吏，昨日歸滄洲。',96,'全唐诗/poet.tang.6000.json','["常稱挂冠吏，昨日歸滄洲。", "行客暮帆遠，主人庭樹秋。", "豈伊問天命，但欲爲山遊。", "萬物我何有，白雲空自幽。", "蕭條江海上，日夕見丹丘。", "生事非漁釣，賞心隨去留。", "惜哉曠微月，欲濟無輕舟。", "倏忽令人老，相思河水流。"]'),
('54dd54ea-8d4b-4872-9990-51bee11135e1','題盧道士房','李頎','唐','唐诗','tang','','[]','秋砧響落木，共坐茅君家。',74,'全唐诗/poet.tang.6000.json','["秋砧響落木，共坐茅君家。", "惟見兩童子，林前汲井華。", "空壇靜白日，神鼎飛丹砂。", "麈尾拂霜草，金鈴搖霽霞。", "上章人世隔，看[弈]桐陰斜。", "稽首問仙要，黃精堪餌花。"]'),
('d69db332-54ab-4736-b29a-2aa858ba5666','題神力師院','李頎','唐','唐诗','tang','','[]','大師神傑貌，五嶽森禪房。',72,'全唐诗/poet.tang.6000.json','["大師神傑貌，五嶽森禪房。", "堅持日月珠，豁見滄江長。", "隨病拔諸苦，致身如法王。", "階庭藥草徧，飯食天花香。", "樹色向高閣，晝陰橫半牆。", "每聞第一義，心淨琉璃光。"]'),
('9291dfae-21bb-44af-aac4-d3c3021b3679','題僧房雙桐','李頎','唐','唐诗','tang','','[]','青桐雙拂日，傍帶凌霄花。',36,'全唐诗/poet.tang.6000.json','["青桐雙拂日，傍帶凌霄花。", "綠葉傳僧磬，清陰潤井華。", "誰能事音律，焦尾蔡邕家。"]'),
('bce4276d-3417-4536-8561-c80315567bf1','粲公院各賦一物得初荷','李頎','唐','唐诗','tang','','[]','微風和衆草，大葉長圓陰。',36,'全唐诗/poet.tang.6000.json','["微風和衆草，大葉長圓陰。", "晴露珠共合，夕陽花映深。", "從來不著水，清淨本因心。"]'),
('a2b1ed12-6ad1-482d-ae96-618d70c82f19','李兵曹壁畫山水各賦得桂水帆','李頎','唐','唐诗','tang','','[]','片帆浮桂水，落日天涯時。',36,'全唐诗/poet.tang.6000.json','["片帆浮桂水，落日天涯時。", "飛鳥看共度，閑雲相與遲。", "長波無曉夜，泛泛欲何之。"]'),
('dee01ede-afc6-440b-841a-3cd8c26a33f6','題合歡','李頎','唐','唐诗','tang','','[]','開花復卷葉，豔眼又驚心。',36,'全唐诗/poet.tang.6000.json','["開花復卷葉，豔眼又驚心。", "蝶遶西枝露，風披東幹陰。", "黃衫漂細蘂，時拂女郎砧。"]'),
('bea6f283-8f90-49b5-8842-1cb906816548','古從軍行','李頎','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u751f\u6d3b", "\u51ac\u5929", "\u4e50\u5e9c", "\u8fb9\u585e", "\u76f8\u548c\u6b4c\u8f9e"]','白日登山望烽火，黃昏飲馬傍交河。',96,'全唐诗/poet.tang.6000.json','["白日登山望烽火，黃昏飲馬傍交河。", "行人刁斗風沙暗，公主琵琶幽怨多。", "野雲萬里無城郭，雨雪紛紛連大漠。", "胡鴈哀鳴夜夜飛，胡兒眼淚雙雙落。", "聞道玉門猶被遮，應將性命逐輕車。", "年年戰骨埋荒外，空見蒲桃入漢家。"]'),
('fd7beda9-a386-4117-bb7f-c1f6df62dd16','行路難','李頎','唐','唐诗','tang','','[]','漢家名臣楊德祖，四代五公享茅土。',160,'全唐诗/poet.tang.6000.json','["漢家名臣楊德祖，四代五公享茅土。", "父子兄弟綰銀黃，躍馬鳴珂朝建章。", "火浣單衣繡方領，茱萸錦帶玉盤囊。", "賓客填街復滿座，片言出口生輝光。", "世人逐勢爭奔走，瀝膽墮肝惟恐後。", "當時一顧登青雲，自謂生死長隨君。", "一朝謝病還鄉里，窮巷蒼苔絕知己。", "秋風落葉閉重門，昨日論交竟誰是。", "薄俗嗟嗟難重陳，深山麋鹿可爲鄰。", "魯連所以蹈東海，古往今來稱達人。"]'),
('eb91e314-0451-46a4-b1ec-9fbde0987d8d','緩歌行','李頎','唐','唐诗','tang','','[]','小來託身攀貴遊，傾財破產無所憂。',160,'全唐诗/poet.tang.6000.json','["小來託身攀貴遊，傾財破產無所憂。", "暮擬經過石渠署，朝將出入銅龍樓。", "結交杜陵輕薄子，謂言可生復可死。", "一沈一浮會有時，棄我翻然如脫屣。", "男兒立身須自強，十年閉戶潁水陽。", "業就功成見明主，擊鐘鼎食坐華堂。", "二八蛾眉梳墮馬，美酒清歌曲房下。", "文昌宮中賜錦衣，長安陌上退朝歸。", "五陵賓從莫敢視，三省官僚揖者稀。", "早知今日讀書是，悔作從前任俠非。"]'),
('7d906794-b4d1-4922-9c59-eee5b19602ad','琴歌','李頎','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u97f3\u4e50", "\u5bb4\u4f1a", "\u4e03\u8a00\u53e4\u8bd7"]','主人有酒歡今夕，請奏鳴琴廣陵客。',80,'全唐诗/poet.tang.6000.json','["主人有酒歡今夕，請奏鳴琴廣陵客。", "月照城頭烏半飛，霜淒萬樹風入衣。", "銅鑪華燭燭增輝，初彈淥水後楚妃。", "一聲已動物皆靜，四座無言星欲稀。", "清淮奉使千餘里，敢告雲山從此始。"]'),
('5d85a4dd-bcfd-4a2b-9752-679fe76c46c6','放歌行荅從弟墨卿','李頎','唐','唐诗','tang','','["\u957f\u6c5f"]','小來好文恥學武，世上功名不解取。',192,'全唐诗/poet.tang.6000.json','["小來好文恥學武，世上功名不解取。", "雖沾寸祿已後時，徒欲出身事明主。", "柏梁賦詩不及宴，長楸走馬誰相數。", "歛迹俛眉心自甘，高歌擊節聲半苦。", "由是蹉跎一老夫，養雞牧豕東城隅。", "空歌漢代蕭相國，肯事霍家馮子都。", "徒爾當年聲籍籍，濫作詞林兩京客。", "故人斗酒安陵橋，黃鳥春風洛陽陌。", "吾家令弟才不羈，五言破的人共推。", "興來逸氣若濤湧，千里長江歸海時。", "別離短景何蕭索，佳句相思能間作。", "舉頭遙望魯陽山，木葉紛紛向人落。"]'),
('db5c92b9-ba8c-4ffd-be09-b31293cdca71','王母歌','李頎','唐','唐诗','tang','','[]','武皇齋戒承華殿，端拱須臾王母見。',176,'全唐诗/poet.tang.6000.json','["武皇齋戒承華殿，端拱須臾王母見。", "霓旌照耀麒麟車，羽蓋淋漓孔雀扇。", "手指交梨遣帝食，可以長生臨宇縣。", "頭上復戴九星冠，總領玉童坐南面。", "欲聞要言今告汝，帝乃焚香請此語。", "若能鍊魄去三尸，後當見我天皇所。", "顧謂侍女董雙成，酒闌可奏雲和笙。", "紅霞白日儼不動，七龍五鳳紛相迎。", "惜哉志驕神不悅，歎息馬蹄與車轍。", "複道歌鐘杳將暮，深宮桃李花成雪。", "爲看青玉五枝燈，蟠螭吐火光欲絕。"]'),
('e464d1b5-c5cf-4d9f-9c0c-98e0c914638a','鮫人歌','李頎','唐','唐诗','tang','','[]','鮫人潛織水底居，側身上下隨遊魚。',96,'全唐诗/poet.tang.6000.json','["鮫人潛織水底居，側身上下隨遊魚。", "輕綃文綵不可識，夜夜澄波連月色。", "有時寄宿來城市，海島青冥無極已。", "泣珠報恩君莫辭，今年相見明年期。", "始知萬族無不有，百尺深泉架戶牖。", "鳥沒空山誰復望，一望雲濤堪白首。"]'),
('fbba1d53-59a3-437f-946d-fdf3a5e846d5','夏宴張兵曹東堂','李頎','唐','唐诗','tang','','[]','重林華屋堪避暑，況乃烹鮮會佳客。',96,'全唐诗/poet.tang.6000.json','["重林華屋堪避暑，況乃烹鮮會佳客。", "主人三十朝大夫，滿座森然見矛戟。", "北窓臥簟連心花，竹裏蟬鳴西日斜。", "羽扇搖風却珠汗，玉盆貯水割甘瓜。", "雲峰峨峨自冰雪，坐對芳樽不知熱。", "醉來但挂葛巾眠，莫道明朝有離別。"]'),
('b6935798-aee3-4f7c-896e-916a1f15357d','同張員外諲詶荅之作','李頎','唐','唐诗','tang','','[]','洛中高士日沈冥，手自灌園方帶經。',98,'全唐诗/poet.tang.6000.json','["洛中高士日沈冥，手自灌園方帶經。", "王湛牀頭見周易，長康傳裏好丹青。", "鶡冠葛屨無名位，博[弈]賦詩聊遣意。", "清言只到衞家兒，用筆能誇鍾太尉。", "東籬二月種蘭蓀，窮巷人稀鳥雀喧。", "聞道郎官問生事，肯令鬢髮老柴門。"]'),
('74d2df66-8cd6-4b4e-9a07-cafda38b5182','欲之新鄉荅崔顥綦毋潛','李頎','唐','唐诗','tang','','[]','數年作吏家屢空，誰道黑頭成老翁。',128,'全唐诗/poet.tang.6000.json','["數年作吏家屢空，誰道黑頭成老翁。", "男兒在世無產業，行子出門如轉蓬。", "吾屬交歡此何夕，南家擣衣動歸客。", "銅鑪將炙相歡飲，星宿縱橫露華白。", "寒風卷葉度滹沱，飛雪布地悲峨峨。", "孤城日落見棲鳥，馬上時聞漁者歌。", "明朝東路把君手，臘日辭君期歲首。", "自知寂寞無去思，敢望縣人致牛酒。"]'),
('7501fdb6-d229-4121-8914-1002ed2d50cb','荅高三十五留別便呈于十一','李頎','唐','唐诗','tang','','[]','累薦賢良皆不就，家近陳留訪耆舊。',160,'全唐诗/poet.tang.6000.json','["累薦賢良皆不就，家近陳留訪耆舊。", "韓康雖復在人間，王霸終思隱巖竇。", "清冷池水灌園蔬，萬物滄江心澹如。", "妻子歡同五株柳，雲山老對一牀書。", "昨日公車見三事，明君賜衣遣爲吏。", "懷章不使郡邸驚，待詔初從闕庭至。", "散誕由來自不羈，低頭授職爾何爲。", "故園壁挂烏紗帽，官舍塵生白接䍦。", "寄書寂寂於陵子，蓬蒿沒身胡不仕。", "藜羹被褐環堵中，歲晚將貽故人恥。"]'),
('afdb6bb1-f626-4f2c-9ee7-b367f304cbeb','送康洽入京進樂府歌','李頎','唐','唐诗','tang','','[]','識子十年何不遇，只愛歡遊兩京路。',128,'全唐诗/poet.tang.6000.json','["識子十年何不遇，只愛歡遊兩京路。", "朝吟左氏嬌女篇，夜誦相如美人賦。", "長安春物舊相宜，小苑蒲萄花滿枝。", "柳色偏濃九華殿，鶯聲醉殺五陵兒。", "曳裾此日從何所，中貴由來盡相許。", "白裌春衫仙吏贈，烏皮隱几臺郎與。", "新詩樂府唱堪愁，御妓應傳鳷鵲樓。", "西上雖因長公主，終須一見曲陵侯。"]'),
('11847814-ef85-40fa-971c-1dfb87957696','送劉十','李頎','唐','唐诗','tang','','[]','三十不官亦不娶，時人焉識道高下。',128,'全唐诗/poet.tang.6000.json','["三十不官亦不娶，時人焉識道高下。", "房中唯有老氏經，櫪上空餘少遊馬。", "往來嵩華與函秦，放歌一曲前山春。", "西林獨鶴引閑步，南澗飛泉清角巾。", "前年上書不得意，歸臥東窓兀然醉。", "諸兄相繼掌青史，第五之名齊驃騎。", "烹葵摘果告我行，落日夏雲縱復橫。", "聞道謝安掩口笑，知君不免爲蒼生。"]'),
('b7f92ab3-747f-4a3e-a4c2-3c228fecd9f6','送王道士還山','李頎','唐','唐诗','tang','','[]','嵩陽道士餐柏實，居處三花對石室。',160,'全唐诗/poet.tang.6000.json','["嵩陽道士餐柏實，居處三花對石室。", "心窮伏火陽精丹，口誦淮王萬畢術。", "自言神訣不可求，我師聞之玄圃遊。", "出入彤庭佩金印，承恩赫赫如王侯。", "雙峰樹下曾受業，應傳肘後長生法。", "吾聞仙地多後身，安知不是具茨人。", "玉膏清泠瀑泉水，白雲谿中日方此。", "後今不見數十年，鬢髮顏容只如是。", "先生捨我欲何歸，竹杖黃裳登翠微。", "當有巖前白蝙蝠，迎君日暮雙來飛。"]'),
('109f25f7-3fa6-4290-ae88-1f5b88f7af81','別梁鍠','李頎','唐','唐诗','tang','','[]','梁生倜儻心不羈，途窮氣蓋長安兒。',240,'全唐诗/poet.tang.6000.json','["梁生倜儻心不羈，途窮氣蓋長安兒。", "回頭轉眄似鵰鶚，有志飛鳴人豈知。", "雖云四十無祿位，曾與大軍掌書記。", "抗辭請刃誅部曲，作色論兵犯二帥。", "一言不合龍頟侯，擊劒拂衣從此棄。", "朝朝飲酒黃公壚，脫帽露頂爭叫呼。", "庭中犢鼻昔嘗挂，懷裏琅玕今在無。", "時人見子多落魄，共笑狂歌非遠圖。", "忽然遣躍紫騮馬，還是昂藏一丈夫。", "洛陽城頭曉霜白，層冰峨峨滿川澤。", "但聞行路吟新詩，不歎舉家無擔石。", "莫言貧賤長可欺，覆簣成山當有時。", "莫言富歸長可託，木槿朝看暮還落。", "不見古時塞上翁，倚伏由來任天作。", "去去滄波勿復陳，五湖三江愁殺人。"]'),
('5c200457-70f8-485e-9538-0051ec211079','送從弟遊江淮兼謁鄱陽劉太守','李頎','唐','唐诗','tang','','[]','都門柳色朝朝新，念爾今爲江上人。',96,'全唐诗/poet.tang.6000.json','["都門柳色朝朝新，念爾今爲江上人。", "穆陵關帶清風遠，彭蠡湖連芳草春。", "泊舟借問西林寺，曉聽猿聲在山翠。", "潯陽北望鴻鴈回，湓水東流客心醉。", "須知聖代舉賢良，不使遺才滯一方。", "應見鄱陽虎符守，思歸共指白雲鄉。"]'),
('d39d3ffe-b532-4962-8b21-c570e0f54093','雙笋歌送李回兼呈劉四','李頎','唐','唐诗','tang','','[]','並抽新笋色漸綠，迥出空林雙碧玉。',64,'全唐诗/poet.tang.6000.json','["並抽新笋色漸綠，迥出空林雙碧玉。", "春風解籜雨潤根，一枝半葉清露痕。", "爲君當面拂雲日，孤生四遠何足論。", "再三抱此悵爲別，嵩洛故人與之說。"]'),
('d9a38c34-7eb7-46d6-af26-da6f6f68bdf2','送劉四赴夏縣','李頎','唐','唐诗','tang','','["\u5e90\u5c71"]','九霄特立紅鸞姿，萬仞孤生玉樹枝。',256,'全唐诗/poet.tang.6000.json','["九霄特立紅鸞姿，萬仞孤生玉樹枝。", "劉侯致身能若此，天骨自然多歎美。", "聲名播揚二十年，足下長途幾千里。", "舉世皆親丞相閣，我心獨愛伊川水。", "脫略勢利猶埃塵，嘯傲時人而已矣。", "新詩數歲即文雄，上書昔召蓬萊宮。", "明主拜官麒麟閣，光車駿馬看玉童。", "高人往來廬山遠，隱士往來張長公。", "扶南甘蔗甜如蜜，雜以荔枝龍州橘。", "赤縣繁詞滿劇曹，白雲孤峯暉永日。", "朝持手板望飛鳥，暮誦楞伽對空室。", "一朝出宰汾河間，明府下車人吏閑。", "端坐訟庭更無事，開門咫尺巫咸山。", "男耕女織蒙惠化，麥熟雉鳴長秋稼。", "明年九府議功時，五辟三徵當在茲。", "聞道桐鄉有遺老，邑中還欲置生祠。"]'),
('0a40b584-7596-446c-8d15-e9a7b840d612','少室雪晴送王寧','李頎','唐','唐诗','tang','','["\u79bb\u522b", "\u7559\u604b", "\u5199\u666f"]','少室衆峯幾峰別，一峰晴見一峰雪。',80,'全唐诗/poet.tang.6000.json','["少室衆峯幾峰別，一峰晴見一峰雪。", "隔城半山連青松，素色峨峨千萬重。", "過景斜臨不可道，白雲欲盡難爲容。", "行人與我翫幽境，北風切切吹衣冷。", "惜別浮橋駐馬時，舉頭試望南山嶺。"]'),
('9e6cbc1b-95ed-406b-8c9d-d05876a1342c','送陳章甫','李頎','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9001\u522b", "\u4e03\u8a00\u53e4\u8bd7"]','四月南風大麥黃，棗花未落桐陰長。',144,'全唐诗/poet.tang.6000.json','["四月南風大麥黃，棗花未落桐陰長。", "青山朝別暮還見，嘶馬出門思舊鄉。", "陳侯立身何坦蕩，虬鬚虎眉仍大顙。", "腹中貯書一萬卷，不肯低頭在草莽。", "東門酤酒飲我曹，心輕萬事皆鴻毛。", "醉臥不知白日暮，有時空望孤雲高。", "長河浪頭連天黑，津口停舟渡不得。", "鄭國遊人未及家，洛陽行子空歎息。", "聞道故林相識多，罷官昨日今如何。"]'),
('2d66a9e4-7b4d-4be4-91fd-6a4b2cd8817b','聽安萬善吹觱篥歌','李頎','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u97f3\u4e50", "\u4e03\u8a00\u53e4\u8bd7"]','南山截竹爲觱篥，此樂本自龜茲出。',144,'全唐诗/poet.tang.6000.json','["南山截竹爲觱篥，此樂本自龜茲出。", "流傳漢地曲轉奇，涼州胡人爲我吹。", "傍鄰聞者多歎息，遠客思鄉皆淚垂。", "世人解聽不解賞，長飆風中自來往。", "枯桑老柏寒颼飀，九雛鳴鳳亂啾啾。", "龍吟虎嘯一時發，萬籟百泉相與秋。", "忽然更作漁陽摻，黃雲蕭條白日暗。", "變調如聞楊柳春，上林繁花照眼新。", "歲夜高堂列明燭，美酒一杯聲一曲。"]'),
('de5aad73-75e5-4e19-be62-d52ac7ec7402','魏倉曹東堂檉樹','李頎','唐','唐诗','tang','','[]','愛君雙檉一樹奇，千葉齊生萬葉垂。',64,'全唐诗/poet.tang.6000.json','["愛君雙檉一樹奇，千葉齊生萬葉垂。", "長頭拂石帶烟雨，獨立空山人莫知。", "攢青蓄翠陰滿屋，紫穗紅英曾斷目。", "洛陽墨客遊雲間，若到麻源第三谷。"]'),
('662bf0af-9040-4780-aa07-7fde14e32096','照公院雙橙','李頎','唐','唐诗','tang','','[]','種橙夾階生得地，細葉隔簾見雙翠。',64,'全唐诗/poet.tang.6000.json','["種橙夾階生得地，細葉隔簾見雙翠。", "抽條向長未及肩，泉水遶根日三四。", "青青何必楚人家，帶雨凝烟新著花。", "永願香爐灑甘露，夕陽時映東枝斜。"]'),
('c6610895-5ff8-425a-b5fd-705b349d221a','愛敬寺古藤歌','李頎','唐','唐诗','tang','','[]','古藤池水盤樹根，左攫右拏龍虎蹲。',96,'全唐诗/poet.tang.6000.json','["古藤池水盤樹根，左攫右拏龍虎蹲。", "橫空直上相陵突，丰茸離纚若無骨。", "風雷霹靂連黑枝，人言其下藏妖魑。", "空庭落葉乍開合，十月苦寒常倒垂。", "憶昨花飛滿空殿，密葉吹香飯僧遍。", "南階雙桐一百尺，相與年年老霜霰。"]'),
('0e86ad7b-5212-45a0-b64e-5b48f36c289a','崔五六圖屏風各賦一物得烏孫佩刀','李頎','唐','唐诗','tang','','[]','烏孫腰間佩兩刀，刃可吹毛錦爲帶。',96,'全唐诗/poet.tang.6000.json','["烏孫腰間佩兩刀，刃可吹毛錦爲帶。", "握手枕宿穹廬室，馬上割飛翳螉塞。", "執之魍魎誰能前，氣凜清風沙漠邊。", "磨用陰山一片玉，洗將胡地獨流泉。", "主人屏風寫奇狀，鐵鞘金鐶儼相向。", "回頭瞪目時一看，使予心在江湖上。"]'),
('f1496cf4-4f85-4f9e-9e0e-dd05370641d3','古意','李頎','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6218\u4e89", "\u8c6a\u4fa0", "\u62df\u53e4", "\u620d\u8fb9", "\u4e03\u8a00\u53e4\u8bd7"]','男兒事長征，少小幽燕客。',84,'全唐诗/poet.tang.6000.json','["男兒事長征，少小幽燕客。", "賭勝馬蹄下，由來輕七尺。", "殺人莫敢前，鬚如蝟毛磔。", "黃雲隴底白雪飛，未得報恩不能歸。", "遼東小婦年十五，慣彈琵琶解歌舞。", "今爲羗笛出塞聲，使我三軍淚如雨。"]'),
('68a02d7f-453d-42bf-bf41-af9aa64556bd','采蓮','李頎','唐','唐诗','tang','','[]','越溪女，越溪蓮，齊菡萏，雙嬋娟。',76,'全唐诗/poet.tang.6000.json','["越溪女，越溪蓮，齊菡萏，雙嬋娟。", "嬉遊向何處，采摘且同船。", "浩唱發容與，清波生漪漣。", "時逢島嶼泊，幾伴鴦鴛眠。", "襟袖既盈溢，馨香亦相傳。", "薄暮歸去來，苧羅生碧烟。"]'),
('adba4578-a5cc-4829-b247-3e48f04159e9','雜興','李頎','唐','唐诗','tang','','[]','沈沈牛渚磯，舊說多靈怪。',156,'全唐诗/poet.tang.6000.json','["沈沈牛渚磯，舊說多靈怪。", "行人夜秉生犀燭，洞照洪深闢滂湃。", "乘車駕馬往復旋，赤紱朱冠何偉然。", "波驚海若潛幽石，龍抱胡髯臥黑泉。", "水濱丈人曾有語，物或惡之當害汝。", "武昌妖夢果爲災，百代英威埋鬼府。", "青青蘭艾本殊香，察見泉魚固不祥。", "濟水自清河自濁，周公大聖接輿狂。", "千年魑魅逢華表，九日茱萸作佩囊。", "善惡死生齊一貫，祗應斗酒任蒼蒼。"]'),
('bbbb2d00-acd3-4d89-86cb-02ed1db5c10e','絕纓歌','李頎','唐','唐诗','tang','','[]','楚王宴客章華臺，章華美人善歌舞。',96,'全唐诗/poet.tang.6000.json','["楚王宴客章華臺，章華美人善歌舞。", "玉顏豔豔空相向，滿堂目成不得語。", "紅燭滅，芳酒闌，羅衣半醉春夜寒。", "絕纓解帶一爲歡，君王赦過不之罪。", "暗中珠翠鳴珊珊，寧愛賢，不愛色。", "青娥買死誰能識，果却一軍全社稷。"]'),
('24242e3c-c8d7-48b9-8d63-84a799d97cf8','鄭櫻桃歌','李頎','唐','唐诗','tang','','[]','石季龍，僭天祿，擅雄豪，美人姓鄭名櫻桃。',180,'全唐诗/poet.tang.6000.json','["石季龍，僭天祿，擅雄豪，美人姓鄭名櫻桃。", "櫻桃美顏香且澤，娥娥侍寢專宮掖。", "後庭卷衣三萬人，翠眉清鏡不得親。", "宮軍女騎一千匹，繁花照耀漳河春。", "織成花映紅綸巾，紅旗掣曳鹵簿新。", "鳴鼙走馬接飛鳥，銅馱瑟瑟隨去塵。", "鳳陽重門如意館，百尺金梯倚銀漢。", "自言富貴不可量，女爲公主男爲王。", "赤花雙簟珊瑚牀，盤龍斗帳琥珀光。", "淫昏僞位神所惡，滅石者陵終不悟。", "鄴城蒼蒼白露微，世事翻覆黃雲飛。"]'),
('7592779c-b7f4-4ae1-b4b0-c2f7e889c241','送劉昱','李頎','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u666f"]','八月寒葦花，秋江浪頭白。',56,'全唐诗/poet.tang.6000.json','["八月寒葦花，秋江浪頭白。", "北風吹五兩，誰是潯陽客。", "鸕鷀山頭微雨晴，揚州郭裏暮潮生。", "行人夜宿金陵渚，試聽沙邊有鴈聲。"]'),
('710b3902-dd99-4e13-9a11-21eee9e603c9','送郝判官','李頎','唐','唐诗','tang','','[]','楚城木葉落，夏口青山遍。',80,'全唐诗/poet.tang.6000.json','["楚城木葉落，夏口青山遍。", "鴻鴈向南時，君乘使者傳。", "楓林帶水驛，夜火明山縣。", "千里送行人，蔡州如眼見。", "江連清漢東逶迤，遙望荆雲相蔽虧。", "應問襄陽舊風俗，爲余騎馬習家池。"]'),
('7df35400-246a-42e6-b37b-3c9cda55a016','送劉方平','李頎','唐','唐诗','tang','','[]','綺紈遊上國，多作少年行。',128,'全唐诗/poet.tang.6000.json','["綺紈遊上國，多作少年行。", "二十二詞賦，惟君著美名。", "童顏且白皙，佩德如瑤瓊。", "荀氏風流盛，胡家公子清。", "有才不偶誰之過，肯即藏鋒事高臥。", "洛陽草色猶自春，遊子東歸喜拜親。", "漳水橋頭值鳴鴈，朝歌縣北少行人。", "別離斗酒心相許，落日青郊半微雨。", "請君騎馬望西陵，爲我殷勤弔魏武。"]'),
('361a3e5e-ef71-4749-b39a-aa2f5d9180e4','聽董大彈胡笳聲兼寄語弄房給事','李頎','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u957f\u8bd7", "\u4e03\u8a00\u53e4\u8bd7", "\u6292\u60c5", "\u53e4\u4f53"]','蔡女昔造胡笳聲，一彈一十有八拍。',220,'全唐诗/poet.tang.6000.json','["蔡女昔造胡笳聲，一彈一十有八拍。", "胡人落淚沾邊草，漢使斷腸對歸客。", "古戍蒼蒼烽火寒，大荒沈沈飛雪白。", "先拂商弦後角羽，四郊秋葉驚摵摵。", "董夫子，通神明，深山竊聽來妖精。", "言遲更速皆應手，將往復旋如有情。", "空山百鳥散還合，萬里浮雲陰且晴。", "嘶酸雛鴈失羣夜，斷絕胡兒戀母聲。", "川爲淨其波，鳥亦罷其鳴。", "烏孫部落家鄉遠，邏娑沙塵哀怨生。", "幽音變調忽飄灑，長風吹林雨墮瓦。", "迸泉颯颯飛木末，野鹿呦呦走堂下。", "長安城連東掖垣，鳳凰池對青瑣門。", "高才脫略名與利，日夕望君抱琴至。"]'),
('c3bcafdf-092e-4744-83c4-b73f789f483c','彈棋歌','李頎','唐','唐诗','tang','','[]','崔侯善彈棋，巧妙盡於此。',108,'全唐诗/poet.tang.6000.json','["崔侯善彈棋，巧妙盡於此。", "藍田美玉清如砥，白黑相分十二子。", "聯翩百中皆造微，魏文手巾不足比。", "緣邊度隴未可嘉，鳥跂星懸危復斜。", "迴飆轉指速飛電，拂四取五旋風花。", "坐中齊聲稱絕藝，仙人六博何能繼。", "一別常山道路遙，爲余更作三五勢。"]'),
('4a064a36-c5a2-424e-bb2f-e87d41a288a7','送山陰姚丞攜妓之任兼寄蘇少府','李頎','唐','唐诗','tang','','[]','東風香草路，南客心容與。',144,'全唐诗/poet.tang.6000.json','["東風香草路，南客心容與。", "白皙吳王孫，青蛾柳家女。", "都門數騎出，河口片帆舉。", "夜簟眠橘洲，春衫傍楓嶼。", "山陰政簡甚從容，到罷惟求物外蹤。", "落日花邊剡溪水，晴烟竹裏會稽峰。", "才子風流蘇伯玉，同官曉暮應相逐。", "加飡共愛鱸魚肥，醒酒仍憐甘蔗熟。", "知君練思本清新，季子如今得爲鄰。", "他日知尋始寧墅，題詩早晚寄西人。"]'),
('5bca0b77-e9bb-4581-8f83-358b77803d74','塞下曲','李頎','唐','唐诗','tang','','[]','少年學騎射，勇冠幷州兒。',48,'全唐诗/poet.tang.6000.json','["少年學騎射，勇冠幷州兒。", "直愛出身早，邊功沙漠垂。", "戎鞭腰下插，羌笛雪中吹。", "膂力今應盡，將軍猶未知。"]'),
('096b0d3e-2863-4d0a-b806-a0a470272729','寄鏡湖朱處士','李頎','唐','唐诗','tang','','[]','澄霽晚流闊，微風吹綠蘋。',48,'全唐诗/poet.tang.6000.json','["澄霽晚流闊，微風吹綠蘋。", "鱗鱗遠峰見，淡淡平湖春。", "芳草日堪把，白雲心所親。", "何時可爲樂，夢裏東山人。"]'),
('133c0ca6-642a-4645-aa1f-a8b2485f1e19','宴陳十六樓','李頎','唐','唐诗','tang','','[]','西樓對金谷，此地古人心。',48,'全唐诗/poet.tang.6000.json','["西樓對金谷，此地古人心。", "白日落庭內，黃花生澗陰。", "四鄰見疎木，萬井度寒砧。", "石上題詩處，千年留至今。"]'),
('dd04484b-5baa-452a-a264-47c84b478e13','送相里造入京','李頎','唐','唐诗','tang','','[]','子月過秦正，寒雲覆洛城。',48,'全唐诗/poet.tang.6000.json','["子月過秦正，寒雲覆洛城。", "嗟君未得志，猶作苦辛行。", "煖酒嫌衣薄，瞻風候雨晴。", "春官含笑待，驅馬速前程。"]'),
('9279e4f0-0561-4caa-9ee7-2966862b7659','送錢子入京','李頎','唐','唐诗','tang','','[]','夜夢還京北，鄉心恨擣衣。',48,'全唐诗/poet.tang.6000.json','["夜夢還京北，鄉心恨擣衣。", "朝逢入秦使，走馬喚君歸。", "驛路清霜下，關門黃葉稀。", "還家應信宿，看子速如飛。"]'),
('6f73328c-e408-4037-93b0-f170f89a5afc','送綦毋三寺中賦得紗燈','李頎','唐','唐诗','tang','','[]','禪室吐香燼，輕紗籠翠烟。',48,'全唐诗/poet.tang.6000.json','["禪室吐香燼，輕紗籠翠烟。", "長繩挂青竹，百尺垂紅蓮。", "熠爚衆星下，玲瓏雙塔前。", "含光待明發，此別豈徒然。"]'),
('6b7964f3-4f04-469f-a8f2-539298fbe2c2','送人尉閩中','李頎','唐','唐诗','tang','','[]','可歎芳菲日，分爲萬里情。',48,'全唐诗/poet.tang.6000.json','["可歎芳菲日，分爲萬里情。", "閶門折垂柳，御苑聽殘鶯。", "海戍通閩邑，江航過楚城。", "客心君莫問，春草是王程。"]'),
('9e961071-11e8-4e8d-a11d-e7ce4213239d','送人歸沔南','李頎','唐','唐诗','tang','','[]','梅花今正發，失路復何如。',48,'全唐诗/poet.tang.6000.json','["梅花今正發，失路復何如。", "舊國雲山在，新年風景餘。", "春饒漢陽夢，日寄武陵書。", "可即明時老，臨川莫羨魚。"]'),
('14db03d3-7e86-4e56-bbda-9ea681cd5ae8','送盧逸人','李頎','唐','唐诗','tang','','[]','洛陽爲此別，攜手更何時。',48,'全唐诗/poet.tang.6000.json','["洛陽爲此別，攜手更何時。", "不復人間見，祗應海上期。", "清谿入雲木，白首臥茅茨。", "共惜盧敖去，天邊望所思。"]'),
('c584e126-947e-44b3-9d0b-1ea3cb8913e9','送顧朝陽還吳','李頎','唐','唐诗','tang','','[]','寂寞俱不偶，裹糧空入秦。',48,'全唐诗/poet.tang.6000.json','["寂寞俱不偶，裹糧空入秦。", "宦途已可識，歸臥包山春。", "舊國指飛鳥，滄波愁旅人。", "開樽洛水上，怨別柳花新。"]'),
('0700bf45-2199-428a-9da7-0df637195f8a','送竇參軍','李頎','唐','唐诗','tang','','[]','城南送歸客，舉酒對林巒。',48,'全唐诗/poet.tang.6000.json','["城南送歸客，舉酒對林巒。", "暄鳥迎風囀，春衣度雨寒。", "桃花開翠幕，柳色拂金鞍。", "公子何時至，無令芳草闌。"]'),
('0fa51383-e58c-4252-b000-ae3614667694','望秦川','李頎','唐','唐诗','tang','','[]','秦川朝望迥，日出正東峰。',48,'全唐诗/poet.tang.6000.json','["秦川朝望迥，日出正東峰。", "遠近山河淨，逶迤城闕重。", "秋聲萬戶竹，寒色五陵松。", "客有歸歟歎，悽其霜露濃。"]'),
('0256b0a6-d8f1-4b23-9c84-461e2c99c9c5','晚歸東園','李頎','唐','唐诗','tang','','[]','荆扉帶郊郭，稼穡滿東葘。',48,'全唐诗/poet.tang.6000.json','["荆扉帶郊郭，稼穡滿東葘。", "倚杖寒山暮，鳴梭秋葉時。", "回雲覆陰谷，返景照霜梨。", "澹泊真吾事，清風別自茲。"]'),
('dbe51772-97af-4374-b728-97e70eec3652','覺公院施鳥石臺','李頎','唐','唐诗','tang','','[]','石臺置香飯，齋後施諸禽。',48,'全唐诗/poet.tang.6000.json','["石臺置香飯，齋後施諸禽。", "童子亦知善，衆生無懼心。", "苔痕蒼曉露，盤勢出香林。", "錫杖或圍繞，吾師一念深。"]'),
('93fc27c7-af33-4fde-8984-286d0547b585','籬筍','李頎','唐','唐诗','tang','','[]','東園長新笋，映日復穿籬。',48,'全唐诗/poet.tang.6000.json','["東園長新笋，映日復穿籬。", "迸出依青嶂，攢生半綠池。", "色因林向背，行逐地高卑。", "但恐春將老，青青獨爾爲。"]'),
('531d1278-2f48-45e6-9114-82c14612d5bc','達奚吏部夫人寇氏挽歌','李頎','唐','唐诗','tang','','[]','存歿令名傳，青青松柏田。',48,'全唐诗/poet.tang.6000.json','["存歿令名傳，青青松柏田。", "事姑稱孝婦，生子繼先賢。", "露濕銘旌重，風吹鹵簿前。", "陰堂從此閉，誰誦女師篇。"]'),
('bf71d2e0-f802-4aef-8997-a0ca554aeea1','寄司勳盧員外','李頎','唐','唐诗','tang','','[]','流澌臘月下河陽，草色新年發建章。',64,'全唐诗/poet.tang.6000.json','["流澌臘月下河陽，草色新年發建章。", "秦地立春傳太史，漢宮題柱憶仙郎。", "歸鴻欲度千門雪，侍女新添五夜香。", "早晚薦雄文似者，故人今已賦長楊。"]'),
('818f2c7f-86ff-4cd3-bff2-eba44cfc45fb','寄綦毋三','李頎','唐','唐诗','tang','','[]','新加大邑綬仍黃，近與單車去洛陽。',64,'全唐诗/poet.tang.6000.json','["新加大邑綬仍黃，近與單車去洛陽。", "顧眄一過丞相府，風流三接令公香。", "南川稉稻花侵縣，西嶺雲霞色滿堂。", "共道進賢蒙上賞，看君幾歲作臺郎。"]'),
('6340ef19-35e2-4194-96a9-3ee0a667905b','送魏萬之京','李頎','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53d9\u4e8b", "\u4e03\u8a00\u5f8b\u8bd7", "\u5199\u666f", "\u53cb\u60c5", "\u6292\u60c5"]','朝聞遊子唱離歌，昨夜微霜初渡河。',64,'全唐诗/poet.tang.6000.json','["朝聞遊子唱離歌，昨夜微霜初渡河。", "鴻鴈不堪愁裏聽，雲山況是客中過。", "關城樹色催寒近，御苑砧聲向晚多。", "莫見長安行樂處，空令歲月易蹉跎。"]'),
('1d9edb8d-9abd-47f0-8441-95435901b9f8','送李回','李頎','唐','唐诗','tang','','[]','知君官屬大司農，詔幸驪山職事雄。',64,'全唐诗/poet.tang.6000.json','["知君官屬大司農，詔幸驪山職事雄。", "歲發金錢供御府，晝看仙液注離宮。", "千巖曙雪旌門上，十月寒花輦路中。", "不覩聲明與文物，自傷流滯去關東。"]'),
('f3dd960a-4589-496f-912f-38e0e8380d4a','宿瑩公禪房聞梵','李頎','唐','唐诗','tang','','[]','花宮仙梵遠微微，月隱高城鐘漏稀。',64,'全唐诗/poet.tang.6000.json','["花宮仙梵遠微微，月隱高城鐘漏稀。", "夜動霜林驚落葉，曉聞天籟發清機。", "蕭條已入寒空靜，颯沓仍隨秋雨飛。", "始覺浮生無住著，頓令心地欲皈依。"]'),
('3a7e3beb-7631-42d3-abeb-42ce887d3a12','題璿公山池','李頎','唐','唐诗','tang','','["\u5e90\u5c71"]','遠公遯跡廬山岑，開士幽居祇樹林。',64,'全唐诗/poet.tang.6000.json','["遠公遯跡廬山岑，開士幽居祇樹林。", "片石孤峯窺色相，清池皓月照禪心。", "指揮如意天花落，坐臥閑房春草深。", "此外俗塵都不染，惟餘玄度得相尋。"]'),
('f8c90f9e-f292-472a-8f5c-653b27e43de6','題盧五舊居','李頎','唐','唐诗','tang','','[]','物在人亡無見期，閑庭繫馬不勝悲。',64,'全唐诗/poet.tang.6000.json','["物在人亡無見期，閑庭繫馬不勝悲。", "窓前綠竹生空地，門外青山如舊時。", "悵望秋天鳴墜葉，巑岏枯柳宿寒鴟。", "憶君淚落東流水，歲歲花開知爲誰。"]'),
('a62f42e5-d321-4d43-9405-6acebd1f25bd','贈別張兵曹','李頎','唐','唐诗','tang','','[]','漢家蕭相國，功蓋五諸侯。',120,'全唐诗/poet.tang.6000.json','["漢家蕭相國，功蓋五諸侯。", "勳業河山重，丹青錫命優。", "君爲禁臠壻，爭看玉人遊。", "荀令焚香日，潘郎振藻秋。", "新成鸚鵡賦，能衣鷫鸘裘。", "不憚軒車遠，仍尋薜荔幽。", "苑梨飛絳葉，伊水淨寒流。", "雪滿故關道，雲遮祥鳳樓。", "一身輕寸祿，萬物任虛舟。", "別後如相問，滄波雙白鷗。"]'),
('259f1f93-dcd7-4698-8e7f-4eb3c27d517f','宿香山寺石樓','李頎','唐','唐诗','tang','','[]','夜宿翠微半，高樓聞暗泉。',72,'全唐诗/poet.tang.6000.json','["夜宿翠微半，高樓聞暗泉。", "漁舟帶遠火，山磬發孤烟。", "衣拂雲松外，門清河漢邊。", "峰巒低枕席，世界接人天。", "靄靄花出霧，輝輝星映川。", "東林曙鶯滿，惆悵欲言旋。"]'),
('15d12326-5a85-493c-bde8-80e6b2ba85ec','聖善閣送裴迪入京','李頎','唐','唐诗','tang','','[]','雲華滿高閣，苔色上鈎欄。',72,'全唐诗/poet.tang.6000.json','["雲華滿高閣，苔色上鈎欄。", "藥草空階靜，梧桐返照寒。", "清吟可愈疾，攜手暫同歡。", "墮葉和金磬，飢烏鳴露盤。", "伊流惜東別，灞水向西看。", "舊託含香署，雲霄何足難。"]'),
('cc784f57-296b-4a24-98ce-315d33706fdc','奉送漪叔遊潁川兼謁淮陽太守','李頎','唐','唐诗','tang','','[]','罷吏今何適，辭家方獨行。',72,'全唐诗/poet.tang.6000.json','["罷吏今何適，辭家方獨行。", "嵩陽入歸夢，潁水半前程。", "聞道淮陽守，東南臥理清。", "郡齋觀政日，人馬望鄉情。", "疊嶺雪初霽，寒砧霜後鳴。", "臨川嗟拜手，寂寞事躬耕。"]'),
('2c591c14-2c7f-4f25-a2fe-51b89ce68143','二妃廟送裴侍御使桂陽','李頎','唐','唐诗','tang','','[]','沅上秋草晚，蒼蒼堯女祠。',72,'全唐诗/poet.tang.6000.json','["沅上秋草晚，蒼蒼堯女祠。", "無人見精魄，萬古寒猿悲。", "桂水身歿後，椒漿神降時。", "回雲迎赤豹，驟雨颯文狸。", "受命出炎海，焚香徵楚詞。", "乘驄感遺跡，一弔清川湄。"]'),
('d19e2ab5-f5db-47c4-8b8a-ff5706d615b7','送暨道士還玉清觀','李頎','唐','唐诗','tang','','[]','仙宮有名籍，度世吳江濆。',72,'全唐诗/poet.tang.6000.json','["仙宮有名籍，度世吳江濆。", "大道本無我，青春長與君。", "中州俄已到，至理得而聞。", "明主降黃屋，時人看白雲。", "空山何窈窕，三秀日氛氳。", "遂此留書客，超遙烟駕分。"]'),
('7c8f8e35-27a6-4e5f-afd9-114ffd0e76ea','送劉主簿歸金壇','李頎','唐','唐诗','tang','','[]','與子十年舊，其如離別何。',72,'全唐诗/poet.tang.6000.json','["與子十年舊，其如離別何。", "宦遊鄰故國，歸夢是滄波。", "京口青山遠，金陵芳草多。", "雲帆曉容裔，江日晝清和。", "縣郭舟人飲，津亭漁者歌。", "茅山有仙洞，羨爾再經過。"]'),
('b13d1a30-3c51-4411-ad5c-591ac6c11412','送盧少府赴延陵','李頎','唐','唐诗','tang','','[]','問君從宦所，何日府中趨。',96,'全唐诗/poet.tang.6000.json','["問君從宦所，何日府中趨。", "遙指金陵縣，青山天一隅。", "行人懷寸祿，小吏獻新圖。", "北固波濤險，南天風俗殊。", "春江連橘柚，晚景媚菰蒲。", "漠漠花生渚，亭亭雲過湖。", "灘沙映村火，水霧歛檣烏。", "回首東門路，鄉書不可無。"]'),
('2fcb174d-3d15-4996-8df3-b149765745c5','送皇甫曾遊襄陽山水兼謁韋太守','李頎','唐','唐诗','tang','','[]','峴山枕襄陽，滔滔江漢長。',120,'全唐诗/poet.tang.6000.json','["峴山枕襄陽，滔滔江漢長。", "山深臥龍宅，水淨斬蛟鄉。", "元凱春秋傳，昭明文選堂。", "風流滿今古，烟島思微茫。", "白鴈暮衝雪，青林寒帶霜。", "蘆花獨戍晚，柑實萬家香。", "舊國欲茲別，輕舟眇未央。", "百花亭漫漫，一柱觀蒼蒼。", "按俗荆南牧，持衡吏部郎。", "逢君立五馬，應醉習家塘。"]'),
('1c52fe18-7800-47e0-95fe-bc2de4e06dce','龍門送裴侍御監五嶺選','李頎','唐','唐诗','tang','','[]','萬里番禺地，官人繼帝憂。',120,'全唐诗/poet.tang.6000.json','["萬里番禺地，官人繼帝憂。", "君爲柱下史，將命出東周。", "歇馬傍川路，張燈臨石樓。", "稜稜靜疎木，濞濞響寒流。", "榔葉四荒外，梅花五嶺頭。", "明珠尉佗國，翠羽夜郎洲。", "夷俗富珍產，土風資宦遊。", "心清物不雜，弊革事無留。", "舉善必稱最，持姦當去尤。", "何辭桂江遠，今日用賢秋。"]'),
('fe2004c3-7ef1-477c-bbff-6f6b95679239','送喬琳','李頎','唐','唐诗','tang','','[]','草綠小平津，花開伊水濱。',120,'全唐诗/poet.tang.6000.json','["草綠小平津，花開伊水濱。", "今君不得意，孤負帝鄉春。", "口不言金帛，心常任屈伸。", "阮公惟飲酒，陶令肯羞貧。", "陽羨風流地，滄海遊寓人。", "菱歌五湖遠，桂樹八公鄰。", "青鳥迎孤棹，白雲隨一身。", "潮隨秣陵上，月映石頭新。", "未可逃名利，應須在縉紳。", "汀洲芳杜色，勸爾暫垂綸。"]'),
('fbb34578-e435-4b68-89b4-f0e4c61fcc2d','題少府監李丞山池','李頎','唐','唐诗','tang','','[]','能向府亭內，置茲山與林。',72,'全唐诗/poet.tang.6000.json','["能向府亭內，置茲山與林。", "他人驌驦馬，而我薜蘿心。", "雨止禁門肅，鶯啼官柳深。", "長廊閟軍器，積水背城陰。", "窓外王孫草，牀頭中散琴。", "清風多仰慕，吾亦爾知音。"]'),
('759ba4c1-69e7-4e6d-a631-e1e4ad834ac3','長壽寺粲公院新甃井','李頎','唐','唐诗','tang','','[]','僧房來往久，露井每同觀。',60,'全唐诗/poet.tang.6000.json','["僧房來往久，露井每同觀。", "白石抱新甃，蒼苔依舊欄。", "空瓶宛轉下，長綆轆轤盤。", "境界因心淨，泉源見底寒。", "鐘鳴時灌頂，對此日閑安。"]'),
('4b451422-9604-43ea-a48e-fd35c2634c10','魏倉曹宅各賦一物得當軒石竹','李頎','唐','唐诗','tang','','[]','羅生殊衆色，獨爲表華滋。',60,'全唐诗/poet.tang.6000.json','["羅生殊衆色，獨爲表華滋。", "雖雜蕙蘭處，無爭桃李時。", "同人趨府暇，落日後庭期。", "密葉散紅點，靈條驚紫蕤。", "芳菲看不厭，采摘願來茲。"]'),
('0b36a19d-3623-4165-887e-f2f00704efe3','奉送五叔入京兼寄綦毋三','李頎','唐','唐诗','tang','','["\u9ec4\u5c71"]','雲陰帶殘日，悵別此何時。',24,'全唐诗/poet.tang.6000.json','["雲陰帶殘日，悵別此何時。", "欲望黃山道，無由見所思。"]'),
('2a1ad234-a935-42b9-bdbc-5633180d1a99','寄韓鵬','李頎','唐','唐诗','tang','','[]','爲政心閑物自閑，朝看飛鳥暮飛還。',32,'全唐诗/poet.tang.6000.json','["爲政心閑物自閑，朝看飛鳥暮飛還。", "寄書河上神明宰，羨爾城頭姑射山。"]'),
('4d09f3c4-f3eb-4ece-b255-91a06da1e6a8','百花原','李頎','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u6292\u60c5"]','百花原頭望京師，黃河水流無已時。',32,'全唐诗/poet.tang.6000.json','["百花原頭望京師，黃河水流無已時。", "窮秋曠野行人絕，馬首東來知是誰。"]'),
('c339392c-eb50-40b2-b223-6c98ab879d53','遇劉五','李頎','唐','唐诗','tang','','[]','洛陽一別梨花新，黃鳥飛飛逢故人。',32,'全唐诗/poet.tang.6000.json','["洛陽一別梨花新，黃鳥飛飛逢故人。", "攜手當年共爲樂，無驚蕙草惜殘春。"]'),
('262c723c-0d6e-4491-af0b-468c25872575','送崔嬰赴漢陽','李頎','唐','唐诗','tang','','[]','中外相連弟與兄，新加小縣子男名。',32,'全唐诗/poet.tang.6000.json','["中外相連弟與兄，新加小縣子男名。", "纔年三十佩銅印，知爾弦歌漢水清。"]'),
('f1880e64-2612-4d8b-a9fc-24164e6e75da','送五叔入京兼寄綦毋三','李頎','唐','唐诗','tang','','[]','吏部明年拜官後，西城必與故人期。',32,'全唐诗/poet.tang.6000.json','["吏部明年拜官後，西城必與故人期。", "寄書春草年年色，莫道相逢玉女祠。"]'),
('6f7d8969-6d94-486f-97e4-2f2b315c7ca3','野老曝背','李頎','唐','唐诗','tang','','[]','百歲老翁不種田，惟知曝背樂殘年。',32,'全唐诗/poet.tang.6000.json','["百歲老翁不種田，惟知曝背樂殘年。", "有時捫虱獨搔首，目送歸鴻籬下眠。"]'),
('098f81a6-a202-4656-ba49-0f7ed72ad8a0','送東陽王太守','李頎','唐','唐诗','tang','','[]','江臯杜蘅綠，芳草日遲遲。',96,'全唐诗/poet.tang.6000.json','["江臯杜蘅綠，芳草日遲遲。", "檜楫今何去，星郎出守時。", "彤襜問風俗，明主寄惸嫠。", "令下不徒爾，人和當在茲。", "昔年經此地，微月有佳期。", "洞口桂花白，巖前春草滋。", "素沙靜津瀨，青壁帶川坻。", "野鶴每孤立，林鼯常晝悲。"]'),
('ed525dd2-587a-440e-80bd-47abd0b222b0','詠張諲山水','李頎','唐','唐诗','tang','','[]','小山破體閑支策，落日梨花照空壁。',32,'全唐诗/poet.tang.6000.json','["小山破體閑支策，落日梨花照空壁。", "詩堪記室妬風流，畫與將軍作勍敵。"]'),
('94e374cb-d887-4b10-b39d-d9e9f1f1757b','失題','李頎','唐','唐诗','tang','','[]','紫極殿前朝伏奏，龍華會裏日相望。',32,'全唐诗/poet.tang.6000.json','["紫極殿前朝伏奏，龍華會裏日相望。", "別離歲歲如流水，誰辨他鄉與故鄉。"]'),
('291f404b-fab4-4097-ae66-bbca79e55f89','冬夜寓居寄儲太祝','綦毋潛','唐','唐诗','tang','','[]','自爲洛陽客，夫子吾知音。',48,'全唐诗/poet.tang.6000.json','["自爲洛陽客，夫子吾知音。", "盡義能下士，時人無此心。", "奈何離居夜，巢鳥悲空林。", "愁坐至月上，復聞南鄰砧。"]'),
('6290b8f0-48de-407f-be2c-629140d91f83','春泛若耶溪','綦毋潛','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6292\u60c5", "\u4e94\u8a00\u53e4\u8bd7"]','幽意無斷絕，此去隨所偶。',60,'全唐诗/poet.tang.6000.json','["幽意無斷絕，此去隨所偶。", "晚風吹行舟，花路入溪口。", "際夜轉西壑，隔山望南斗。", "潭煙飛溶溶，林月低向後。", "生事且彌漫，願爲持竿叟。"]'),
('5742a099-ffbf-4ae8-9d49-07230cc778de','題鶴林寺','綦毋潛','唐','唐诗','tang','','[]','道林隱形勝，向背臨層霄。',74,'全唐诗/poet.tang.6000.json','["道林隱形勝，向背臨層霄。", "松覆山殿[冷]，花藏谿路遙。", "珊珊寶幡挂，焰焰明燈燒。", "遲日半空谷，春風連上潮。", "少憑水木興，暫令身心調。", "願謝攜手客，茲山禪誦饒。"]'),
('9982e29b-869e-46d8-921e-806398ee19fb','題栖霞寺','綦毋潛','唐','唐诗','tang','','[]','南山勢迴合，靈境依此住。',72,'全唐诗/poet.tang.6000.json','["南山勢迴合，靈境依此住。", "殿轉雲崖陰，僧探石泉度。", "龍蛇爭翕習，神鬼皆密護。", "萬壑奔道場，羣峰向雙樹。", "天花飛不著，水月白成路。", "今日觀身我，歸心復何處。"]'),
('54547cd5-6844-4c78-8817-e9c4bd70a229','送儲十二還莊城','綦毋潛','唐','唐诗','tang','','[]','西坂何繚繞，青林問子家。',48,'全唐诗/poet.tang.6000.json','["西坂何繚繞，青林問子家。", "天寒噪野雀，日晚度城鴉。", "寂歷道傍樹，曈曨原上霞。", "茲情不可說，長恨隱淪賒。"]'),
('2a05621e-d87d-43a4-9537-168baca4de02','送章彝下第','綦毋潛','唐','唐诗','tang','','[]','長安渭橋路，行客別時心。',48,'全唐诗/poet.tang.6000.json','["長安渭橋路，行客別時心。", "獻賦溫泉畢，無媒魏闕深。", "黃鶯啼就馬，白日暗歸林。", "三十名未立，君還惜寸陰。"]'),
('3ab99853-9e39-4cc2-b8fe-9f80d5c250ee','送崔員外黔中監選','綦毋潛','唐','唐诗','tang','','[]','持衡出帝畿，星指夜郎飛。',48,'全唐诗/poet.tang.6000.json','["持衡出帝畿，星指夜郎飛。", "神女雲迎馬，荆門雨濕衣。", "聽猿收淚罷，繫鴈待書稀。", "蠻貊雖殊俗，知君肝膽微。"]'),
('c1cf74ec-4e8f-4d96-a6e0-6450c4690e79','送賈恆明府兼寄溫張二司戶','綦毋潛','唐','唐诗','tang','','[]','越客新安別，秦人舊國情。',48,'全唐诗/poet.tang.6000.json','["越客新安別，秦人舊國情。", "舟乘晚風便，月帶上潮平。", "花路西施石，雲峰句踐城。", "明州報兩掾，相憶二毛生。"]'),
('7d3c02c9-beb6-4eb1-81f1-a6530dd55f6f','送宋秀才','綦毋潛','唐','唐诗','tang','','[]','冠古積榮盛，當時數戟門。',48,'全唐诗/poet.tang.6000.json','["冠古積榮盛，當時數戟門。", "舊交丞相子，繼世五侯孫。", "長劒倚天外，短書盈萬言。", "秋風一送別，江上黯消魂。"]'),
('bd62ebec-0580-407f-b10c-7c828ab2421a','送平判官入秦','綦毋潛','唐','唐诗','tang','','[]','謫遠自安命，三年已忘歸。',48,'全唐诗/poet.tang.6000.json','["謫遠自安命，三年已忘歸。", "同聲願執手，驛騎到門扉。", "云是帝鄉去，軍書謁紫微。", "曾爲金馬客，向日淚沾衣。"]'),
('6ab56a35-a129-4f6a-ad7b-bf0e0232bc2b','送鄭務拜伯父','綦毋潛','唐','唐诗','tang','','[]','名公作逐臣，驅馬拂行塵。',48,'全唐诗/poet.tang.6000.json','["名公作逐臣，驅馬拂行塵。", "舊國問鄖子，勞歌過郢人。", "一川花送客，二月柳宜春。", "奉料竹林興，寬懷此別晨。"]'),
('f3d1052d-5b2f-4f65-9f97-a41b848d5c1d','題招隱寺絢公房','綦毋潛','唐','唐诗','tang','','[]','開士度人久，空巖花霧深。',48,'全唐诗/poet.tang.6000.json','["開士度人久，空巖花霧深。", "徒知燕坐處，不見有爲心。", "蘭若門對壑，田家路隔林。", "還言證法性，歸去比黃金。"]'),
('706d8c47-3008-4e58-a275-9f048ebb19d7','宿太平觀','綦毋潛','唐','唐诗','tang','','[]','夕到玉京寢，窅冥雲漢低。',48,'全唐诗/poet.tang.6000.json','["夕到玉京寢，窅冥雲漢低。", "魂交仙室蝶，曙聽羽人雞。", "滴瀝花上露，清泠松下谿。", "明當訪真隱，揮手入無倪。"]'),
('42cf3a65-dee7-495d-abc2-47ac39fbba8d','題靈隱寺山頂禪院','綦毋潛','唐','唐诗','tang','','[]','招提此山頂，下界不相聞。',48,'全唐诗/poet.tang.6000.json','["招提此山頂，下界不相聞。", "塔影挂清漢，鐘聲和白雲。", "觀空靜室掩，行道衆香焚。", "且駐西來駕，人天日未曛。"]'),
('5f6ffb21-59dd-4e71-8f59-5280fcc1d92b','若耶溪逢孔九','綦毋潛','唐','唐诗','tang','','[]','相逢此溪曲，勝託在煙霞。',48,'全唐诗/poet.tang.6000.json','["相逢此溪曲，勝託在煙霞。", "潭影竹間動，巖陰簷外斜。", "人言上皇代，犬吠武陵家。", "借問淹留日，春風滿若耶。"]'),
('bf89be7e-31a7-4e7c-9120-dccb9396cd94','宿龍興寺','綦毋潛','唐','唐诗','tang','','[]','香剎夜忘歸，松青古殿扉。',48,'全唐诗/poet.tang.6000.json','["香剎夜忘歸，松青古殿扉。", "燈明方丈室，珠繫比丘衣。", "白日傳心靜，青蓮喻法微。", "天花落不盡，處處鳥銜飛。"]'),
('69def054-408a-424e-b288-1f720a7b6280','題沈東美員外山池','綦毋潛','唐','唐诗','tang','','[]','仙郎偏好道，鑿沼象瀛洲。',48,'全唐诗/poet.tang.6000.json','["仙郎偏好道，鑿沼象瀛洲。", "魚樂隨情性，船行任去留。", "秦人辨雞犬，堯日識巢由。", "歸客衡門外，仍憐返景幽。"]'),
('2f60e2e5-813b-4186-8be3-690c9a94b446','茅山洞口','綦毋潛','唐','唐诗','tang','','[]','華陽仙洞口，半嶺拂雲看。',48,'全唐诗/poet.tang.6000.json','["華陽仙洞口，半嶺拂雲看。", "窈窕穿苔壁，差池對石壇。", "方隨地脉轉，稍覺水晶寒。", "未果變金骨，歸來茲路難。"]'),
('7911c240-6791-42df-a986-4a7a1f584e1d','過方尊師院','綦毋潛','唐','唐诗','tang','','[]','羽客北山尋，草堂松徑深。',48,'全唐诗/poet.tang.6000.json','["羽客北山尋，草堂松徑深。", "養神宗示法，得道不知心。", "洞戶逢雙履，寥天有一琴。", "更登玄圃上，仍種杏成林。"]'),
('9b363113-5825-4d4e-a5e0-4eece9ec0a8b','經陸補闕隱居','綦毋潛','唐','唐诗','tang','','[]','不敢要君徵亦起，致君全得似唐虞。',64,'全唐诗/poet.tang.6000.json','["不敢要君徵亦起，致君全得似唐虞。", "讜言昨歎離天聽，新象今聞入縣圖。", "琴鎖壞窗風自響，鶴歸喬木隱難呼。", "學書弟子何人在，點檢猶存諫草無。"]'),
('78cb7f8b-5906-469f-a964-c73388b1a3c2','登天竺寺','綦毋潛','唐','唐诗','tang','','[]','郡有化城最，西窮疊嶂深。',72,'全唐诗/poet.tang.6000.json','["郡有化城最，西窮疊嶂深。", "松門當澗口，石路在峰心。", "幽見夕陽霽，高逢暮雨陰。", "佛身瞻紺髮，寶地踐黃金。", "雲向竹谿盡，月從花洞臨。", "因物成真悟，遺世在茲岑。"]'),
('02b96a97-bf2b-4bca-885d-4477637f85e5','滿公房','綦毋潛','唐','唐诗','tang','','[]','世界蓮花藏，行人香火緣。',24,'全唐诗/poet.tang.6000.json','["世界蓮花藏，行人香火緣。", "燈王照不盡，中夜寂相傳。"]'),
('c575c996-1310-448f-a30a-e3f4842b2f45','過融上人蘭若','綦毋潛','唐','唐诗','tang','','[]','山頭禪室挂僧衣，窗外無人溪鳥飛。',32,'全唐诗/poet.tang.6000.json','["山頭禪室挂僧衣，窗外無人溪鳥飛。", "黃昏半在下山路，却聽鐘聲連翠微。"]'),
('d548d87c-f901-4ac2-bf2a-42249c164aa3','早發上東門','綦毋潛','唐','唐诗','tang','','[]','十五能行西入秦，三十無家作路人。',32,'全唐诗/poet.tang.6000.json','["十五能行西入秦，三十無家作路人。", "時命不將明主合，布衣空染洛陽塵。"]'),
('04bb42bd-b530-47a1-b16d-194ade6f07cf','祇園寺','綦毋潛','唐','唐诗','tang','','[]','寶坊求往跡，神理駐沿洄。',48,'全唐诗/poet.tang.6000.json','["寶坊求往跡，神理駐沿洄。", "鴈塔酬前願，王身更後來。", "加持將暝合，朗悟豁然開。", "兩世分明見，餘生復幾哉。"]'),
('a55071fb-7c28-4b91-99e7-c171064c2779','送集賢學士伊闕史少府放歸江東覲省','綦毋潛','唐','唐诗','tang','','[]','墨客鍾張侶，材高吳越珍。',48,'全唐诗/poet.tang.6000.json','["墨客鍾張侶，材高吳越珍。", "千門來謁帝，駟馬去榮親。", "吏邑沿清洛，鄉山指白蘋。", "歸期應不遠，當及未央春。"]'),
('286afdbf-943f-4db8-ae95-4771364f294e','述韋昭應畫犀牛','儲光羲','唐','唐诗','tang','','[]','遐方獻文犀，萬里隨南金。',120,'全唐诗/poet.tang.6000.json','["遐方獻文犀，萬里隨南金。", "大邦柔遠人，以之居山林。", "食棘無秋冬，絕流無淺深。", "雙角前嶄嶄，三蹄下駸駸。", "朝賢壯其容，未能辨其音。", "有我衰鳥郎，新邑長鳴琴。", "陛閣飛嘉聲，丘甸盈仁心。", "閑居命國工，作繪北堂陰。", "眈眈若有神，庶比來儀禽。", "昔有舞天庭，爲君奏龍吟。"]'),
('9ec7ee8c-d3d1-4bc6-a039-4690aaae44de','獻王威儀','儲光羲','唐','唐诗','tang','','[]','入與真主言，有騎天馬來。',36,'全唐诗/poet.tang.6000.json','["入與真主言，有騎天馬來。", "但有華清宮，不用神明臺。", "肅肅長自閑，門靜無人開。"]'),
('5933a7ce-8229-4c73-8ee3-0512a999b93f','野田黃雀行','儲光羲','唐','唐诗','tang','','[]','嘖嘖野田雀，不知軀體微。',84,'全唐诗/poet.tang.6000.json','["嘖嘖野田雀，不知軀體微。", "閑穿深蒿裏，爭食復爭飛。", "窮老一頹舍，棗多桑樹稀。", "無棗猶可食，無桑何以衣。", "蕭條空倉暮，相引時來歸。", "斜路豈不捷，渚田豈不肥。", "水長路且壞，惻惻與心違。"]'),
('c8d49a74-fe0a-4003-a0da-5653665504f5','樵父詞','儲光羲','唐','唐诗','tang','','[]','山北饒朽木，山南多枯枝。',84,'全唐诗/poet.tang.6000.json','["山北饒朽木，山南多枯枝。", "枯枝作採薪，爨室私自知。", "詰朝礪斧尋，視暮行歌歸。", "先雪隱薜荔，迎暄臥茅茨。", "清澗日濯足，喬木時曝衣。", "終年登險阻，不復憂安危。", "蕩漾與神遊，莫知是與非。"]'),
('ce84ec5f-cac1-4ed4-a04b-07d740c76585','漁父詞','儲光羲','唐','唐诗','tang','','[]','澤魚好鳴水，溪魚好上流。',84,'全唐诗/poet.tang.6000.json','["澤魚好鳴水，溪魚好上流。", "漁梁不得意，下渚潛垂鉤。", "亂荇時礙楫，新蘆復隱舟。", "靜言念終始，安坐看沈浮。", "素髮隨風揚，遠心與雲遊。", "逆浪還極浦，信潮下滄洲。", "非爲徇形役，所樂在行休。"]'),
('3cf09a50-e553-4e24-a7c9-7249464a56d7','牧童詞','儲光羲','唐','唐诗','tang','','[]','不言牧田遠，不道牧陂深。',84,'全唐诗/poet.tang.6000.json','["不言牧田遠，不道牧陂深。", "所念牛馴擾，不亂牧童心。", "圓笠覆我首，長簑披我襟。", "方將憂暑雨，亦以懼寒陰。", "大牛隱層坂，小牛穿近林。", "同類相鼓舞，觸物成謳吟。", "取樂須臾間，寧問聲與音。"]'),
('62be752e-7964-4b51-97c6-d86415ab8654','采蓮詞','儲光羲','唐','唐诗','tang','','[]','淺渚荇花繁，深潭菱葉疎。',72,'全唐诗/poet.tang.6000.json','["淺渚荇花繁，深潭菱葉疎。", "獨往方自得，恥邀淇上姝。", "廣江無術阡，大澤絕方隅。", "浪中海童語，流下鮫人居。", "春鴈時隱舟，新萍復滿湖。", "采采乘日暮，不思賢與愚。"]'),
('09f5cc10-01a4-4ec2-be4a-3deab75787fd','採菱詞','儲光羲','唐','唐诗','tang','','[]','濁水菱葉肥，清水菱葉鮮。',96,'全唐诗/poet.tang.6000.json','["濁水菱葉肥，清水菱葉鮮。", "義不遊濁水，志士多苦言。", "潮沒具區藪，潦深雲夢田。", "朝隨北風去，暮逐南風旋。", "浦口多漁家，相與邀我船。", "飯稻以終日，羹蓴將永年。", "方冬水物窮，又欲休山樊。", "盡室相隨從，所貴無憂患。"]'),
('80b7dcdf-a5af-46c8-9ce4-f01a77a0f890','射雉詞','儲光羲','唐','唐诗','tang','','[]','曝暄理新翳，迎春射鳴雉。',96,'全唐诗/poet.tang.6000.json','["曝暄理新翳，迎春射鳴雉。", "原田遙一色，臯陸曠千里。", "遙聞咿喔聲，時見雙飛起。", "冪䍥疎蒿下，毰毸深叢裏。", "顧敵已忘生，爭雄方決死。", "仁心貴勇義，豈能復傷此。", "超遙下故墟，迢遞回高畤。", "大夫昔何苦，取笑歡妻子。"]'),
('ba47801f-e80d-4381-8a6e-523809fd1d76','猛虎詞','儲光羲','唐','唐诗','tang','','[]','寒亦不憂雪，飢亦不食人。',96,'全唐诗/poet.tang.6000.json','["寒亦不憂雪，飢亦不食人。", "人肉豈不甘，所惡傷明神。", "太室爲我宅，孟門爲我鄰。", "百獸爲我膳，五龍爲我賓。", "蒙馬一何威，浮江一以仁。", "彩章耀朝日，爪牙雄武臣。", "高雲逐氣浮，厚地隨聲震。", "君能賈餘勇，日夕長相親。"]'),
('562c378e-1d6f-43a1-96f6-a7efd799a3e9','渭橋北亭作','儲光羲','唐','唐诗','tang','','[]','停車渭陽暮，望望入秦京。',48,'全唐诗/poet.tang.6000.json','["停車渭陽暮，望望入秦京。", "不見鵷鸞道，如聞歌吹聲。", "鄉魂涉江水，客路指蒲城。", "獨有故樓月，今來亭上明。"]'),
('97033757-7f04-4642-a13c-ab76622ca0ef','述華清宮五首 一','儲光羲','唐','唐诗','tang','','[]','上在蓬萊宮，莫若居華清。',36,'全唐诗/poet.tang.6000.json','["上在蓬萊宮，莫若居華清。", "朝朝禮玄閣，日日聞體輕。", "大聖不私己，精禋爲羣氓。"]'),
('9fea8fa6-3c29-45d0-83ed-3eacf059f158','述華清宮五首 二','儲光羲','唐','唐诗','tang','','[]','上出蓬萊時，六龍儼齊首。',36,'全唐诗/poet.tang.6000.json','["上出蓬萊時，六龍儼齊首。", "長道舒羽儀，彤雲暎前後。", "天聲殷宇宙，真氣到林藪。"]'),
('5615d8d0-7549-48cf-8cbc-e164f5f7e7a5','述華清宮五首 三','儲光羲','唐','唐诗','tang','','[]','昔在軒轅朝，五城十二樓。',36,'全唐诗/poet.tang.6000.json','["昔在軒轅朝，五城十二樓。", "今我神泉宮，獨在驪山陬。", "羣方趨順動，百辟隨天遊。"]'),
('6b5036a9-e8ff-4b87-9a79-71baed7d10b0','述華清宮五首 四','儲光羲','唐','唐诗','tang','','[]','正月開陽和，通門緝元化。',36,'全唐诗/poet.tang.6000.json','["正月開陽和，通門緝元化。", "穆穆睟容歸，豈爲明燈夜。", "高山大風起，肅肅隨龍駕。"]'),
('82eef091-ce72-4483-b43d-b5fee95a1afc','述華清宮五首 五','儲光羲','唐','唐诗','tang','','[]','上林神君宮，此地即明庭。',36,'全唐诗/poet.tang.6000.json','["上林神君宮，此地即明庭。", "山開鴻濛色，天轉招搖星。", "三雪報大有，孰爲非我靈。"]'),
('2295758a-d709-4f67-b0fa-86270479657e','雜詠五首 石子松','儲光羲','唐','唐诗','tang','','[]','盤石青巖下，松生盤石中。',36,'全唐诗/poet.tang.6000.json','["盤石青巖下，松生盤石中。", "冬春無異色，朝暮有清風。", "五鬣何人采，西山舊兩童。"]'),
('226dca1e-5a98-4f44-a3c1-aa76fbb7d166','雜詠五首 架簷藤','儲光羲','唐','唐诗','tang','','[]','得從軒墀下，殊勝松柏林。',36,'全唐诗/poet.tang.6000.json','["得從軒墀下，殊勝松柏林。", "生枝逐架遠，吐葉向門深。", "何許答君子，簷間朝暝陰。"]'),
('9977d464-9d73-4e6e-a8ff-ae70c3ad2b22','雜詠五首 池邊鶴','儲光羲','唐','唐诗','tang','','[]','舞鶴傍池邊，水清毛羽鮮。',36,'全唐诗/poet.tang.6000.json','["舞鶴傍池邊，水清毛羽鮮。", "立如依岸雪，飛似向池泉。", "江海雖言曠，無如君子前。"]'),
('74b8ae25-a739-49fc-8c2e-d3165ea6471c','雜詠五首 釣魚灣','儲光羲','唐','唐诗','tang','','["\u6625\u5929", "\u7231\u60c5", "\u9493\u9c7c"]','垂釣綠灣春，春深杏花亂。',36,'全唐诗/poet.tang.6000.json','["垂釣綠灣春，春深杏花亂。", "潭清疑水淺，荷動知魚散。", "日暮待情人，維舟綠楊岸。"]'),
('e811658a-f938-46ae-9acc-9d04d305c9b0','雜詠五首 幽人居','儲光羲','唐','唐诗','tang','','[]','幽人下山徑，去去夾青林。',36,'全唐诗/poet.tang.6000.json','["幽人下山徑，去去夾青林。", "滑處莓苔濕，暗中蘿薜深。", "春朝煙雨散，猶帶浮雲陰。"]'),
('caa9b91e-7626-4baf-9d62-ef924a70022a','題太玄觀','儲光羲','唐','唐诗','tang','','[]','門外車馬喧，門裏宮殿清。',36,'全唐诗/poet.tang.6000.json','["門外車馬喧，門裏宮殿清。", "行即翳若木，坐即吹玉笙。", "所喧既非我，真道其冥冥。"]'),
('da1194a2-8f8a-4e96-b09e-bd7756bc3c5e','至嵩陽觀觀即天皇故宅','儲光羲','唐','唐诗','tang','','[]','真人上清室，乃在中峰前。',72,'全唐诗/poet.tang.6000.json','["真人上清室，乃在中峰前。", "花霧生玉井，霓裳畫列仙。", "念茲宮故宇，多此地新泉。", "松柏有清陰，薜蘿亦自妍。", "一聞步虛子，又話逍遙篇。", "忽若在雲漢，風中意泠然。"]'),
('1493859d-0727-4927-b91b-e3444fc31c44','貽韋鍊師','儲光羲','唐','唐诗','tang','','[]','精思莫知日，意靜如空虛。',48,'全唐诗/poet.tang.6000.json','["精思莫知日，意靜如空虛。", "三鳥自來去，九光遙卷舒。", "新池近天井，玉宇停雲車。", "余亦苦山路，洗心祈道書。"]'),
('7e6ebc0b-0134-4a55-aecd-2616e80cc74c','霽後貽馬十二巽','儲光羲','唐','唐诗','tang','','[]','高天風雨散，清氣在園林。',48,'全唐诗/poet.tang.6000.json','["高天風雨散，清氣在園林。", "況我夜初靜，當軒鳴綠琴。", "雲開北堂月，庭滿南山陰。", "不見長裾者，空歌遊子吟。"]'),
('26409e2d-2a62-4860-982e-905713740b4e','題陸山人樓','儲光羲','唐','唐诗','tang','','[]','暮聲雜初鴈，夜色涵早秋。',48,'全唐诗/poet.tang.6000.json','["暮聲雜初鴈，夜色涵早秋。", "獨見海中月，照君池上樓。", "山雲拂高棟，天漢入雲流。", "不惜朝光滿，其如千里遊。"]'),
('2565e126-7159-4b28-beec-f19a14cac556','獻八舅東歸','儲光羲','唐','唐诗','tang','','[]','高位莫能捨，捨之世所賢。',120,'全唐诗/poet.tang.6000.json','["高位莫能捨，捨之世所賢。", "雲車遊日華，豈比龍樓前。", "寢疾乃就枕，情感唯靈仙。", "帝鴻思道宗，臣彭亦長年。", "天書加羽服，又許歸東川。", "鏡水涵太清，禹山朝上玄。", "誠亡真混沌，玉立方嬋娟。", "素業作仙居，子孫當自傳。", "門多松柏樹，篋有逍遙篇。", "獨往不可羣，滄海成桑田。"]'),
('7c9313b8-bcef-45e5-b4ae-25e281307257','泛茅山東溪','儲光羲','唐','唐诗','tang','','[]','清晨登仙峰，峰遠行未極。',60,'全唐诗/poet.tang.6000.json','["清晨登仙峰，峰遠行未極。", "江海霽初景，草木含新色。", "而我任天和，此時聊動息。", "望鄉白雲裏，發棹清溪側。", "松柏生深山，無心自貞直。"]'),
('3658ec58-110e-4eed-8761-5b8910883e8c','喫茗粥作','儲光羲','唐','唐诗','tang','','[]','當晝暑氣盛，鳥雀靜不飛。',60,'全唐诗/poet.tang.6000.json','["當晝暑氣盛，鳥雀靜不飛。", "念君高梧陰，復解山中衣。", "數片遠雲度，曾不蔽炎暉。", "淹留膳茶粥，共我飯蕨薇。", "敝廬既不遠，日暮徐徐歸。"]'),
('74afbaa0-bea6-4408-8268-5970cbc949e2','遊茅山五首 一','儲光羲','唐','唐诗','tang','','[]','十年別鄉縣，西去入皇州。',72,'全唐诗/poet.tang.6000.json','["十年別鄉縣，西去入皇州。", "此意在觀國，不言空遠遊。", "九衢平若水，利往無輕舟。", "北洛反初路，東江還故丘。", "春山多秀木，碧澗盡清流。", "不見子桑扈，當從方外求。"]'),
('ba855c71-24b1-441b-aaad-95428df93159','遊茅山五首 二','儲光羲','唐','唐诗','tang','','[]','世業傳儒行，行成非不榮。',72,'全唐诗/poet.tang.6000.json','["世業傳儒行，行成非不榮。", "其如懷獨善，況以聞長生。", "家近華陽洞，早年深此情。", "巾車雲路入，理棹瑤溪行。", "天地朝光滿，江山春色明。", "王庭有軒冕，此日方知輕。"]'),
('89e360a8-7fa8-4dd8-aaf8-0a7080695a09','遊茅山五首 三','儲光羲','唐','唐诗','tang','','[]','平生非作者，望古懷清芬。',72,'全唐诗/poet.tang.6000.json','["平生非作者，望古懷清芬。", "心以道爲際，行將時不羣。", "茲山在人境，靈貺久傳聞。", "遠勢一峰出，近形千嶂分。", "冬春有茂草，朝暮多鮮雲。", "此去亦何極，但言西日曛。"]'),
('f949d6a1-f457-445b-9f1c-809694ece7c6','遊茅山五首 四','儲光羲','唐','唐诗','tang','','[]','昔賢居柱下，今我去人間。',72,'全唐诗/poet.tang.6000.json','["昔賢居柱下，今我去人間。", "良以直心曠，兼之外視閑。", "垂綸非釣國，好學異希顏。", "落日登高嶼，悠然望遠山。", "溪流碧水去，雲帶清陰還。", "想見中林士，巖扉長不關。"]'),
('0a15619e-69d8-49a5-b319-8be60e4ec1f2','遊茅山五首 五','儲光羲','唐','唐诗','tang','','[]','名嶽徵仙事，清都訪道書。',72,'全唐诗/poet.tang.6000.json','["名嶽徵仙事，清都訪道書。", "山門入松柏，天路涵空虛。", "南極見朝采，西潭聞夜漁。", "遠心尚雲宿，浪跡出林居。", "爲己存實際，忘形同化初。", "此行良已矣，不樂復何如。"]'),
('41a27c44-6404-4e6d-b7dc-202b2d87c35c','述降聖觀','儲光羲','唐','唐诗','tang','','[]','一山盡天苑，一峰開道宮。',72,'全唐诗/poet.tang.6000.json','["一山盡天苑，一峰開道宮。", "道花飛羽衞，天鳥遊雲空。", "玉殿俯玄水，春旗搖素風。", "夾門小松柏，覆井新梧桐。", "自昔大仙下，乃知元化功。", "神皇作桂館，此意與天通。"]'),
('4e67e320-c626-401e-a546-e768e8fcf993','題眄上人禪居','儲光羲','唐','唐诗','tang','','[]','真王清淨子，燕居復行心。',72,'全唐诗/poet.tang.6000.json','["真王清淨子，燕居復行心。", "結宇鄰居邑，寤言非遠尋。", "丹青丈室滿，草樹一庭深。", "秀色玄冬發，交枝白日陰。", "江流暎朱戶，山鳥鳴香林。", "獨住已寂寂，安知浮與沈。"]'),
('b35f4e36-2000-4a2e-9500-37318c52f3f3','過新豐道中','儲光羲','唐','唐诗','tang','','[]','西下長樂坂，東入新豐道。',72,'全唐诗/poet.tang.6000.json','["西下長樂坂，東入新豐道。", "雨多車馬稀，道上生秋草。", "太陰蔽臯陸，莫知晚與早。", "雷雨杳冥冥，川谷漫浩浩。", "詔書植嘉木，衆言桃李好。", "自媿無此容，歸從漢陰老。"]'),
('7b5fb428-57f2-45e8-bd6b-ed61ebce6fcd','夜到洛口入黃河','儲光羲','唐','唐诗','tang','','["\u9ec4\u6cb3"]','河洲多青草，朝暮增客愁。',72,'全唐诗/poet.tang.6000.json','["河洲多青草，朝暮增客愁。", "客愁惜朝暮，枉渚蹔停舟。", "中宵大川靜，解纜逐歸流。", "浦漵既清曠，沿洄非阻修。", "登艫望落月，擊汰悲新秋。", "倘遇乘槎客，永言星漢遊。"]'),
('2b2be217-4c67-40b7-98fc-4f15fae0f25d','使過彈箏峽作','儲光羲','唐','唐诗','tang','','[]','鳥雀知天雪，羣飛復羣鳴。',84,'全唐诗/poet.tang.6000.json','["鳥雀知天雪，羣飛復羣鳴。", "原田無遺粟，日暮滿空城。", "達士憂世務，鄙夫念王程。", "晨過彈箏峽，馬足凌兢行。", "雙壁隱靈曜，莫能知晦明。", "皚皚堅冰白，漫漫陰雲平。", "始信古人言，苦節不可貞。"]'),
('c776c897-2104-4261-8517-9dd0c729395e','泊舟貽潘少府','儲光羲','唐','唐诗','tang','','[]','行子苦風潮，維舟未能發。',84,'全唐诗/poet.tang.6000.json','["行子苦風潮，維舟未能發。", "宵分卷前幔，臥視清秋月。", "四澤蒹葭深，中洲煙火絕。", "蒼蒼水霧起，落落疎星沒。", "所遇盡漁商，與言多楚越。", "其如念極浦，又以思明哲。", "常若千里餘，況之異鄉別。"]'),
('34fbd63f-f80a-4ca2-8842-e5f9ddbbc943','仲夏入園中東陂','儲光羲','唐','唐诗','tang','','[]','方塘深且廣，伊昔俯吾廬。',84,'全唐诗/poet.tang.6000.json','["方塘深且廣，伊昔俯吾廬。", "環岸垂綠柳，盈澤發紅蕖。", "上延北原秀，下屬幽人居。", "暑雨若混沌，清明如空虛。", "此鄉多隱逸，水陸見樵漁。", "廢賞亦何貴，爲歡良易攄。", "且言重觀國，當此賦歸歟。"]'),
('411d50c5-64f7-49e4-bb04-040b8633fa87','效古二首 一','儲光羲','唐','唐诗','tang','','[]','晨登涼風臺，暮走邯鄲道。',84,'全唐诗/poet.tang.6000.json','["晨登涼風臺，暮走邯鄲道。", "曜靈何赫烈，四野無青草。", "大軍北集燕，天子西居鎬。", "婦人役州縣，丁男事征討。", "老幼相別離，哭泣無昏早。", "稼穡既殄絕，川澤復枯槁。", "曠哉遠此憂，冥冥商山皓。"]'),
('b68bbb5c-3aa4-4649-9202-dabdb523519e','效古二首 二','儲光羲','唐','唐诗','tang','','[]','東風吹大河，河水如倒流。',84,'全唐诗/poet.tang.6000.json','["東風吹大河，河水如倒流。", "河洲塵沙起，有若黃雲浮。", "赬霞燒廣澤，洪曜赫高丘。", "野老泣相語，無地可蔭休。", "翰林有客卿，獨負蒼生憂。", "中夜起躑躅，思欲獻厥謀。", "君門峻且深，踠足空夷猶。"]'),
('4a3148e7-97cf-4a62-b8e4-a0ecf7064b15','雜詩二首 一','儲光羲','唐','唐诗','tang','','[]','混沌本無象，末路多是非。',84,'全唐诗/poet.tang.6000.json','["混沌本無象，末路多是非。", "達士志寥廓，所在能忘禨。", "耕鑿時未至，還山聊采薇。", "虎豹對我蹲，鸑鷟旁我飛。", "仙人空中來，謂我勿復歸。", "格澤爲君駕，虹蜺爲君衣。", "西遊崑崙墟，可與世人違。"]'),
('f8141f67-1f00-4d17-9b81-28aac0264590','雜詩二首 二','儲光羲','唐','唐诗','tang','','[]','秋氣肅天地，太行高崔嵬。',84,'全唐诗/poet.tang.6000.json','["秋氣肅天地，太行高崔嵬。", "猨狖清夜吟，其聲一何哀。", "寂寞掩圭蓽，夢寐遊蓬萊。", "琪樹遠亭亭，玉堂雲中開。", "洪崖吹簫管，玉女飄颻來。", "雨師既先後，道路無纖埃。", "鄙哉楚襄王，獨好陽雲臺。"]'),
('289e14b7-4e83-4968-9491-e141e44e883d','陸著作挽歌 一','儲光羲','唐','唐诗','tang','','[]','世業江湖側，郊原休沐處。',48,'全唐诗/poet.tang.6000.json','["世業江湖側，郊原休沐處。", "獨言五日歸，未道千秋去。", "鄉亭春水綠，昌閣寒光暮。", "昔爲晝錦遊，今成逝川路。"]'),
('5b835e44-8fd3-40b9-ae17-da1533a2bbf8','陸著作挽歌 二','儲光羲','唐','唐诗','tang','','[]','歸路秦城下，寒雲慘平田。',48,'全唐诗/poet.tang.6000.json','["歸路秦城下，寒雲慘平田。", "故園滄海邊，綠柳覆平川。", "送客異他日，還舟殊昔年。", "華亭有明月，長向隴頭懸。"]'),
('63ba36c8-6e5d-49de-ab6d-9e696d978a3b','陸著作挽歌 三','儲光羲','唐','唐诗','tang','','[]','劍水千人石，荆江萬里流。',48,'全唐诗/poet.tang.6000.json','["劍水千人石，荆江萬里流。", "英英有君子，才德滿中州。", "明道俟良佐，惟賢初薄遊。", "生涯一朝盡，寂寞夜臺幽。"]'),
('ca396722-5b4c-4b44-bb09-1a81beac7286','陸著作挽歌 四','儲光羲','唐','唐诗','tang','','[]','金堂策令名，仙掖居清位。',48,'全唐诗/poet.tang.6000.json','["金堂策令名，仙掖居清位。", "鳴玉朝雙闕，垂纓遊兩地。", "朝夕既論思，春秋仍書事。", "何言魯聲伯，忽下瓊珠淚。"]'),
('3b3fe4cc-76d6-4f91-bab1-2e235fdbad16','陸著作挽歌 五','儲光羲','唐','唐诗','tang','','[]','令德棄人世，明朝降寵章。',48,'全唐诗/poet.tang.6000.json','["令德棄人世，明朝降寵章。", "起居存有位，著作沒爲郎。", "寒水落南浦，月華虛北堂。", "松門一長想，彷彿見清揚。"]'),
('cda93da7-799f-4307-a5f8-5338b4c98375','山居貽裴十二迪','儲光羲','唐','唐诗','tang','','[]','落葉滿山砌，蒼煙埋竹扉。',72,'全唐诗/poet.tang.6000.json','["落葉滿山砌，蒼煙埋竹扉。", "遠懷青冥士，書劒常相依。", "霜臥眇茲地，琴言紛已違。", "衡陽今萬里，南雁將何歸。", "出徑惜松引，入舟憐釣磯。", "西林有明月，夜久空微微。"]'),
('5f55bc09-3baf-4335-acb6-3eb3d1bda0c4','秦中歲晏馬舍人宅宴集','儲光羲','唐','唐诗','tang','','[]','冬暮久無樂，西行至長安。',48,'全唐诗/poet.tang.6000.json','["冬暮久無樂，西行至長安。", "故人處東第，清夜多新歡。", "廣庭竹陰靜，華池月色寒。", "知音盡詞客，方見交情難。"]'),
('bf380f86-29a3-4088-8ae1-c77568b1d13e','薦玄德公廟','儲光羲','唐','唐诗','tang','','[]','神道本無已，成化亦自然。',72,'全唐诗/poet.tang.6000.json','["神道本無已，成化亦自然。", "君居寥天上，德在玉華泉。", "真遊踐王豫，永日遲雲仙。", "表微在營道，明祀將祈年。", "靈山俯新邑，松上生彩煙。", "豈知穆天子，遠去瑤池邊。"]'),
('52c412ea-32e0-41df-9ff1-3dbf6e0415d8','上長史王公責躬','儲光羲','唐','唐诗','tang','','[]','覆舟無伯夷，覆車無仲尼。',120,'全唐诗/poet.tang.6000.json','["覆舟無伯夷，覆車無仲尼。", "自咎失明義，寧由貝錦詩。", "松柏日已堅，桃李日以滋。", "顧己獨暗昧，所居成蒺藜。", "大賢薦時文，醜婦用蛾眉。", "惕惕愧不已，豈敢論其私。", "方朔既有言，子建亦有詩。", "惻隱及先世，析薪成自悲。", "靈鳥酬德輝，黃雀報仁慈。", "若公庶伏罪，此事安能遲。"]'),
('71eb1de4-46ce-451c-ac03-bff775feb664','至嶽寺即大通大照禪塔上溫上人','儲光羲','唐','唐诗','tang','','[]','秋山下暎宮，宮色宜朝陽。',96,'全唐诗/poet.tang.6000.json','["秋山下暎宮，宮色宜朝陽。", "迢遞在半嶺，參差非一行。", "燕息雲滿門，出遊花隱房。", "二尊此成道，禪宇遙相望。", "鳳鐸天中鳴，巖梯松下長。", "山墟響信鼓，蘅薄生蕙香。", "起滅一以雪，往來亦誠亡。", "悲哉門弟子，要自知心長。"]'),
('e8b646d0-8a7b-4d7e-9bdb-bd5d30646bf3','終南幽居獻蘇侍郎三首時拜太祝未上 一','儲光羲','唐','唐诗','tang','','[]','暮春天氣和，登嶺望層城。',84,'全唐诗/poet.tang.6000.json','["暮春天氣和，登嶺望層城。", "朝日懸清景，巍峨宮殿明。", "聖君常臨朝，達士復懸衡。", "道近燕艮足，歸來臥山楹。", "靈堦曝仙書，深室煉金英。", "春巖松柏秀，晨路鵾雞鳴。", "羽化既有言，無然悲不成。"]'),
('df98c532-426e-4342-a35a-915724ff2e06','終南幽居獻蘇侍郎三首時拜太祝未上 二','儲光羲','唐','唐诗','tang','','[]','中歲尚微道，始知將谷神。',84,'全唐诗/poet.tang.6000.json','["中歲尚微道，始知將谷神。", "抗策還南山，水木自相親。", "深林開一道，青嶂成四鄰。", "平明去采薇，日入行刈薪。", "雲歸萬壑暗，雪罷千崖春。", "始看玄鳥來，已見瑤華新。", "寄言搴芳者，無乃後時人。"]'),
('0d7cfedc-35ae-4cfb-9768-70571345db5c','終南幽居獻蘇侍郎三首時拜太祝未上 三','儲光羲','唐','唐诗','tang','','[]','卜築青巖裏，雲蘿四垂陰。',84,'全唐诗/poet.tang.6000.json','["卜築青巖裏，雲蘿四垂陰。", "虛室若無人，喬木自成林。", "時有清風至，側聞樵採音。", "鳳皇鳴南岡，望望隔層岑。", "既言山路遠，復道溪流深。", "偓佺空中遊，虯龍水間吟。", "何當見輕翼，爲我達遠心。"]'),
('d26ecc0e-2a13-45ba-8bf6-e8b333afcd0e','題應聖觀','儲光羲','唐','唐诗','tang','','[]','空中望小山，山下見餘雪。',96,'全唐诗/poet.tang.6000.json','["空中望小山，山下見餘雪。", "皎皎河漢女，在茲養真骨。", "登門駭天書，啓籥問仙訣。", "池光搖水霧，燈色連松月。", "合甎起花臺，折草成玉節。", "天雞弄白羽，王母垂玄髮。", "北有上年宮，一路在雲霓。", "上心方嚮道，時復朝金闕。"]'),
('08c5e20f-2f21-4f62-8e7f-0d1c4238606d','至閑居精舍呈正上人','儲光羲','唐','唐诗','tang','','[]','太室三招提，其趣皆不同。',96,'全唐诗/poet.tang.6000.json','["太室三招提，其趣皆不同。", "不同非一趣，況是天遊宮。", "雙嶺前夾門，閣道復橫空。", "寶坊若花積，宛轉不可窮。", "流泉自成池，清松信饒風。", "秋晏景氣逈，皛明丹素功。", "將近隱者鄰，遠與西山通。", "大師假惠照，念以息微躬。"]'),
('5481f438-f97a-496f-b2aa-33627742a098','酬綦毋校書夢耶溪見贈之作','儲光羲','唐','唐诗','tang','','[]','校文在仙掖，每有滄洲心。',96,'全唐诗/poet.tang.6000.json','["校文在仙掖，每有滄洲心。", "況以北窗下，夢遊清溪陰。", "春看湖水漫，夜入迴塘深。", "往往纜垂葛，出舟望前林。", "山人松下飯，釣客蘆中吟。", "小隱何足貴，長年固可尋。", "還車首東道，惠言若黃金。", "以我采薇意，傳之天姥岑。"]'),
('090bbd6f-73ea-4461-87d1-ff763bb36a09','田家即事','儲光羲','唐','唐诗','tang','','[]','蒲葉日已長，杏花日已滋。',96,'全唐诗/poet.tang.6000.json','["蒲葉日已長，杏花日已滋。", "老農要看此，貴不違天時。", "迎晨起飯牛，雙駕耕東菑。", "蚯蚓土中出，田烏隨我飛。", "羣合亂啄噪，嗷嗷如道飢。", "我心多惻隱，顧此兩傷悲。", "撥食與田烏，日暮空筐歸。", "親戚更相誚，我心終不移。"]'),
('fd3b61f9-7467-4d6f-b3f8-42324c85822e','同王十三維偶然作十首 一','儲光羲','唐','唐诗','tang','','[]','仲夏日中時，草木看欲燋。',84,'全唐诗/poet.tang.6000.json','["仲夏日中時，草木看欲燋。", "田家惜工力，把鋤來東臯。", "顧望浮雲陰，往往誤傷苗。", "歸來悲困極，兄嫂共相譊。", "無錢可沽酒，何以解劬勞？", "夜深星漢明，庭宇虛寥寥。", "高柳三五株，可以獨逍遙。"]'),
('f0d480e9-f100-4ebe-bb05-0de13d73113b','同王十三維偶然作十首 二','儲光羲','唐','唐诗','tang','','[]','北山種松柏，南山種蒺藜。',84,'全唐诗/poet.tang.6000.json','["北山種松柏，南山種蒺藜。", "出入雖同趣，所向各有宜。", "孔丘貴仁義，老氏好無爲。", "我心若虛空，此道將安施。", "暫過伊闕間，晼晚三伏時。", "高閣入雲中，芙蓉滿清池。", "要自非我室，還望南山陲。"]'),
('fb811375-9dfb-4b56-ad3c-2fa584180ac4','同王十三維偶然作十首 三','儲光羲','唐','唐诗','tang','','[]','野老本貧賤，冒暑鋤瓜田。',108,'全唐诗/poet.tang.6000.json','["野老本貧賤，冒暑鋤瓜田。", "一畦未及終，樹下高枕眠。", "荷蓧者誰子，皤皤來息肩。", "不復問鄉墟，相見但依然。", "腹中無一物，高話羲皇年。", "落日臨層隅，逍遙望晴川。", "使婦提蠶筐，呼兒榜漁船。", "悠悠泛綠水，去摘浦中蓮。", "蓮花豔且美，使我不能還。"]'),
('2d233e41-411e-4e28-b7bd-302fbee385e7','同王十三維偶然作十首 四','儲光羲','唐','唐诗','tang','','[]','浮雲在虛空，隨風復卷舒。',96,'全唐诗/poet.tang.6000.json','["浮雲在虛空，隨風復卷舒。", "我心方處順，動作何憂虞。", "但言嬰世網，不復得間居。", "迢遞別東國，超遙來西都。", "見人乃恭敬，曾不問賢愚。", "雖若不能言，中心亦難誣。", "故鄉滿親戚，道遠情日疎。", "偶欲陳此意，復無南飛鳧。"]'),
('1c20c3f6-8146-4946-ae6f-8d7596196165','同王十三維偶然作十首 五','儲光羲','唐','唐诗','tang','','[]','草木花葉生，相與命爲春。',72,'全唐诗/poet.tang.6000.json','["草木花葉生，相與命爲春。", "當非草木意，信是故時人。", "靜念惻羣物，何由知至真。", "狂歌問夫子，夫子莫能陳。", "鳳皇飛且鳴，容裔下天津。", "清淨無言語，茲焉庶可親。"]'),
('65401677-a0e6-4d31-932f-eb958779a2f0','同王十三維偶然作十首 六','儲光羲','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河流向東，弱水流向西。',108,'全唐诗/poet.tang.6000.json','["黃河流向東，弱水流向西。", "趨舍各有異，造化安能齊。", "妾本邯鄲女，生長在叢臺。", "既聞容見寵，復想玄爲妻。", "刻畫尚風流，幸會君招攜。", "逶迤歌舞座，婉孌芙蓉閨。", "日月方向除，恩愛忽焉暌。", "棄置誰復道，但悲生不諧。", "羨彼匹婦意，偕老常同棲。"]'),
('e93a8da2-85de-45dc-bacc-8f1ac591eba3','同王十三維偶然作十首 七','儲光羲','唐','唐诗','tang','','[]','日暮登春山，山鮮雲復輕。',72,'全唐诗/poet.tang.6000.json','["日暮登春山，山鮮雲復輕。", "遠近看春色，踟躕新月明。", "仙人浮丘公，對月時吹笙。", "丹鳥飛熠熠，蒼蠅亂營營。", "羣動汩吾真，訛言傷我情。", "安得如子晉，與之遊太清。"]'),
('f558ee81-6086-4c77-beea-594e062259a7','同王十三維偶然作十首 八','儲光羲','唐','唐诗','tang','','[]','耽耽銅鞮宮，遙望長數里。',96,'全唐诗/poet.tang.6000.json','["耽耽銅鞮宮，遙望長數里。", "賓客無多少，出入皆珠履。", "樸儒亦何爲，辛苦讀舊史。", "不道無家舍，效他養妻子。", "冽冽玄冬暮，衣裳無準擬。", "偶然著道書，神人養生理。", "公卿時見賞，賜賚難具紀。", "莫問身後事，且論朝夕是。"]'),
('f310916a-38d5-4493-a022-e8332a163322','同王十三維偶然作十首 九','儲光羲','唐','唐诗','tang','','[]','空山暮雨來，衆鳥竟棲息。',84,'全唐诗/poet.tang.6000.json','["空山暮雨來，衆鳥竟棲息。", "斯須照夕陽，雙雙復撫翼。", "我念天時好，東田有稼穡。", "浮雲蔽川原，新流集溝洫。", "裴回顧衡宇，僮僕邀我食。", "臥覽牀頭書，睡看機中織。", "想見明膏煎，中夜起唧唧。"]'),
('165f3bc8-57e6-4046-88a2-f0325b7081c7','同王十三維偶然作十首 十','儲光羲','唐','唐诗','tang','','[]','四鄰競豐屋，我獨好卑室。',96,'全唐诗/poet.tang.6000.json','["四鄰競豐屋，我獨好卑室。", "窈窕高臺中，時聞撫新瑟。", "狂飆動地起，拔木乃非一。", "相顧始知悲，中心憂且慄。", "蚩蚩命子弟，恨不居高秩。", "日入賓從歸，清晨冠蓋出。", "中庭有奇樹，榮早衰復疾。", "此道猶不知，微言安可述。"]'),
('c2daf737-459a-485c-b970-96d7ddc460e8','昇天行貽盧六健','儲光羲','唐','唐诗','tang','','["\u5e90\u5c71"]','真人居閬風，時奏清商音。',120,'全唐诗/poet.tang.6000.json','["真人居閬風，時奏清商音。", "聽者即王母，泠泠和瑟琴。", "坐對三花枝，行隨五雲陰。", "天長崑崙小，日久蓬萊深。", "上由玉華宮，下視首陽岑。", "神州亦清淨，要自有浮沈。", "惻惻苦哉行，呱呱遊子吟。", "廬山逢若士，思欲化黃金。", "雨雪沒太山，誰能無歸心。", "逍遙在雲漢，可以來相尋。"]'),
('e1f7e0de-a0ed-49e7-9f58-e29273d52c87','田家雜興八首 一','儲光羲','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','春至鶬鶊鳴，薄言向田墅。',84,'全唐诗/poet.tang.6000.json','["春至鶬鶊鳴，薄言向田墅。", "不能自力作，黽勉娶鄰女。", "既念生子孫，方思廣田圃。", "閑時相顧笑，喜悅好禾黍。", "夜夜登嘯臺，南望洞庭渚。", "百草被霜露，秋山響砧杵。", "却羨故年時，中情無所取。"]'),
('459aa485-e005-4fce-8ce2-98dc25417d9d','田家雜興八首 二','儲光羲','唐','唐诗','tang','','[]','衆人恥貧賤，相與尚膏腴。',84,'全唐诗/poet.tang.6000.json','["衆人恥貧賤，相與尚膏腴。", "我情既浩蕩，所樂在畋漁。", "山澤時晦暝，歸家蹔閑居。", "滿園植葵藿，繞屋樹桑榆。", "禽雀知我閑，翔集依我廬。", "所願在優游，州縣莫相呼。", "日與南山老，兀然傾一壺。"]'),
('88e3e2c9-c6b3-4413-9fff-43c222118164','田家雜興八首 三','儲光羲','唐','唐诗','tang','','[]','逍遙阡陌上，遠近無相識。',84,'全唐诗/poet.tang.6000.json','["逍遙阡陌上，遠近無相識。", "落日照秋山，千巖同一色。", "網罟繞深莽，鷹鸇始輕翼。", "獵馬既如風，奔獸莫敢息。", "駐旗滄海上，犒士吳宮側。", "楚國有夫人，性情本貞直。", "鮮禽徒自致，終歲竟不食。"]'),
('6585b742-5745-45dc-a4e3-3df3ac3efbf4','田家雜興八首 四','儲光羲','唐','唐诗','tang','','[]','田家趨壠畝，當晝掩虛關。',84,'全唐诗/poet.tang.6000.json','["田家趨壠畝，當晝掩虛關。", "鄰里無煙火，兒童共幽閑。", "桔槔懸空圃，雞犬滿桑間。", "時來農事隙，採藥遊名山。", "但言所採多，不念路險艱。", "人生如蜉蝣，一往不可攀。", "君看西王母，千載美容顏。"]'),
('bd025c4a-1535-49bc-934b-30e1a9e5dbd8','田家雜興八首 五','儲光羲','唐','唐诗','tang','','[]','平生養情性，不復計憂樂。',84,'全唐诗/poet.tang.6000.json','["平生養情性，不復計憂樂。", "去家行賣畚，留滯南陽郭。", "秋至黍苗黃，無人可刈獲。", "稚子朝未飯，把竿逐鳥雀。", "忽見梁將軍，乘車出宛洛。", "意氣軼道路，光輝滿墟落。", "安知負薪者，咥咥笑輕薄。"]'),
('5df45fd4-9419-476d-88ef-28718330e3b5','田家雜興八首 六','儲光羲','唐','唐诗','tang','','[]','楚山有高士，梁國有遺老。',72,'全唐诗/poet.tang.6000.json','["楚山有高士，梁國有遺老。", "築室既相鄰，向田復同道。", "糗糒常共飯，兒孫每更抱。", "忘此耕耨勞，媿彼風雨好。", "蟪蛄鳴空澤，鶗鴂傷秋草。", "日夕寒風來，衣裳苦不早。"]'),
('9702a6a1-f1c5-4f0a-a8c4-e878c4a26bd6','田家雜興八首 七','儲光羲','唐','唐诗','tang','','[]','梧桐蔭我門，薜荔網我屋。',72,'全唐诗/poet.tang.6000.json','["梧桐蔭我門，薜荔網我屋。", "迢迢兩夫婦，朝出暮還宿。", "稼穡既自種，牛羊還自牧。", "日旰懶耕鋤，登高望川陸。", "空山足禽獸，墟落多喬木。", "白馬誰家兒，聯翩相馳逐。"]'),
('fa586f05-a04e-4f05-aed5-4ccb9138286a','田家雜興八首 八','儲光羲','唐','唐诗','tang','','[]','種桑百餘樹，種黍三十畝。',96,'全唐诗/poet.tang.6000.json','["種桑百餘樹，種黍三十畝。", "衣食既有餘，時時會親友。", "夏來菰米飯，秋至菊花酒。", "孺人喜逢迎，稚子解趨走。", "日暮閑園裏，團團蔭榆柳。", "酩酊乘夜歸，涼風吹戶牖。", "清淺望河漢，低昂看北斗。", "數甕猶未開，明朝能飲否。"]'),
('87ba9e30-c02a-4744-9b2d-e909dc327f76','題辨覺精舍','儲光羲','唐','唐诗','tang','','[]','朝隨秋雲陰，乃至青松林。',48,'全唐诗/poet.tang.6000.json','["朝隨秋雲陰，乃至青松林。", "花閣空中遠，方池巖下深。", "竹風亂天語，溪響成龍吟。", "試問真君子，遊山非世心。"]'),
('ace56877-719a-48dc-ae06-118d4efc5847','題慎言法師故房','儲光羲','唐','唐诗','tang','','[]','精廬不住子，自有無生鄉。',48,'全唐诗/poet.tang.6000.json','["精廬不住子，自有無生鄉。", "過客知何道，裴回雁子堂。", "浮雲歸故嶺，落月還西方。", "日夕虛空裏，時時聞異香。"]'),
('964a27c9-2542-4bcb-9709-13879feab772','石甕寺','儲光羲','唐','唐诗','tang','','[]','遙山起真宇，西向盡花林。',48,'全唐诗/poet.tang.6000.json','["遙山起真宇，西向盡花林。", "下見宮殿小，上看廊廡深。", "苑花落池水，天語聞松音。", "君子又知我，焚香期化心。"]'),
('253ce3b8-e3a2-4c94-85b1-d9901a7a69f9','題崔山人別業','儲光羲','唐','唐诗','tang','','[]','南陽隱居者，築室丹溪源。',74,'全唐诗/poet.tang.6000.json','["南陽隱居者，築室丹溪源。", "溪冷懼秋[晏]，室寒欣景暾。", "山雞鳴菌閣，水霧入衡門。", "東嶺或舒嘯，北窗時討論。", "封君渭陽竹，逸士漢陰園。", "何必崆峒上，獨爲堯所尊。"]'),
('3026c473-d37c-4051-af18-ef705b588556','行次田家澳梁作','儲光羲','唐','唐诗','tang','','[]','田家俯長道，邀我避炎氛。',72,'全唐诗/poet.tang.6000.json','["田家俯長道，邀我避炎氛。", "當暑日方晝，高天無片雲。", "桑間禾黍氣，柳下牛羊羣。", "野雀棲空屋，晨昏不復聞。", "前登澳梁坂，極望溫泉分。", "逆旅方三舍，西山猶未曛。"]'),
('ba8dac79-354e-4719-86e3-b38da53c5ec0','昭聖觀','儲光羲','唐','唐诗','tang','','[]','主家隱溪口，微路入花源。',96,'全唐诗/poet.tang.6000.json','["主家隱溪口，微路入花源。", "數日朝青閣，彩雲猶在門。", "雙樓夾一殿，玉女侍玄元。", "扶橑盡蟠木，步櫩多畫繙。", "新松引天籟，小柏繞山樊。", "坐弄竹陰遠，行隨溪水喧。", "石池辨春色，林獸知人言。", "未逐鳳皇去，真宮在此原。"]'),
('47d5f864-fb65-4a22-9141-1d8db778dd6a','題辛道士房','儲光羲','唐','唐诗','tang','','[]','全神不言命，所尚道家流。',96,'全唐诗/poet.tang.6000.json','["全神不言命，所尚道家流。", "迨此遠南楚，遂令思北遊。", "先生秀衡嶽，玉立居玄丘。", "門帶江山靜，房隨瑤草幽。", "逍遙三花發，罔象五雲浮。", "自有太清紀，曾垂華髮憂。", "大年方橐籥，小智即蜉蝣。", "七日赤龍至，莫令余獨留。"]'),
('8aa34b2b-7216-41a4-8453-892834425b91','登秦嶺作時陷賊歸國','儲光羲','唐','唐诗','tang','','[]','朝出猛獸林，躨跜登高峰。',156,'全唐诗/poet.tang.6000.json','["朝出猛獸林，躨跜登高峰。", "僮僕履雲霧，隨我行太空。", "羲和舒靈暉，倏忽西極通。", "迴首望涇渭，隱隱如長虹。", "九逵合蒼蕪，五陵遙瞳矇。", "鹿遊大明殿，霧濕華清宮。", "網羅蠛蠓時，顧齒熊羆鋒。", "失途走江漢，不能有其功。", "氣逐招遙星，魂隨閶闔風。", "惟言宇宙清，復使車書同。", "林木被繁霜，合沓連山紅。", "鵬鶚勵羽翼，俯視荆棘叢。", "誓將食鶬鴞，然後歸崆峒。"]'),
('3c0107ff-92eb-4f0b-abda-35be6cc580f4','晦日任橋池亭','儲光羲','唐','唐诗','tang','','[]','溫泉作天邑，直北開新洲。',72,'全唐诗/poet.tang.6000.json','["溫泉作天邑，直北開新洲。", "未有菰蒲生，即聞鳧雁遊。", "六亭在高岸，數島居中流。", "晦日望清波，相與期泛游。", "西道苦轉轂，北隄疲行舟。", "清泠水木陰，纔可適我憂。"]'),
('14c40953-f8d5-49cc-850d-1710256dd7e7','望幸亭','儲光羲','唐','唐诗','tang','','[]','五年一巡狩，西幸過東畿。',96,'全唐诗/poet.tang.6000.json','["五年一巡狩，西幸過東畿。", "周國易居守，周人多怨思。", "君王敷惠政，程作貴從時。", "大廈非一木，沈沈臨九逵。", "慶雲宿飛棟，嘉樹羅青墀。", "疎屏宜朝享，方塘堪水嬉。", "雲中仰華蓋，桁下望春旗。", "天意知如此，星言歸洛師。"]'),
('04b32c17-108e-4d4f-b347-07b2017cb0c8','哥舒大夫頌德','儲光羲','唐','唐诗','tang','','[]','天紀啓真命，君生臣亦生。',264,'全唐诗/poet.tang.6000.json','["天紀啓真命，君生臣亦生。", "乃知赤帝子，復有蒼龍精。", "神武建皇極，文昌開將星。", "超超渭濱器，落落山西名。", "畫閫入受脤，鑿門出扞城。", "戎人昧正朔，我有軒轅兵。", "隴路起豐鎬，關雲隨斾旌。", "河湟訓兵甲，義勇方橫行。", "韓魏多銳士，蹶張在幕庭。", "大非四決軋，石堡高崢嶸。", "攻伐若振槁，孰云非神明。", "嘉謀即天意，驟勝由師貞。", "枯草被西陸，烈風昏太清。", "戢戈旄頭落，牧馬崑崙平。", "賓從儼冠蓋，封山紀天聲。", "來朝芙蓉闕，鳴玉飄華纓。", "直道濟時憲，天邦遂輕刑。", "抗書報知己，松柏亦以榮。", "嘉命列上第，德輝照天京。", "在車持簡墨，粲粲皆詞英。", "顧我搶榆者，莫能翔青冥。", "遊燕非騏驥，躑躅思長鳴。"]'),
('18f03b07-b9da-4191-96f7-506e48b4426c','安宜園林獻高使君','儲光羲','唐','唐诗','tang','','[]','直道已三出，幸從江上迴。',72,'全唐诗/poet.tang.6000.json','["直道已三出，幸從江上迴。", "新居茅茨逈，起見秋雲開。", "十里次舟楫，二橋交往來。", "楚言滿鄰里，鴈呌喧池臺。", "魚鱉樂仁政，浮沈亦至哉。", "小山宜大隱，要自望蓬萊。"]'),
('399c7e64-bbbc-49b6-8e2c-fbcd948c7702','','儲光羲','唐','唐诗','tang','','["\u6cf0\u5c71"]','伊昔好觀國，自鄉西入秦。',240,'全唐诗/poet.tang.6000.json','["伊昔好觀國，自鄉西入秦。", "往復萬餘里，相逢皆衆人。", "大君幸東嶽，世哲扈時巡。", "予亦從此去，閑居清洛濱。", "稍稍寒木直，彩彩陽華新。", "迭宕孔文舉，風流石季倫。", "妙年一相得，白首定相親。", "重此虛賓館，歡言冬及春。", "哲兄盛文史，出入馳高軌。", "令德本同人，深心重知己。", "絳衣朝聖主，紗帳延才子。", "伯淮與季江，清濬各孤峙。", "羣芳趨汎愛，萬物通情理。", "而我信空虛，提攜過杞梓。", "夫君美聲德，直道期終始。", "孰謂忽離居，優游鄭東里。", "東里近王城，山連路亦平。", "何言相去遠，閑言獨淒清。", "萬里鴻鴈度，四鄰砧杵鳴。", "其如久離別，重以霜風驚。"]'),
('faf8ce54-5add-41a6-b5f8-471bed171906','河中望鳥灘作貽呂四郎中','儲光羲','唐','唐诗','tang','','[]','河流有深曲，舟子莫能知。',72,'全唐诗/poet.tang.6000.json','["河流有深曲，舟子莫能知。", "弭棹臨沙嶼，微吟西日馳。", "平明春色霽，兩岸好風吹。", "去去川途盡，悠悠親友離。", "漢宮成羽翼，伊水弄參差。", "爲惜淮南子，如何攀桂枝。"]'),
('e0976ddc-93c3-4780-97e6-82f14a17455b','秦中初霽獻給事二首 一','儲光羲','唐','唐诗','tang','','[]','渭水收暮雨，處處多新澤。',72,'全唐诗/poet.tang.6000.json','["渭水收暮雨，處處多新澤。", "宮苑傍山明，雲林帶天碧。", "君子聳高駕，英聲邈今昔。", "鏘珮出中臺，彯纓入仙掖。", "夙心幸清鑒，晚志欣良覿。", "鳴盜非足徵，願言同下客。"]'),
('d26181f5-dde5-471b-ac85-d333b2a51461','秦中初霽獻給事二首 二','儲光羲','唐','唐诗','tang','','[]','南國久爲思，西都嘗作賓。',72,'全唐诗/poet.tang.6000.json','["南國久爲思，西都嘗作賓。", "雲開天地色，日照山河春。", "善聽在知己，揚光唯達人。", "妙年弄柔翰，弱冠偶良晨。", "擢第文昌閣，還家滄海濱。", "寸心何所望，東掖有賢臣。"]'),
('9ac969fb-ba17-4247-a7d8-d169e86d7d2e','晚次東亭獻鄭州宋使君文','儲光羲','唐','唐诗','tang','','[]','自初賓上國，乃到鄒人鄉。',288,'全唐诗/poet.tang.6000.json','["自初賓上國，乃到鄒人鄉。", "曾點與曾子，俱升闕里堂。", "武皇恢大略，逸翮思寥廓。", "三居清憲臺，兩拜文昌閣。", "爲道既貞信，處名猶謇諤。", "鐵柱勵風威，錦軸含光輝。", "夜聞持簡立，朝看伏奏歸。", "洞門清珮響，廣路玉珂飛。", "驤首入丹掖，摶空趨太微。", "絲綸逢聖主，出入飄華組。", "愔愔宿帝梧，侃侃居文府。", "海內語三獨，朝端謀六戶。", "善計在弘羊，清嚴歸仲舉。", "侍郎跨方朔，中丞蔑周處。", "天眷擇循良，惟賢降寵章。", "分符指聊攝，爲政本農桑。", "籍籍歌五袴，祁祁頌千箱。", "隨車微雨灑，逐扇清風颺。", "既以遷列國，復茲鄰帝鄉。", "褰帷乃仍舊，坐嘯非更張。", "居敬物無擾，履端人自康。", "薄遊出京邑，引領東南望。", "林晚鳥雀噪，田秋稼穡黃。", "成臯天地險，廣武征戰場。"]'),
('6e60e06f-4062-4c72-bddb-0d151a79d9d2','秋次霸亭寄申大','儲光羲','唐','唐诗','tang','','[]','橘柚植寒陵，芙蓉蔕脩坂。',132,'全唐诗/poet.tang.6000.json','["橘柚植寒陵，芙蓉蔕脩坂。", "無言不得意，得意何由展。", "況我行且徒，而君往猶蹇。", "既傷人事近，復言天道遠。", "薄暮入空亭，中夜不能飯。", "南聽鴻雁盡，西見招搖轉。", "千門漢主宮，百里周王苑。", "杲杲初景出，油油鮮雲卷。", "會朝幸歲正，校獵從新獮。", "念君久京國，雙涕如露泫。", "無人薦子雲，太息竟誰辨。"]'),
('fb81e391-0ffb-4754-abdc-f7440fea887e','舟中別武金壇','儲光羲','唐','唐诗','tang','','[]','曰予輕皎潔，坦率賓混元。',120,'全唐诗/poet.tang.6000.json','["曰予輕皎潔，坦率賓混元。", "忽乃異羣萃，高歌信陵門。", "信陵好賓客，清夜開華軒。", "月光麗池閣，野氣浮林園。", "偶坐爛明星，歸志潛崩奔。", "漾舟清潭裏，慰我別離魂。", "落日下西山，左右慘無言。", "蕭條風雨散，窅靄江湖昏。", "秋荷尚幽鬱，暮鳥復翩翻。", "紙筆亦何爲，寫我心中冤。"]'),
('9875f97a-9765-4529-bd9a-1a6b1243ede8','鞏城東莊道中作','儲光羲','唐','唐诗','tang','','[]','北陵散寒鳥，西山照初日。',144,'全唐诗/poet.tang.6000.json','["北陵散寒鳥，西山照初日。", "婉孌晉陽京，踟躕野人室。", "南軒草間去，後乘林中出。", "靄靄長路暖，遲遲狹路歸。", "蜉蝣時蔽月，枳棘復傷衣。", "城上東風起，河邊早雁飛。", "夏王紀冬令，殷人乃正月。", "涯口度新雲，山陰留故雪。", "幸逢耆耋話，餘待親隣別。", "總轡出叢薄，歇鞍登峻隅。", "春源既蕩漭，伏戰亦睢盱。", "未獲遵平道，徒言信薄夫。"]'),
('5483dafa-09b1-4349-9719-b50f785b5916','赴馮翊作','儲光羲','唐','唐诗','tang','','[]','本自江海人，且無寥廓志。',120,'全唐诗/poet.tang.6000.json','["本自江海人，且無寥廓志。", "大明耀天宇，靄靄風雨被。", "迢遞別荆吳，飄颻涉沂泗。", "廣川俟舟檝，峻坂傷騏驥。", "蹭蹬失歸道，崎嶇從下位。", "西出太華陰，北走少梁地。", "葱蘢墟落色，泱漭關河氣。", "恥從俠烈遊，甘爲刀筆吏。", "寶劒茱萸匣，豈忘知音貴。", "大道且泛然，沈浮未云異。"]'),
('f75eac14-cd7a-49d2-b9ea-f9f3b29466fd','晚霽中園喜赦作','儲光羲','唐','唐诗','tang','','[]','五月黃梅時，陰氣蔽遠邇。',108,'全唐诗/poet.tang.6000.json','["五月黃梅時，陰氣蔽遠邇。", "濃雲連晦朔，菰菜生隣里。", "落日燒霞明，農夫知雨止。", "幾悲衽席濕，長歎垣牆毀。", "曭朗天宇開，家族躍以喜。", "渙汗發大號，坤元更資始。", "散衣出中園，小徑尚滑履。", "池光搖萬象，倏忽滅復起。", "嘉樹如我心，欣欣豈云已。"]'),
('505ef721-ace4-41b5-852c-07bbb6f7971a','觀范陽遞俘','儲光羲','唐','唐诗','tang','','[]','北河旄星隕，鬼方獮林胡。',120,'全唐诗/poet.tang.6000.json','["北河旄星隕，鬼方獮林胡。", "羣師舞弓矢，電發歸燕墟。", "皇皇軒轅君，贊贊臯陶謨。", "方思壯軍實，遠近遞生俘。", "車馬踐大逵，合沓成深渠。", "牧人過橐駞，校正引騊駼。", "烈風朝送寒，雲雪靄天隅。", "草木同一色，誰能辨榮枯。", "四履封元戎，百金酬勇夫。", "大邦武功爵，固與炎皇殊。"]'),
('bab79fe6-65bb-4ff6-a1ea-08cf632d5555','次天元十載華陰發兵作時有郎官點發','儲光羲','唐','唐诗','tang','','[]','鬼方生獫狁，時寇盧龍營。',108,'全唐诗/poet.tang.6000.json','["鬼方生獫狁，時寇盧龍營。", "帝念霍嫖姚，詔發咸林兵。", "天星下文閣，簡師臨我城。", "三陌觀勇夫，五餌謀長纓。", "雷野大車發，震雲靈鼓鳴。", "太華色莽蒼，清渭風交橫。", "胡馬悲雨雪，詩人歌斾旌。", "閼氏爲女奴，單于作邊氓。", "神皇麒麟閣，大將不書名。"]'),
('a1b346e9-fed6-4c8a-9cd8-5aba1440c90a','送丘健至州敕放作時任下邽縣','儲光羲','唐','唐诗','tang','','[]','太史登觀臺，天街耀旄頭。',144,'全唐诗/poet.tang.6000.json','["太史登觀臺，天街耀旄頭。", "大君忽霆震，詔爵冠軍侯。", "南必梁孫源，西將圉崑丘。", "河隴徵擊卒，虎符到我州。", "朝集咸林城，師言亂啁啾。", "殺氣變木德，凜凜如高秋。", "元戎啓神皇，廟堂發嘉謀。", "息兵業稼穡，歸馬復休牛。", "和風開陰雪，大耀中天流。", "歡聲殷河嶽，涵盪非煙浮。", "邦牧新下車，德禮彼甿謳。", "乾坤日交泰，吾亦遂優游。"]'),
('0205f595-4a09-4565-b078-f76d010f28d9','登商丘','儲光羲','唐','唐诗','tang','','[]','河水日夜流，客心多殷憂。',72,'全唐诗/poet.tang.6000.json','["河水日夜流，客心多殷憂。", "維梢歷宋國，結纜登商丘。", "漢皇封子弟，周室命諸侯。", "搖搖世祀怨，傷古復兼秋。", "鳴鴻念極浦，征旅慕前儔。", "太息梁王苑，時非牧馬遊。"]'),
('7f2b7fba-a42e-465c-a238-8ae1af4a274a','羣鴉詠','儲光羲','唐','唐诗','tang','','[]','新宮驪山陰，龍衮時出豫。',108,'全唐诗/poet.tang.6000.json','["新宮驪山陰，龍衮時出豫。", "朝陽照羽儀，清吹肅逵路。", "羣鴉隨天車，夜滿新豐樹。", "所思在腐餘，不復憂霜露。", "河低宮閣深，燈影鼓鐘曙。", "繽紛集寒枝，矯翼時相顧。", "冢宰收琳琅，侍臣盡鴛鷺。", "高舉摩太清，永絕矰繳懼。", "茲禽亦翱翔，不以微小故。"]'),
('f902d2ee-a480-4520-84cd-ce523ed5619e','尚書省受誓誡貽太廟裴丞','儲光羲','唐','唐诗','tang','','[]','皇家有恆憲，齋祭崇明祀。',72,'全唐诗/poet.tang.6000.json','["皇家有恆憲，齋祭崇明祀。", "嚴車伊洛間，受誓文昌裏。", "沈沈雲閣見，稍稍城烏起。", "曙色照衣冠，虛庭鳴劒履。", "裴回念私覿，悵望臨清汜。", "點翰欲何言，相思從此始。"]'),
('a977d1b2-a874-43f4-b6db-9c2850647219','夏日尋藍田唐丞登高宴集','儲光羲','唐','唐诗','tang','','[]','東望春明門，駕言聊出遊。',120,'全唐诗/poet.tang.6000.json','["東望春明門，駕言聊出遊。", "南行小徑盡，綠竹臨清流。", "君出罷六安，居此澹忘憂。", "園林與城市，閭里隨人幽。", "披顏闢衡闈，置酒登崇丘。", "山河臨咫尺，宇宙窮寸眸。", "是時春載陽，佳氣滿皇州。", "宮殿碧雲裏，鴛鴦初命儔。", "良辰方在茲，志士安得休。", "成名苟有地，何必東陵侯。"]'),
('9203a594-a988-4f2e-a870-da54a4071852','田家即事答崔二東臯作四首 一','儲光羲','唐','唐诗','tang','','[]','玄鳥雙雙飛，杏林初發花。',36,'全唐诗/poet.tang.6000.json','["玄鳥雙雙飛，杏林初發花。", "喣媮命僮僕，可以樹桑麻。", "清旦理犂鋤，日入未還家。"]'),
('cfecc769-7b16-4174-8bca-8c5ef1d504a4','田家即事答崔二東臯作四首 二','儲光羲','唐','唐诗','tang','','[]','有客山中至，言傳故人訊。',36,'全唐诗/poet.tang.6000.json','["有客山中至，言傳故人訊。", "蕩漾敷遠情，飄颻吐清韻。", "猗歟春臯上，無乃成秋興。"]'),
('b7ac5454-1f7d-4a40-ad7d-5c4ba301aebe','田家即事答崔二東臯作四首 三','儲光羲','唐','唐诗','tang','','[]','念別求須臾，忽至嚶鳴時。',36,'全唐诗/poet.tang.6000.json','["念別求須臾，忽至嚶鳴時。", "菜田燒故草，初樹養新枝。", "所寓非幽深，夢寐相追隨。"]'),
('f4d20c8b-0fa9-4bf2-b419-a5d7cc7e1fb7','田家即事答崔二東臯作四首 四','儲光羲','唐','唐诗','tang','','[]','依依親隴畝，寂寂無隣里。',36,'全唐诗/poet.tang.6000.json','["依依親隴畝，寂寂無隣里。", "不聞雞犬音，日見和風起。", "賴君遺掞藻，憂來散能弭。"]'),
('3ad23a83-95f4-4e06-8db2-b36c6844a1e2','敬酬陳掾親家翁秋夜有贈','儲光羲','唐','唐诗','tang','','[]','大姬配胡公，位乃三恪賓。',288,'全唐诗/poet.tang.6000.json','["大姬配胡公，位乃三恪賓。", "盛德百代祀，斯言良不泯。", "敬仲爲齊卿，當國名益震。", "仲舉登宰輔，太丘榮縉紳。", "武皇受瑤圖，爵士封其新。", "繁祉既驟集，裔孫生賢臣。", "特達踰珪璋，節操方松筠。", "雲漢一矯翼，天池三振鱗。", "曳裾朝赤墀，酌醴侍紫宸。", "大君錫車馬，時復過平津。", "言則廣台階，道亦資天均。", "清秋忽高興，震藻若有神。", "曜曜趨宮廷，洸洸邁徐陳。", "鎬京既賜第，門巷交朱輪。", "方將襲伊臯，永以崇夏殷。", "宗黨無遠近，敬恭依仁人。", "雪盡宇宙暄，雁歸滄海春。", "沈吟白華頌，帝闥降絲綸。", "驛騎及蕪城，相逢在郊鄄。", "別離曠南北，譴謫罹苦辛。", "晝遊還荆吳，迷方客咸秦。", "惟賢惠重義，男女期嘉姻。", "梧桐生朝陽，鶗鴂鳴蕭晨。", "豈不畏時暮，坎壈無與鄰。"]'),
('ad5e3d68-fb99-48d2-8fd1-dadc54b78589','蘇十三瞻登玉泉寺峰入寺中見贈作','儲光羲','唐','唐诗','tang','','[]','慶門疊華組，盛列鍾英彥。',276,'全唐诗/poet.tang.6000.json','["慶門疊華組，盛列鍾英彥。", "貞信發天姿，文明叶邦選。", "爲情貴深遠，作德齊隱見。", "別業在春山，懷歸出芳甸。", "逖聽多時友，招邀及浮賤。", "朝沿霸水窮，暮矚藍田徧。", "百花照阡陌，萬木森鄉縣。", "澗淨綠蘿深，巖暄新鳥轉。", "依然造華薄，豁爾開靈院。", "淹留火禁辰，愉樂弦歌宴。", "肅肅列樽俎，鏘鏘引纓弁。", "天籟激微風，陽光轢奔箭。", "以茲小人腹，不勝君子饌。", "是日既低迷，中宵方眄眩。", "枕上思獨往，胸中理交戰。", "碧雲暗雨來，舊原芳色變。", "歡然自此絕，心賞何由見。", "鴻濛已笑雲，列缺仍揮電。", "忽與去人遠，俄逢歸者便。", "想像玉泉宮，依稀明月殿。", "峰巒如登陟，水木以遊衍。", "息心幸自忘，點翰仍留眷。", "恨無荆文璧，以答丹青絢。"]'),
('9cb78293-4fd2-4b86-9433-de4e0420c275','酬李處士山中見贈','儲光羲','唐','唐诗','tang','','[]','厥初遊太學，相與極周旋。',192,'全唐诗/poet.tang.6000.json','["厥初遊太學，相與極周旋。", "含采共朝暮，知言同古先。", "孟陽題劒閣，子雲獻甘泉。", "斯須曠千里，婉娩將十年。", "今來豔陽月，好鳥鳴翩翩。", "同聲既求友，不肖亦懷賢。", "引領遲芳信，果枉瑤華篇。", "成頌非其德，高文徒自妍。", "聲塵邈超越，比興起孤絕。", "始信郢中人，乃能歌白雪。", "跂予北堂夜，搖筆酬明哲。", "綠竹動清風，層軒靜華月。", "想像南山下，恬然謝朝列。", "猶恐鶗鴂鳴，坐看芳草歇。", "邀以青松色，同之白華潔。", "永願登龍門，相將持此節。"]'),
('db3780c5-9cb8-4eee-9eb5-e934cc17cbe6','同諸公秋日遊昆明池思古','儲光羲','唐','唐诗','tang','','[]','僕人理車騎，西出金光逵。',288,'全唐诗/poet.tang.6000.json','["僕人理車騎，西出金光逵。", "蒼蒼白帝郊，我將遊靈池。", "太陰連晦朔，雨與天根違。", "淒風披田原，橫汙益山陂。", "農畯盡顛沛，顧望稼穡悲。", "皇靈惻羣甿，神政張天維。", "坤紀戮屏翳，元綱扶逶迤。", "迴塘清滄流，大曜懸金暉。", "秋色浮渾沌，清光隨漣漪。", "豫章盡莓苔，柳杞成枯枝。", "驟聞漢天子，征彼西南夷。", "伐棘開洪淵，秉旄訓我師。", "震雲靈鼉鼓，照水蛟龍旂。", "銳士千萬人，猛氣如熊羆。", "刑罰一以正，干戈自有儀。", "坐作河漢傾，進退樓船飛。", "羽發鴻鴈落，檜動芙蓉披。", "峨峨三雲宮，肅肅振旅歸。", "惡德忽小醜，器用窮地貲。", "上兵貴伐謀，此道不能爲。", "吁哉蒸人苦，始曰征伐非。", "穆穆軒轅朝，耀德守方陲。", "君臣日安閑，遠近無怨思。", "石鯨既蹭蹬，女牛亦流離。"]'),
('bb2e729e-893d-47ab-b48d-c417fd2ccd16','同諸公登慈恩寺塔','儲光羲','唐','唐诗','tang','','[]','金祠起真宇，直上青雲垂。',132,'全唐诗/poet.tang.6000.json','["金祠起真宇，直上青雲垂。", "地靜我亦閑，登之秋清時。", "蒼蕪宜春苑，片碧昆明池。", "誰道天漢高，逍遙方在茲。", "虛形賓太極，攜手行翠微。", "雷雨傍杳冥，鬼神中躨跜。", "靈變在倏忽，莫能窮天涯。", "冠上閶闔開，履下鴻雁飛。", "宮室低邐迤，羣山小參差。", "俯仰宇宙空，庶隨了義歸。", "崱屴非大廈，久居亦以危。"]'),
('c533f5cd-a633-4e8a-a9b9-e79a4b7a8a4b','同諸公秋霽曲江俯見南山','儲光羲','唐','唐诗','tang','','[]','天靜終南高，俯暎江水明。',134,'全唐诗/poet.tang.6000.json','["天靜終南高，俯暎江水明。", "有若蓬萊下，淺深見澄瀛。", "羣峰懸中流，石壁如瑤瓊。", "魚龍隱蒼翠，鳥獸遊清泠。", "菰蒲林下秋，薜荔波中輕。", "山戛浴蘭阯，水若居雲屏。", "嵐氣浮渚宮，孤光隨曜靈。", "陰陰豫章館，宛宛百花亭。", "大君及羣臣，[宴]樂方嚶鳴。", "吾黨二三子，蕭辰怡性情。", "逍遙滄洲時，乃在長安城。"]'),
('fc0ffb23-73ca-4334-8999-cf98a30db468','同諸公送李雲南伐蠻','儲光羲','唐','唐诗','tang','','[]','昆明濱滇池，蠢爾敢逆常。',240,'全唐诗/poet.tang.6000.json','["昆明濱滇池，蠢爾敢逆常。", "天星耀鈇鑕，弔彼西南方。", "冢宰統元戎，太守齒軍行。", "囊括千萬里，矢謨在廟堂。", "耀耀金虎符，一息到炎荒。", "蒐兵自交趾，茇舍出瀘陽。", "羣山高嶄巖，凌越如鳥翔。", "封豕驟跧伏，巨象遙披攘。", "迴溪深天淵，揭厲踰舟梁。", "玄武掃孤蜮，蛟龍除方良。", "雷霆隨神兵，硼磕動穹蒼。", "斬伐若草木，繫縲同犬羊。", "餘醜隱弭河，啁啾亂行藏。", "君子惡薄險，王師恥重傷。", "廣車設罝梁，太白收光芒。", "邊吏靜縣道，新書行紀綱。", "劒關掉鞅歸，武弁朝建章。", "龍樓加命服，獬豸擁秋霜。", "邦人頌靈旗，側聽何洋洋。", "京觀在七德，休哉我神皇。"]'),
('6a4aa673-4ff1-4b81-aa94-3a125b8cfbac','奉和韋判官獻侍郎叔除河東採訪使','儲光羲','唐','唐诗','tang','','[]','天卿小冢宰，道大名亦大。',144,'全唐诗/poet.tang.6000.json','["天卿小冢宰，道大名亦大。", "醜正在權臣，建旟千里外。", "楚山俯江漢，汴水連譙沛。", "兩持方伯珪，再轉諸侯蓋。", "恬淡輕黜陟，優游邈千載。", "乾象變台衡，羣賢盡交泰。", "聿徠股肱郡，河嶽即襟帶。", "盛德滋冀方，仁風清汾澮。", "四封盡高足，相府軺車最。", "超超青雲器，婉婉竹林會。", "賤士敢知言，成頌文明代。", "燕雀依大廈，期之保貞悔。"]'),
('448cc553-053e-44d3-b333-834d477a27c7','同王十三維哭殷遙','儲光羲','唐','唐诗','tang','','[]','生理無不盡，念君在中年。',168,'全唐诗/poet.tang.6000.json','["生理無不盡，念君在中年。", "遊道雖未深，舉世莫能賢。", "筮仕苦貧賤，爲客少田園。", "膏腴不可求，乃在許西偏。", "四鄰盡桑柘，咫尺開牆垣。", "內艱未及虞，形影隨化遷。", "茅茨俯苫蓋，雙殯兩楹間。", "時聞孤女號，逈出陌與阡。", "慈烏亂飛鳴，猛獸亦以跧。", "故人王夫子，靜念無生篇。", "哀樂久已絕，聞之將泫然。", "太陽蔽空虛，雨雪浮蒼山。", "迢遰親靈櫬，顧予悲絕絃。", "處順與安時，及此乃空言。"]'),
('1758512b-5438-4b83-8374-84d477f0c53a','貽丁主簿仙芝別','儲光羲','唐','唐诗','tang','','[]','赫赫明天子，翹翹羣秀才。',240,'全唐诗/poet.tang.6000.json','["赫赫明天子，翹翹羣秀才。", "昭昭皇宇廣，隱隱雲門開。", "搖曳君初起，聯翩予復來。", "茲年不得意，相命遊靈臺。", "驊騮多逸氣，琳瑯有清響。", "聯行擊水飛，獨影凌虛上。", "關河施芳聽，江海徼新賞。", "歛袵歸故山，敷言播天壤。", "雲峰雖有異，楚越幸相親。", "既別復遊處，道深情更殷。", "下愚忝聞見，上德猶邅迍。", "偃仰東城曲，棲遲依水濱。", "脫巾從會府，結綬歸海裔。", "親知送河門，邦族迎江澨。", "夫子安恬淡，他人悵迢遞。", "飛艎既眇然，洲渚徒虧蔽。", "人謀固無準，天德諒難知。", "高名處下位，逸翮棲卑枝。", "去去水中沚，搖搖天一涯。", "蓬壺不可見，來泛躍龍池。"]'),
('d9a2fdb6-61b3-4388-9809-7102bec8c90c','京口送別王四誼','儲光羲','唐','唐诗','tang','','[]','江上楓林秋，江中秋水流。',48,'全唐诗/poet.tang.6000.json','["江上楓林秋，江中秋水流。", "清晨惜分袂，秋日尚同舟。", "落潮洗魚浦，傾荷枕驛樓。", "明年菊花熟，洛東泛觴遊。"]'),
('eda2b426-0a4e-4dba-a88d-2fce136d5ee7','同房憲部應旋','儲光羲','唐','唐诗','tang','','["\u8861\u5c71"]','衡山法王子，慧見息諸苦。',168,'全唐诗/poet.tang.6000.json','["衡山法王子，慧見息諸苦。", "落髮自南州，燕居在西土。", "養正不因晦，得中寧患旅。", "曠然長虛閒，即理寄行補。", "四句了自性，一音亦非取。", "橘柚故園枝，隨人植庭戶。", "我地少安住，念天時啓處。", "憲卿文昌歸，愉悅來晤語。", "車騎踐香草，僕人沐花雨。", "長風散繁雲，萬里靜天宇。", "起滅信易覺，清真知有所。", "逍遙高殿陰，六月無炎暑。", "微言發新偈，粲粲如懸圃。", "直心視惠光，在此大法鼓。"]'),
('13c6ec5e-dbdb-43e2-9509-27f5c923e808','奉別長史庾公太守徐公應召','儲光羲','唐','唐诗','tang','','[]','烈風起江漢，白浪忽如山。',132,'全唐诗/poet.tang.6000.json','["烈風起江漢，白浪忽如山。", "方伯驟勤王，杞人亦憂天。", "酆鎬頃霾晦，雲龍召我賢。", "車騎北艱苦，艅艎西泝沿。", "水靈靜湍瀨，猛獸趨後先。", "龍樓開新陽，萬里出雲間。", "宇宙既焜耀，崇德濟巨川。", "受命在神宗，振兵猶軒轅。", "煌煌踰涿鹿，穆穆更坤元。", "明王朝太階，遠邇望嘉言。", "遊子淡何思，江湖將永年。"]'),
('0e036fe3-3b59-4b6e-9d72-257c376e5070','獄中貽姚張薛李鄭柳諸公','儲光羲','唐','唐诗','tang','','[]','直道時莫親，起羞見讒口。',240,'全唐诗/poet.tang.6000.json','["直道時莫親，起羞見讒口。", "輿人是非怪，西子言有咎。", "誣善不足悲，失聽一何醜。", "大來敢遐望，小往且虛受。", "中夜囹圄深，初秋縲紲久。", "疎螢出暗草，朔風鳴衰柳。", "河漢低在戶，蟏蛸垂向牖。", "雁聲遠天末，涼氣生霽後。", "負戶愁讀書，劒光忿衝斗。", "哀哀害神理，惻惻傷慈母。", "妻子垂涕泣，家僮日奔走。", "書詞苦人吏，饋食勞交友。", "寒服猶未成，繁霜漸將厚。", "吉凶問詹尹，倚伏信北叟。", "鬼哭知己冤，鳥言誠所誘。", "諸公深惠愛，朝夕相左右。", "束濕雖欲操，鉤金庶無負。", "傷羅念搖翮，踠足思驤首。", "瑾瑜頗匿瑕，邦國方含垢。", "眷言出深穽，永日常攜手。"]'),
('b389fbca-08fb-4d3e-bf8b-93361f043010','貽鼓吹李丞時信安王北伐李公王之所器者也','儲光羲','唐','唐诗','tang','','[]','北伐昧天造，王師示有征。',144,'全唐诗/poet.tang.6000.json','["北伐昧天造，王師示有征。", "轅門統元律，帝室命宗英。", "靈威方首事，仗鉞按邊城。", "膏雨被春草，黃雲浮太清。", "文儒託後乘，武旅趨前旌。", "出車發西洛，營軍臨北平。", "曰予深固陋，志氣頗縱橫。", "嘗思驃騎幕，願逐嫖姚兵。", "惟賢美無度，海內依揚聲。", "河間舊相許，車騎日逢迎。", "折節下謀士，深心論客卿。", "忠言雖未列，庶以知君誠。"]'),
('c5e9dd73-5403-412f-9218-5e3598052aae','貽王侍御出臺掾丹陽','儲光羲','唐','唐诗','tang','','[]','高高瑯琊臺，臺下生箘簵。',288,'全唐诗/poet.tang.6000.json','["高高瑯琊臺，臺下生箘簵。", "照車十二乘，光彩不足諭。", "既當少微星，復隱高山霧。", "金丘華陽下，仙伯養晦處。", "茅茨對三峰，梧桐開一路。", "神溪繞臯陸，樵牧自成趣。", "時登青冥遊，若從天江度。", "墟里獻薇蕨，羣公致衣縷。", "深沈復清淨，偃仰視太素。", "猛獸識賓僕，赬霞知早暮。", "峨峨雲龍開，忽有方伯遇。", "達人無不可，壯志且馳騖。", "融泄長雞鳴，繽紛大鵬翥。", "赤墀高崱屴，一見如三顧。", "禮服正邦祀，刑冠肅王度。", "三辰明昭代，光啓玄元祚。", "章臺收杞梓，太液滿鵷鷺。", "豐澤耀純仁，八方晏黔庶。", "沈沈閶闔起，殷殷蓬萊曙。", "旌戟儼成行，雞人傳發煦。", "翔翼一如鶚，百辟莫不懼。", "清廟奉烝嘗，靈山扈鑾輅。", "天街時蹴鞠，直指讌梐枑。", "四月純陽初，雷雨始奮豫。"]'),
('d8756226-bbac-484b-bfd5-a4cb3950faee','貽劉高士別','儲光羲','唐','唐诗','tang','','[]','夙駕出東城，城傍早霞散。',240,'全唐诗/poet.tang.6000.json','["夙駕出東城，城傍早霞散。", "初日照龍闕，峨峨在天半。", "壯哉麗百常，美矣崇兩觀。", "俯視趨朝客，簪珮何璀璨。", "而我送將歸，裴回霸陵岸。", "北雲去吳越，南雁離江漢。", "伊昔蹈丘園，翩翩理文翰。", "高談閔仲叔，逸氣劉公幹。", "每言竹柏貞，嘗輕朝市玩。", "山晝猿狖靜，溪曛魚鳥亂。", "寧止臥崆峒，直云期汗漫。", "聖君既理歷，族士咸炳煥。", "矯首來天池，振羽泛漪瀾。", "元淑命不達，伯鸞吟可歎。", "東去姑蘇臺，乃過陟陽館。", "舍轡函關道，浮舟滄海畔。", "耳目曠暄涼，懷抱盈悲惋。", "沈沈青歲晚，靄靄秋雲換。", "自言永遁棲，無復從羈絆。", "揮手謝知己，知己莫能讚。"]'),
('0a47d27f-bcc0-4ce1-8b16-a39b5d1c492f','山中貽崔六琪華','儲光羲','唐','唐诗','tang','','[]','恍惚登高嶺，裴回看落日。',120,'全唐诗/poet.tang.6000.json','["恍惚登高嶺，裴回看落日。", "遙想仲長園，如親幼安室。", "春渚菖蒲登，山中撥穀鳴。", "相思不道遠，太息未知情。", "意君來此地，時復疎林薄。", "中夜掃閑門，迎晨閉菌閣。", "屣履清池上，家童奉信歸。", "憂隨落花散，目送歸雲飛。", "故交在天末，心知復千里。", "無人暫往來，獨作中林士。"]'),
('570dc597-4c1f-48e6-80f5-9982e6cf0845','貽余處士','儲光羲','唐','唐诗','tang','','[]','故園至新浦，遙復未百里。',156,'全唐诗/poet.tang.6000.json','["故園至新浦，遙復未百里。", "北望是他邦，紛吾即遊士。", "潮來津門啓，罷楫信流水。", "客意乃成歡，舟人亦相喜。", "遲遲菱荇上，泛泛孤蒲裏。", "漸聞商旅喧，猶見鳧鷖起。", "市亭忽雲構，方物如山峙。", "吳王昔喪元，隋帝又滅祀。", "停艫一以眺，太息興亡理。", "秋苑故池田，宮門新柳杞。", "我行苦炎月，乃及清昊始。", "此地日逢迎，終思隱君子。", "莫言異舒卷，形音在心耳。"]'),
('a4c90909-17f9-4af5-b6b7-e55cb4c1d322','劉先生閑居','儲光羲','唐','唐诗','tang','','[]','高第後歸道，乃居玉華宮。',108,'全唐诗/poet.tang.6000.json','["高第後歸道，乃居玉華宮。", "逍遙人間世，不異浮丘公。", "甘寢何秉羽，出門忽從戎。", "方將遊崑崙，又欲小崆峒。", "進退既在我，歸來長安中。", "焚香東海君，侍坐西山童。", "善行無轍迹，吾亦安能窮。", "但見神色閑，中心如虛空。", "期之比天老，真德輔帝鴻。"]'),
('cc6395dc-1145-45aa-817d-acbe64197d27','京口題崇上人山亭','儲光羲','唐','唐诗','tang','','[]','清旦歷香巖，巖徑紆復直。',72,'全唐诗/poet.tang.6000.json','["清旦歷香巖，巖徑紆復直。", "花林開宿霧，遊目清霄極。", "分明窗戶中，遠近山川色。", "金沙童子戲，香飯諸天食。", "呌呌海鴻聲，軒軒江燕翼。", "寄言清靜者，閭閻徒自踣。"]'),
('8fcf85d1-d1ee-48c6-a46d-c3effe3a7936','朝邑蔡主簿期不會二首 一','儲光羲','唐','唐诗','tang','','[]','下位日趨走，久之賓會疎。',72,'全唐诗/poet.tang.6000.json','["下位日趨走，久之賓會疎。", "空遲偶詞賦，所媿比園廬。", "朝念池上酌，暮逢林下書。", "方將固封守，暫欲混畋漁。", "衰柳隱長路，秋雲滿太虛。", "遙遙望左右，日入未迴車。"]'),
('5d55e2c8-f7af-4680-83e1-267084d91bb4','朝邑蔡主簿期不會二首 二','儲光羲','唐','唐诗','tang','','[]','日入清風至，知君在西偏。',72,'全唐诗/poet.tang.6000.json','["日入清風至，知君在西偏。", "車輿既成列，賓僕復能賢。", "迢遞下墟坂，逍遙看井田。", "蒼山起暮雨，極浦浮長煙。", "服義大如志，交歡數盡年。", "寧言十餘里，不見空來還。"]'),
('ae6f9bbc-7df9-4ea6-9167-7f55b9051594','鞏城南河作寄徐三景暉','儲光羲','唐','唐诗','tang','','[]','初年雨候遲，鞏洛河流小。',72,'全唐诗/poet.tang.6000.json','["初年雨候遲，鞏洛河流小。", "搖搖芳草岸，屢見春山曉。", "清露洗雲林，輕波戲魚鳥。", "唯言故人遠，不念鄉川眇。", "舟檝去瀠廻，湍漵行奔峭。", "寄書千里路，莫道南鴻少。"]'),
('d0078d0d-a976-4a7d-8fa8-d6ad7b8c76d8','貽閻處士防卜居終南','儲光羲','唐','唐诗','tang','','[]','春風搖雜樹，言別還江汜。',180,'全唐诗/poet.tang.6000.json','["春風搖雜樹，言別還江汜。", "堅冰生綠潭，又客三千里。", "兆夢唯顏色，懸情乃文史。", "滌耳貴清言，披歡遲玉趾。", "秦城疑舊廬，佇立問焉如。", "稚子跪而說，還山將隱居。", "竹林既深遠，松宇復清虛。", "跡逈事多逸，心安趣有餘。", "石門動高韻，草堂新著書。", "騫飛久超絕，蹇足空躊躇。", "猶有昔時意，望君當照車。", "驅車當六國，何以須潛默。", "聖主常徵賢，羣公每舉德。", "此時方獨往，身志將何欲。", "願謝山中人，廻車首歸躅。"]'),
('a8f1f22c-6767-4efe-9c6a-1fe77b0dfbce','新豐作貽殷四校書','儲光羲','唐','唐诗','tang','','[]','漢皇思舊邑，秦地作新豐。',72,'全唐诗/poet.tang.6000.json','["漢皇思舊邑，秦地作新豐。", "南出華陽路，西分長樂宮。", "安知天地久，不與昔年同。", "雞犬暮聲合，城池秋霽空。", "紛吾從此去，望極咸陽中。", "不見芸香閣，徒思文雅雄。"]'),
('f2fbe8a4-8e00-4fe7-80cd-bb832ceed2f6','華陽作貽祖三詠','儲光羲','唐','唐诗','tang','','[]','朝行敷水上，暮出華山東。',98,'全唐诗/poet.tang.6000.json','["朝行敷水上，暮出華山東。", "高館宿初靜，長亭秋轉空。", "日余久淪汨，重此聞霜風。", "淅瀝入溪樹，颼飀驚夕鴻。", "[悽]然望伊洛，如見息陽宮。", "舊識無高位，新知盡固窮。", "夫君獨輕舉，遠近善文雄。", "豈念千里駕，崎嶇秦塞中。"]'),
('66e1ba95-9dbd-47a3-97f7-d558ab6975ff','貽袁三拾遺謫作','儲光羲','唐','唐诗','tang','','[]','傾蓋洛之濱，依然心事親。',192,'全唐诗/poet.tang.6000.json','["傾蓋洛之濱，依然心事親。", "龍門何以峻，曾是好詞人。", "珥筆朝文陛，含章諷紫宸。", "帝城多壯觀，被服長如春。", "天子儉爲德，而能清約身。", "公卿盡虛位，天下自趣塵。", "如君物望美，令德聲何已。", "高帝黜儒生，文皇謫才子。", "朝廷非不盛，譴謫良難恃。", "路出大江陰，川行碧峰裏。", "斯言徒自玷，白玉豈爲滓。", "希聲盡衆人，深識唯知己。", "知己怨生離，悠悠天一涯。", "寸心因夢斷，孤憤爲年移。", "花滿芙蓉闕，春深朝夕池。", "空令千萬里，長望白雲垂。"]'),
('6a666243-80aa-467a-9b0e-db9fba806227','洛中貽朝校書衡朝即日本人也','儲光羲','唐','唐诗','tang','','[]','萬國朝天中，東隅道最長。',72,'全唐诗/poet.tang.6000.json','["萬國朝天中，東隅道最長。", "吾生美無度，高駕仕春坊。", "出入蓬山裏，逍遙伊水傍。", "伯鸞遊太學，中夜一相望。", "落日懸高殿，秋風入洞房。", "屢言相去遠，不覺生朝光。"]'),
('49c12afe-6a96-4beb-b6a4-7e12b9837918','貽崔太祝','儲光羲','唐','唐诗','tang','','[]','天都分禮閣，肅肅臨清渠。',72,'全唐诗/poet.tang.6000.json','["天都分禮閣，肅肅臨清渠。", "春山照前屏，高槐蔭內除。", "惟賢尚廩祿，弟去兄來居。", "文雅更驤首，風流信有餘。", "中年幸從事，乃遇兩吹噓。", "何以知君子，交情復淡如。"]'),
('d9803a22-5c21-4783-b91d-a7fc9beb454d','貽王處士子文','儲光羲','唐','唐诗','tang','','[]','春草生洞渚，春風入上林。',72,'全唐诗/poet.tang.6000.json','["春草生洞渚，春風入上林。", "春臯有黃鶴，撫翮未揚音。", "王屋嘗嘉遁，伊川復陸沈。", "張弦鵾雞弄，閉室蓬蒿深。", "避地歌三樂，遊山賦九吟。", "大君思左右，無乃化黃金。"]'),
('a08f09f5-e914-471c-bb97-88acc1af1cab','獻華陰羅丞別','儲光羲','唐','唐诗','tang','','[]','華山薄遊者，玄髮當青春。',96,'全唐诗/poet.tang.6000.json','["華山薄遊者，玄髮當青春。", "道德同仙吏，尊卑即丈人。", "縣城俯京路，獲見官舍裏。", "淹留瓊樹枝，謔浪春泉水。", "昔余在天目，總角奉遊從。", "寒暑遞來往，今復蓮花峰。", "別情無遠近，道別方愁予。", "孰想古人言，乃知悲風雨。"]'),
('c87cce2c-0e09-4549-af67-5880b488136f','閑居','儲光羲','唐','唐诗','tang','','[]','薄遊何所媿，所媿在閑居。',72,'全唐诗/poet.tang.6000.json','["薄遊何所媿，所媿在閑居。", "親故不來往，中園時讀書。", "步欄滴餘雪，春塘抽新蒲。", "梧桐漸覆井，時鳥自相呼。", "悠然念故鄉，乃在天一隅。", "安得如浮雲，來往方須臾。"]'),
('3cda1be8-8a33-407e-8c91-e64406ccdd86','送恂上人還吳','儲光羲','唐','唐诗','tang','','[]','洛城本天邑，洛水即天池。',48,'全唐诗/poet.tang.6000.json','["洛城本天邑，洛水即天池。", "君王既行幸，法子復來儀。", "虛室香花滿，清川楊柳棰。", "乘閑道歸去，遠意誰能知。"]'),
('00ef33e8-8439-4487-951a-39de4e32820c','送周十一','儲光羲','唐','唐诗','tang','','[]','秋風隕羣木，衆草下嚴霜。',48,'全唐诗/poet.tang.6000.json','["秋風隕羣木，衆草下嚴霜。", "復問子何如？自言之帝鄉。", "豈無親所愛，將欲濟時康。", "握手別征駕，返悲岐路長。"]'),
('2cbc7026-922c-4124-b979-5e8885fadf40','新豐主人','儲光羲','唐','唐诗','tang','','[]','新豐主人新酒熟，舊客還歸舊堂宿。',64,'全唐诗/poet.tang.6000.json','["新豐主人新酒熟，舊客還歸舊堂宿。", "滿酌香含北砌花，盈尊色泛南軒竹。", "雲散天高秋月明，東家少女解秦箏。", "醉來忘却巴陵道，夢中疑是洛陽城。"]'),
('168d13a5-327f-48f3-8ddd-7a5a49b527e3','登戲馬臺作','儲光羲','唐','唐诗','tang','','[]','君不見宋公仗鉞誅燕後，英雄踴躍爭趨走。',131,'全唐诗/poet.tang.6000.json','["君不見宋公仗鉞誅燕後，英雄踴躍爭趨走。", "小會衣冠呂梁壑，大徵甲卒碻磝口。", "天門神武樹元勳，九日茱萸饗六軍。", "泛泛樓船遊極浦，搖搖歌吹動浮雲。", "居人滿目市朝變，覇業猶存齊楚甸。", "泗水南流桐柏川，沂山北走瑯琊縣。", "滄海沈沈晨霧開，彭城烈烈秋風來。", "少年自古未得意，日暮蕭條登古臺。"]'),
('a90d93a8-6356-466e-9f1a-0322e86b696c','貽從軍行','儲光羲','唐','唐诗','tang','','[]','取勝小非用，來朝明光殿，東平不足先。',72,'全唐诗/poet.tang.6000.json','["取勝小非用，來朝明光殿，東平不足先。", "夢出鳳林間，夢還滄海闕。", "萬里盡陰色，豈爲我離別。", "馬上吹笛起寒風，道傍舞劒飛春雪。", "男兒懸弧非一日，君去成高節。"]'),
('67f77015-69d7-456c-8fe4-a377ef023676','酬李壺關奉使行縣憶諸公','儲光羲','唐','唐诗','tang','','[]','青楓江上滄浪吟，白月宮中鸚鵡林。',62,'全唐诗/poet.tang.6000.json','["青楓江上滄浪吟，白月宮中鸚鵡林。", "非有淨清心，同道同房若斷金。", "離居忽有雲山意，清韻遙轉舟檝事。", "去時能憶竹園遊，來時莫忘桃園記。"]'),
('813334ea-1a01-4541-b616-aabc22964bd8','薔薇','儲光羲','唐','唐诗','tang','','[]','裊裊長數尋，青青不作林。',124,'全唐诗/poet.tang.6000.json','["裊裊長數尋，青青不作林。", "一莖獨秀當庭心，數枝分作滿庭陰。", "春日遲遲欲將半，庭影離離正堪玩。", "枝上鶯嬌不畏人，葉底蛾飛自相亂。", "秦家女兒愛芳菲，畫眉相伴采葳蕤。", "高處紅鬚欲就手，低邊綠刺已牽衣。", "蒲萄架上朝光滿，楊柳園中暝鳥飛。", "連袂踏歌從此去，風吹香氣逐人歸。"]'),
('ad5a956d-14eb-45d5-a62d-c54222a33233','同張侍御宴北樓','儲光羲','唐','唐诗','tang','','[]','今之太守古諸侯，出入雙旌垂七旒。',160,'全唐诗/poet.tang.6000.json','["今之太守古諸侯，出入雙旌垂七旒。", "朝覽干戈時聽訟，暮延賓客復登樓。", "西山漠漠崦嵫色，北渚沈沈江漢流。", "良宵清淨方高會，繡服光輝聯皂蓋。", "魚龍恍惚堦墀下，雲霧杳冥窗戶外。", "水靈慷慨行泣珠，游女飄颻思解佩。", "蒼蒼低月半遙城，落落疎星滿太清。", "不分開襟悲楚奏，願言吹笛退胡兵。", "軒后青丘埋䝟貐，周王白羽掃欃槍。", "期君武節朝龍闕，余亦翱翔歸玉京。"]'),
('147d5d99-0931-480b-bd62-60abc8ca4f11','臨江亭五詠 一','儲光羲','唐','唐诗','tang','','[]','晉家南作帝，京鎮北爲關。',48,'全唐诗/poet.tang.6000.json','["晉家南作帝，京鎮北爲關。", "江水中分地，城樓下帶山。", "金陵事已往，青蓋理無還。", "落日空亭上，愁看龍尾灣。"]'),
('a26fa3bd-04b6-405d-ae8e-994758e3eac3','臨江亭五詠 二','儲光羲','唐','唐诗','tang','','[]','山橫小苑前，路盡大江邊。',50,'全唐诗/poet.tang.6000.json','["山橫小苑前，路盡大江邊。", "此地興王業，無如宋主賢。", "潮生建業水，風散廣陵煙。", "直望[清]波裏，秪言別有天。"]'),
('c33b6028-10fc-404f-a91f-6be41609c3af','臨江亭五詠 三','儲光羲','唐','唐诗','tang','','[]','城頭落暮暉，城外擣秋衣。',36,'全唐诗/poet.tang.6000.json','["城頭落暮暉，城外擣秋衣。", "江水青雲挹，蘆花白雪飛。", "南州王氣疾，東國海風微。"]'),
('d43c41bb-229f-43e9-8ee6-b8102f5f42ec','臨江亭五詠 四','儲光羲','唐','唐诗','tang','','[]','古木嘯寒禽，層城帶夕陰。',48,'全唐诗/poet.tang.6000.json','["古木嘯寒禽，層城帶夕陰。", "梁園多綠柳，楚岸盡楓林。", "山際空爲險，江流長自深。", "平生何以恨，天地本無心。"]'),
('6f6196e5-daaf-477c-883a-dc35808b9ab2','臨江亭五詠 五','儲光羲','唐','唐诗','tang','','[]','京山千里過，孤憤望中來。',36,'全唐诗/poet.tang.6000.json','["京山千里過，孤憤望中來。", "江勢將天合，城門向水開。", "落霞明楚岸，夕露濕吳臺。"]'),
('716f7354-2d8a-48c3-8647-70b2ac5a2e6a','餞張七琚任宗城即環之季也同產八人俱以才名知','儲光羲','唐','唐诗','tang','','[]','他日曾遊魏，魏家餘趾存。',48,'全唐诗/poet.tang.6000.json','["他日曾遊魏，魏家餘趾存。", "可憐宮殿所，但見桑榆繁。", "此去拜新職，爲榮近故園。", "高陽八才子，況復在君門。"]'),
('c7f6a757-4715-4def-972b-9f7d0accbbfe','留別安慶李太守','儲光羲','唐','唐诗','tang','','[]','明牧念行子，又言悲解攜。',48,'全唐诗/poet.tang.6000.json','["明牧念行子，又言悲解攜。", "初筵方落日，醉止到鳴雞。", "過客來自北，大軍居在西。", "兵家如討逆，敢以庶盤溪。"]'),
('85114306-509d-4937-aa2c-02aadfa84705','洛陽東門送別','儲光羲','唐','唐诗','tang','','[]','東城別故人，臘月遲芳辰。',48,'全唐诗/poet.tang.6000.json','["東城別故人，臘月遲芳辰。", "不惜孤舟去，其如兩地春。", "花明洛陽苑，水綠小平津。", "是日不相見，鶯聲徒自新。"]'),
('7cc65c84-277a-45ab-8a97-c3c2b4497ff9','漢陽即事','儲光羲','唐','唐诗','tang','','[]','楚國千里遠，孰知方寸違。',48,'全唐诗/poet.tang.6000.json','["楚國千里遠，孰知方寸違。", "春遊歡有客，夕寢賦無衣。", "江水帶冰綠，桃花隨雨飛。", "九歌有深意，捐佩乃言歸。"]'),
('f4f2909c-52b4-4786-930b-92169f597134','泊江潭貽馬校書','儲光羲','唐','唐诗','tang','','[]','明月掛青天，遙遙如目前。',48,'全唐诗/poet.tang.6000.json','["明月掛青天，遙遙如目前。", "故人遊畫閣，却望似雲邊。", "水宿依漁父，歌聲好采蓮。", "采蓮江上曲，今夕爲君傳。"]'),
('340134d6-aff3-428e-91f3-648ad3fd2fef','送沈校書吳中搜書','儲光羲','唐','唐诗','tang','','[]','郊外亭臯遠，野中岐路分。',48,'全唐诗/poet.tang.6000.json','["郊外亭臯遠，野中岐路分。", "苑門臨渭水，山翠雜春雲。", "秦閣多遺典，吳臺訪闕文。", "君王思校理，莫滯清江濆。"]'),
('0f871ab3-2946-4a55-b520-5d04d969d625','寒夜江口泊舟','儲光羲','唐','唐诗','tang','','[]','寒潮信未起，出浦纜孤舟。',48,'全唐诗/poet.tang.6000.json','["寒潮信未起，出浦纜孤舟。", "一夜苦風浪，自然增旅愁。", "吳山遲海月，楚火照江流。", "欲有知音者，異鄉誰可求。"]'),
('07bc1851-2ed2-4ad7-bccb-e5a2725f3622','苑外至龍興院作','儲光羲','唐','唐诗','tang','','[]','朝遊天苑外，忽見法筵開。',48,'全唐诗/poet.tang.6000.json','["朝遊天苑外，忽見法筵開。", "山勢當空出，雲陰滿地來。", "疎鐘清月殿，幽梵靜花臺。", "日暮香林下，飄飄仙步迴。"]'),
('69634ad9-987d-46aa-a611-fa2fa7774914','題虬上人房','儲光羲','唐','唐诗','tang','','[]','禪宮分兩地，釋子一爲心。',50,'全唐诗/poet.tang.6000.json','["禪宮分兩地，釋子一爲心。", "入道無來去，清言見古今。", "江寒池水綠，山[暝]竹園深。", "別有中天月，遙遙散夕陰。"]'),
('acd9a51f-7359-44d7-b368-6ad43b0a2d1c','詠山泉','儲光羲','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u5c71\u6c34", "\u548f\u7269"]','山中有流水，借問不知名。',48,'全唐诗/poet.tang.6000.json','["山中有流水，借問不知名。", "映地爲天色，飛空作雨聲。", "轉來深澗滿，分出小池平。", "恬澹無人見，年年長自清。"]'),
('875ef17c-7dd9-45c8-9f1b-c6ba8f93bd81','貽主客呂郎中','儲光羲','唐','唐诗','tang','','[]','上士既開天，中朝爲得賢。',48,'全唐诗/poet.tang.6000.json','["上士既開天，中朝爲得賢。", "青雲方羽翼，畫省比神仙。", "委佩雲霄裏，含香日月前。", "君王儻借問，客有上林篇。"]'),
('20de0cb4-fbe2-43c7-8305-239364b183c1','京口留別徐大補闕趙二零陵','儲光羲','唐','唐诗','tang','','[]','皇州月初曉，處處鼓鐘喧。',48,'全唐诗/poet.tang.6000.json','["皇州月初曉，處處鼓鐘喧。", "樹出蓬萊殿，城開閶闔門。", "近臣朝瑣闥，詞客向文園。", "獨有三川路，空傷遊子魂。"]'),
('25678390-be1b-4ceb-82d3-c06af67819c1','答王十三維','儲光羲','唐','唐诗','tang','','[]','門生故來往，知欲命浮觴。',48,'全唐诗/poet.tang.6000.json','["門生故來往，知欲命浮觴。", "忽奉朝青閣，回車入上陽。", "落花滿春水，疎柳映新塘。", "是日歸來暮，勞君奏雅章。"]'),
('fa81d4a9-be50-455f-b42f-563be223f69c','奉和中書徐侍郎中書省玩白雲寄頴陽趙大','儲光羲','唐','唐诗','tang','','[]','青闕朝初退，白雲遙在天。',48,'全唐诗/poet.tang.6000.json','["青闕朝初退，白雲遙在天。", "非關取雷雨，故欲伴神仙。", "泛灩鵷池曲，飄颻瑣闥前。", "猶多遠山意，幸入侍臣篇。"]'),
('4b2d83fc-df53-4d3d-9a40-8c20606fc3be','和張太祝冬祭馬步','儲光羲','唐','唐诗','tang','','[]','故壇何肅肅，中野自無喧。',48,'全唐诗/poet.tang.6000.json','["故壇何肅肅，中野自無喧。", "烈火見陳信，颺言聞永存。", "房星隱曙色，朔風動寒原。", "今日歌天馬，非關征大宛。"]'),
('8b676626-8a40-414f-af21-2ef31fcf2fa4','祭風伯壇應張太祝作','儲光羲','唐','唐诗','tang','','[]','聖主御青春，綸言命使臣。',48,'全唐诗/poet.tang.6000.json','["聖主御青春，綸言命使臣。", "將修風伯祀，更福太平人。", "帟幕宵聯事，壇場曉降神。", "帝心矜動物，非爲屬車人。"]'),
('9a60e5ed-1bf6-4d87-87d4-86e8d56fac39','尋徐山人遇馬舍人','儲光羲','唐','唐诗','tang','','[]','泊舟伊川右，正見野人歸。',48,'全唐诗/poet.tang.6000.json','["泊舟伊川右，正見野人歸。", "日暮春山綠，我心清且微。", "巖聲風雨度，水氣雲霞飛。", "復有金門客，來參蘿薜衣。"]'),
('8778b855-c076-4ed8-9323-37469ae46229','夜觀妓','儲光羲','唐','唐诗','tang','','[]','白雪宜新舞，清宵召楚妃。',48,'全唐诗/poet.tang.6000.json','["白雪宜新舞，清宵召楚妃。", "嬌童攜錦薦，侍女整羅衣。", "花映垂鬟轉，香迎步履飛。", "徐徐歛長袖，雙燭送將歸。"]'),
('7c83c8b3-4b02-4620-bd30-fd5954105a69','洛橋送別','儲光羲','唐','唐诗','tang','','[]','河橋送客舟，河水正安流。',48,'全唐诗/poet.tang.6000.json','["河橋送客舟，河水正安流。", "遠見輕橈動，遙憐故國遊。", "海禽逢早鴈，江月值新秋。", "一聽南津曲，分明散別愁。"]'),
('72c1861a-dc84-4b29-b0e1-7a72760c950f','秦中送人覲省','儲光羲','唐','唐诗','tang','','[]','二月清江外，遙遙餞故人。',48,'全唐诗/poet.tang.6000.json','["二月清江外，遙遙餞故人。", "南山晴有雪，東陌霽無塵。", "騎別章臺晚，舟行洛水春。", "知君梁苑去，日見白華新。"]'),
('5ffc26ef-fd5a-418e-807a-f555be01db9a','洛中送人還江東','儲光羲','唐','唐诗','tang','','[]','洛城春雨霽，相送下江鄉。',48,'全唐诗/poet.tang.6000.json','["洛城春雨霽，相送下江鄉。", "樹綠天津道，山明伊水陽。", "孤舟從此去，客思一何長。", "直望清波裏，唯餘落日光。"]'),
('835ca302-684b-443d-8e07-8234fddb8ac3','送姚六崑客任會稽何大蹇任孟縣','儲光羲','唐','唐诗','tang','','[]','越城臨渤澥，晉國在河汾。',48,'全唐诗/poet.tang.6000.json','["越城臨渤澥，晉國在河汾。", "仙綬兩鄉意，青郊一路分。", "野棠春未發，田雀暮成羣。", "他日思吳會，嘗因西北雲。"]'),
('36cd07ff-cbc1-422b-8257-18aaa86edbc7','洛潭送人覲省','儲光羲','唐','唐诗','tang','','[]','清洛帶芝田，東流入大川。',48,'全唐诗/poet.tang.6000.json','["清洛帶芝田，東流入大川。", "舟輕水復急，別望杳如仙。", "細草生春岸，明霞散早天。", "送君唯一曲，當是白華篇。"]'),
('4da98d00-a669-436d-8212-1630dafb7824','送人隨大夫和蕃','儲光羲','唐','唐诗','tang','','[]','西方有六國，國國願來賓。',48,'全唐诗/poet.tang.6000.json','["西方有六國，國國願來賓。", "聖主今無外，懷柔遣使臣。", "大夫開幕府，才子作行人。", "解劒聊相送，邊城二月春。"]'),
('645af21c-1afa-4cba-9334-8631c2b83d67','仲夏餞魏四河北覲叔','儲光羲','唐','唐诗','tang','','[]','落日臨御溝，送君還北州。',48,'全唐诗/poet.tang.6000.json','["落日臨御溝，送君還北州。", "樹涼征馬去，路暝歸人愁。", "吳嶽夏雲盡，渭河秋水流。", "東籬摘芳菊，想見竹林遊。"]'),
('13e1fad6-4593-4749-b593-3e44130088b2','送人尋裴斐','儲光羲','唐','唐诗','tang','','[]','柱史迴清憲，謫居臨漢川。',48,'全唐诗/poet.tang.6000.json','["柱史迴清憲，謫居臨漢川。", "遲君千里駕，方外賞雲泉。", "路斷因春水，山深隔暝煙。", "湘江見遊女，寄摘一枝蓮。"]'),
('df2ae035-c364-421b-b84b-c85f78bfbb19','隴頭水送別','儲光羲','唐','唐诗','tang','','[]','相送隴山頭，東西隴水流。',48,'全唐诗/poet.tang.6000.json','["相送隴山頭，東西隴水流。", "從來心膽盛，今日爲君愁。", "暗雪迷征路，寒雲隱戍樓。", "唯餘旌斾影，相逐去悠悠。"]'),
('3399d083-80e6-4cb3-ab5c-9c9986a46e0a','送王上人還襄陽','儲光羲','唐','唐诗','tang','','[]','朝看法雲散，知有至人還。',48,'全唐诗/poet.tang.6000.json','["朝看法雲散，知有至人還。", "送客臨伊水，行車出故關。", "天花滿南國，精舍在空山。", "雖復時來去，中心長日閑。"]'),
('6d456416-fbd8-4121-91df-9c22cfe73646','官莊池觀競渡','儲光羲','唐','唐诗','tang','','[]','落日吹簫管，清池發櫂歌。',48,'全唐诗/poet.tang.6000.json','["落日吹簫管，清池發櫂歌。", "船爭先後渡，岸激去來波。", "水葉藏魚鳥，林花間綺羅。", "踟躕仙女處，猶似望天河。"]'),
('ea180396-0d81-4084-ac98-c83f306b55e0','重寄虬上人','儲光羲','唐','唐诗','tang','','[]','一作雲峰別，三看花柳朝。',48,'全唐诗/poet.tang.6000.json','["一作雲峰別，三看花柳朝。", "青山隔遠路，明月空長霄。", "鵲浴西江雨，雞鳴東海潮。", "此情勞夢寐，況道雙林遙。"]'),
('348682ac-e679-4f4f-935a-bbb2732ce446','藍上茅茨期王維補闕','儲光羲','唐','唐诗','tang','','[]','山中人不見，雲去夕陽過。',48,'全唐诗/poet.tang.6000.json','["山中人不見，雲去夕陽過。", "淺瀨寒魚少，叢蘭秋蝶多。", "老年疎世事，幽性樂天和。", "酒熟思才子，谿頭望玉珂。"]'),
('d9733ead-7d1e-4b64-abd5-f3e2955e9a55','大酺得長字韻時任安宜尉','儲光羲','唐','唐诗','tang','','[]','大道啓元命，時人居太康。',72,'全唐诗/poet.tang.6000.json','["大道啓元命，時人居太康。", "中朝發玄澤，下國被天光。", "明詔始端午，初筵當履霜。", "鼓鼙迎爽氣，羽籥映新陽。", "太守即懸圃，淮夷成葆疆。", "小臣慙下位，拜手頌靈長。"]'),
('7e741e6a-51c3-4eba-95b5-0bf714730803','同張侍御鼎和京兆蕭兵曹華歲晚南園','儲光羲','唐','唐诗','tang','','[]','公府傳休沐，私庭效陸沈。',96,'全唐诗/poet.tang.6000.json','["公府傳休沐，私庭效陸沈。", "方知從大隱，非復在幽林。", "闕下忠貞志，人間孝友心。", "既將冠蓋雅，仍與薜蘿深。", "寒變中園柳，春歸上苑禽。", "池涵青草色，山帶白雲陰。", "潘岳閑居賦，鍾期流水琴。", "一經當自足，何用遺黃金。"]'),
('fee235e6-6eb0-4b97-8c3e-7c043f113a6e','奉酬張五丈垂贈','儲光羲','唐','唐诗','tang','','[]','綵服去江汜，白雲生大梁。',72,'全唐诗/poet.tang.6000.json','["綵服去江汜，白雲生大梁。", "星辰動異色，羔鴈成新行。", "日望天朝近，時憂郢路長。", "情言間薖軸，惠念及滄浪。", "松柏以之茂，江湖亦自忘。", "賈生方弔屈，豈敢比南昌。"]'),
('a4daf63f-3c35-4f21-96d4-e8110e570e07','秦中守歲','儲光羲','唐','唐诗','tang','','[]','衆星已窮次，青帝方行春。',72,'全唐诗/poet.tang.6000.json','["衆星已窮次，青帝方行春。", "永感易成戚，離居難重陳。", "闔門守初夜，燎火到清晨。", "或念無生法，多傷未出塵。", "廣庭日將晏，虛室自爲賓。", "願以桑榆末，常逢甲子新。"]'),
('4c92c83c-966e-4fc4-8b66-8e0e214dc3a0','獻高使君大酺作','儲光羲','唐','唐诗','tang','','[]','肅穆郊禋畢，工歌賞事幷。',60,'全唐诗/poet.tang.6000.json','["肅穆郊禋畢，工歌賞事幷。", "三朝遵湛露，一道洽仁明。", "布德言皆應，無爲物自成。", "花添羅綺色，鶯亂管弦聲。", "獨有同高唱，空陪樂太平。"]'),
('ac094935-0541-45c9-9e19-5c9a24988acc','滎陽馬氏二子','儲光羲','唐','唐诗','tang','','[]','聖君封太嶽，十月建行旃。',96,'全唐诗/poet.tang.6000.json','["聖君封太嶽，十月建行旃。", "輦路開千里，寒雲霽九天。", "故人多侍從，二子留伊川。", "河兗冰初合，關城月屢圓。", "暝過滎水上，聞說鄭卿賢。", "材蔽行人右，名居東里先。", "制巖開別業，桑柘亦依然。", "待至金園側，相將居一廛。"]'),
('e73369ec-6774-4fb3-9a3b-1d71695c105b','觀競渡','儲光羲','唐','唐诗','tang','','[]','大夫沈楚水，千祀國人哀。',60,'全唐诗/poet.tang.6000.json','["大夫沈楚水，千祀國人哀。", "習櫂江流長，迎神雨霧開。", "標隨綠雲動，船逆清波來。", "下怖魚龍起，上驚鳧鴈迴。", "能令秋大有，鼓吹遠相催。"]'),
('b28389ba-7323-4b97-81f9-7cd20532267c','太學貽張筠','儲光羲','唐','唐诗','tang','','[]','璧池忝門子，俄頃變炎涼。',72,'全唐诗/poet.tang.6000.json','["璧池忝門子，俄頃變炎涼。", "綠竹深虛館，清流響洞房。", "園林在建業，新友去咸陽。", "中夜鼓鐘靜，初秋漏刻長。", "浮雲開太室，華蓋上明堂。", "空此遠相望，勞歌還自傷。"]'),
('f44da1e8-6289-4f0e-a607-7feb1cdeb2e6','田家即事','儲光羲','唐','唐诗','tang','','[]','桑柘悠悠水蘸堤，晚風晴景不妨犂。',64,'全唐诗/poet.tang.6000.json','["桑柘悠悠水蘸堤，晚風晴景不妨犂。", "高機猶織臥蠶子，下坂飢逢餉饁妻。", "杏色滿林羊酪熟，麥涼浮壠雉媒低。", "生時樂死皆由命，事在皇天志不迷。"]'),
('e78c496b-cfd3-4919-9634-a5c3253889e2','洛陽道五首獻呂四郎中 一','儲光羲','唐','唐诗','tang','','[]','洛水春冰開，洛城春水綠。',24,'全唐诗/poet.tang.6000.json','["洛水春冰開，洛城春水綠。", "朝看大道上，落花亂馬足。"]'),
('f2e7bf8f-c30c-40a0-92c0-c9e1ddcd1ed5','洛陽道五首獻呂四郎中 二','儲光羲','唐','唐诗','tang','','[]','劇孟不知名，千金買寶劍/。',25,'全唐诗/poet.tang.6000.json','["劇孟不知名，千金買寶劍/。", "出入平津邸，自言嬌且豔。"]'),
('2799a70a-5cc0-421e-9e10-72eb23053ea5','洛陽道五首獻呂四郎中 三','儲光羲','唐','唐诗','tang','','[]','大道直如髮，春日佳氣多。',24,'全唐诗/poet.tang.6000.json','["大道直如髮，春日佳氣多。", "五陵貴公子，雙雙鳴玉珂。"]'),
('71f5dc4c-6e81-4e4b-a3e3-2534be3873ac','洛陽道五首獻呂四郎中 四','儲光羲','唐','唐诗','tang','','[]','春風二月時，道傍柳堪把。',24,'全唐诗/poet.tang.6000.json','["春風二月時，道傍柳堪把。", "上枝覆官閣，下枝覆車馬。"]'),
('a9beccc1-6838-4aac-a19c-ce1fa0b1404b','洛陽道五首獻呂四郎中 五','儲光羲','唐','唐诗','tang','','[]','洛水照千門，千門碧空裏。',24,'全唐诗/poet.tang.6000.json','["洛水照千門，千門碧空裏。", "少年不得志，走馬遊新市。"]'),
('9d542486-50c6-40b9-adfe-909b5ff172c8','同武平一員外遊湖','儲光羲','唐','唐诗','tang','','[]','竹吹留歌扇，蓮香入舞衣。',24,'全唐诗/poet.tang.6000.json','["竹吹留歌扇，蓮香入舞衣。", "前溪多曲漵，乘興莫先歸。"]'),
('90aca2d1-de03-466f-8f11-f2b648788de3','長安道 一','儲光羲','唐','唐诗','tang','','[]','鳴鞭過酒肆，袨服遊倡門。',24,'全唐诗/poet.tang.6000.json','["鳴鞭過酒肆，袨服遊倡門。", "百萬一時盡，含情無片言。"]'),
('95fc9ecc-7201-4fbf-8682-bc9e7156267a','長安道 二','儲光羲','唐','唐诗','tang','','[]','西行一千里，暝色生寒樹。',24,'全唐诗/poet.tang.6000.json','["西行一千里，暝色生寒樹。", "暗聞歌吹聲，知是長安路。"]'),
('fe326097-17a7-4f35-a32b-417d412b149b','江南曲四首 一','儲光羲','唐','唐诗','tang','','[]','綠江深見底，高浪直翻空。',24,'全唐诗/poet.tang.6000.json','["綠江深見底，高浪直翻空。", "慣是湖邊住，舟輕不畏風。"]'),
('8ba77fc3-15e1-49c2-bf76-fb6ba2147136','江南曲四首 二','儲光羲','唐','唐诗','tang','','[]','逐流牽荇葉，綠岸摘蘆苗。',24,'全唐诗/poet.tang.6000.json','["逐流牽荇葉，綠岸摘蘆苗。", "爲惜鴛鴦鳥，輕輕動畫橈。"]'),
('d095b65e-7e44-4e42-86c1-3708c499e237','江南曲四首 三','儲光羲','唐','唐诗','tang','','["\u957f\u6c5f"]','日暮長江裏，相邀歸渡頭。',24,'全唐诗/poet.tang.6000.json','["日暮長江裏，相邀歸渡頭。", "落花如有意，來去逐船流。"]'),
('158cc8e9-d27d-4496-a0a5-8d9fcd7bc9eb','江南曲四首 四','儲光羲','唐','唐诗','tang','','[]','隔江看樹色，沿月聽歌聲。',24,'全唐诗/poet.tang.6000.json','["隔江看樹色，沿月聽歌聲。", "不是長干住，那從此路行。"]'),
('8d9694d9-9424-41ba-8a0c-4e6a2bee769d','關山月','儲光羲','唐','唐诗','tang','','[]','一鴈過連營，繁霜覆古城。',24,'全唐诗/poet.tang.6000.json','["一鴈過連營，繁霜覆古城。", "胡笳在何處？半夜起邊聲。"]'),
('b28f66aa-6354-4298-96cd-10b5154acc98','玉真公主山居','儲光羲','唐','唐诗','tang','','[]','山北天泉苑，山西鳳女家。',24,'全唐诗/poet.tang.6000.json','["山北天泉苑，山西鳳女家。", "不言沁園好，獨隱武陵花。"]'),
('99ba45d7-7930-4c5b-8b49-fdc9e5d1704e','滄浪峽','儲光羲','唐','唐诗','tang','','[]','滄浪臨古道，道上若成塵。',24,'全唐诗/poet.tang.6000.json','["滄浪臨古道，道上若成塵。", "自有滄浪峽，誰爲無事人。"]'),
('e26b59de-597a-433f-8f89-49fc83e0407e','奉真觀','儲光羲','唐','唐诗','tang','','[]','真門逈向北，馳道直向西。',24,'全唐诗/poet.tang.6000.json','["真門逈向北，馳道直向西。", "爲與天光近，雲色成虹霓。"]'),
('d3cd9814-5264-44c4-b2a0-7e42e0933d5b','明妃曲四首 一','儲光羲','唐','唐诗','tang','','[]','西行隴上泣胡天，南向雲中指渭川。',32,'全唐诗/poet.tang.6000.json','["西行隴上泣胡天，南向雲中指渭川。", "毳幕夜來時宛轉，何由得似漢王邊。"]'),
('b0e8a0e1-b173-411f-9fce-9335163b797f','明妃曲四首 二','儲光羲','唐','唐诗','tang','','[]','胡王知妾不勝悲，樂府皆傳漢國辭。',32,'全唐诗/poet.tang.6000.json','["胡王知妾不勝悲，樂府皆傳漢國辭。", "朝來馬上箜篌引，稍似宮中閑夜時。"]'),
('302c12c6-de5f-41fc-8842-c158c4df3028','明妃曲四首 三','儲光羲','唐','唐诗','tang','','[]','日暮驚沙亂雪飛，傍人相勸易羅衣。',32,'全唐诗/poet.tang.6000.json','["日暮驚沙亂雪飛，傍人相勸易羅衣。", "強來前殿看歌舞，共待單于夜獵歸。"]'),
('12d9d605-70e5-4c43-90c4-7a9d666a4f1d','明妃曲四首 四','儲光羲','唐','唐诗','tang','','[]','彩騎雙雙引寶車，羌笛兩兩奏胡笳。',32,'全唐诗/poet.tang.6000.json','["彩騎雙雙引寶車，羌笛兩兩奏胡笳。", "若爲別得橫橋路，莫隱宮中玉樹花。"]'),
('b7363995-2c35-46d0-9e67-2ab8e9eed8a4','同武平一員外遊湖五首時武貶金壇令 一','儲光羲','唐','唐诗','tang','','[]','紅荷碧篠夜相鮮，皂蓋蘭橈浮翠筵。',32,'全唐诗/poet.tang.6000.json','["紅荷碧篠夜相鮮，皂蓋蘭橈浮翠筵。", "舟中對舞邯鄲曲，月下雙彈盧女弦。"]'),
('1e1c3eef-ba92-4723-93f8-071551e83329','同武平一員外遊湖五首時武貶金壇令 二','儲光羲','唐','唐诗','tang','','[]','青林碧嶼暗相期，緩楫揮觥欲賦詩。',32,'全唐诗/poet.tang.6000.json','["青林碧嶼暗相期，緩楫揮觥欲賦詩。", "借問高歌凡幾轉，河低月落五更時。"]'),
('cbea5bfe-3760-4eb7-9d10-92f699fa1004','同武平一員外遊湖五首時武貶金壇令 三','儲光羲','唐','唐诗','tang','','[]','朝來仙閣聽弦歌，暝入花亭見綺羅。',32,'全唐诗/poet.tang.6000.json','["朝來仙閣聽弦歌，暝入花亭見綺羅。", "池邊命酒憐風月，浦口回船惜芰荷。"]'),
('8dd306e7-e6e9-41bc-a2b3-f7fa76c80738','同武平一員外遊湖五首時武貶金壇令 四','儲光羲','唐','唐诗','tang','','[]','朦朧竹影蔽巖扉，淡蕩荷風飄舞衣。',32,'全唐诗/poet.tang.6000.json','["朦朧竹影蔽巖扉，淡蕩荷風飄舞衣。", "舟尋綠水宵將半，月隱青林人未歸。"]'),
('3af69bfe-5e4a-4e81-9e75-f7d5c921515b','同武平一員外遊湖五首時武貶金壇令 五','儲光羲','唐','唐诗','tang','','[]','花潭竹嶼傍幽蹊，畫檝浮空入夜溪。',32,'全唐诗/poet.tang.6000.json','["花潭竹嶼傍幽蹊，畫檝浮空入夜溪。", "芰荷覆水船難進，歌舞留人月易低。"]'),
('170f9a76-d5fb-43be-970d-a0568afba39b','題茅山華陽洞','儲光羲','唐','唐诗','tang','','[]','華陽洞口片雲飛，細雨濛濛欲濕衣。',32,'全唐诗/poet.tang.6000.json','["華陽洞口片雲飛，細雨濛濛欲濕衣。", "玉簫遍滿仙壇上，應是茅家兄弟歸。"]'),
('94291c7d-6279-44e5-924f-bc2d5288ee1d','寄孫山人','儲光羲','唐','唐诗','tang','','[]','新林二月孤舟還，水滿清江花滿山。',32,'全唐诗/poet.tang.6000.json','["新林二月孤舟還，水滿清江花滿山。", "借問故園隱君子，時時來往住人間。"]'),
('041cde06-3afc-4e27-b4c4-eb8d39211c9b','變行路難','王昌齡','唐','唐诗','tang','','[]','向晚橫吹悲，風動馬嘶合。',48,'全唐诗/poet.tang.6000.json','["向晚橫吹悲，風動馬嘶合。", "前趨引旗節，千里陣雲帀。", "單于下陰山，砂礫空颯颯。", "封侯取一戰，豈復念閨閤。"]'),
('8d58a158-1a9b-4085-8ef7-b7b4e6adb66d','塞下曲四首 一','王昌齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u6e38\u4fa0", "\u4e50\u5e9c", "\u8bbd\u523a", "\u8fb9\u585e"]','蟬鳴空桑林，八月蕭關道。',48,'全唐诗/poet.tang.6000.json','["蟬鳴空桑林，八月蕭關道。", "出塞入塞寒，處處黃蘆草。", "從來幽幷客，皆共塵沙老。", "莫學遊俠兒，矜夸紫騮好。"]'),
('59fb3f01-65b2-416a-aefb-c13e502bfba1','塞下曲四首 二','王昌齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6218\u4e89", "\u65b0\u4e50\u5e9c\u8f9e", "\u4e50\u5e9c"]','飲馬渡秋水，水寒風似刀。',48,'全唐诗/poet.tang.6000.json','["飲馬渡秋水，水寒風似刀。", "平沙日未沒，黯黯見臨洮。", "昔日長城戰，咸言意氣高。", "黃塵足今古，白骨亂蓬蒿。"]'),
('4eb08533-cc6b-40cc-af72-fe3aae695224','塞下曲四首 三','王昌齡','唐','唐诗','tang','','[]','奉詔甘泉宮，總徵天下兵。',48,'全唐诗/poet.tang.6000.json','["奉詔甘泉宮，總徵天下兵。", "朝廷備禮出，郡國豫郊迎。", "紛紛幾萬人，去者無全生。", "臣願節宮廐，分以賜邊城。"]'),
('2863d1fe-dd22-43a7-b067-4b323c8fec7f','塞下曲四首 四','王昌齡','唐','唐诗','tang','','[]','邊頭何慘慘，已葬霍將軍。',48,'全唐诗/poet.tang.6000.json','["邊頭何慘慘，已葬霍將軍。", "部曲皆相弔，燕南代北聞。", "功勳多被黜，兵馬亦尋分。", "更遣黃龍戍，唯當哭塞雲。"]'),
('56950b6b-d796-4436-a80a-cca1f325d978','塞上曲','王昌齡','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','秋風夜渡河，吹却鴈門桑。',48,'全唐诗/poet.tang.6000.json','["秋風夜渡河，吹却鴈門桑。", "遙見胡地獵，鞲馬宿嚴霜。", "五道分兵去，孤軍百戰場。", "功多翻下獄，士卒但心傷。"]'),
('23f9cc7d-51cf-4f53-a8ad-58f107aec73d','從軍行二首 一','王昌齡','唐','唐诗','tang','','[]','向夕臨大荒，朔風軫歸慮。',84,'全唐诗/poet.tang.6000.json','["向夕臨大荒，朔風軫歸慮。", "平沙萬里餘，飛鳥宿何處？", "虜騎獵長原，翩翩傍河去。", "邊聲搖白草，海氣生黃霧。", "百戰苦風塵，十年履霜露。", "雖投定遠筆，未坐將軍樹。", "早知行路難，悔不理章句。"]'),
('b1118052-b14f-4b18-9a45-c4c53b95f2e0','從軍行二首 二','王昌齡','唐','唐诗','tang','','[]','秋草馬蹄輕，角弓持弦急。',96,'全唐诗/poet.tang.6000.json','["秋草馬蹄輕，角弓持弦急。", "去爲龍城戰，正值胡兵襲。", "軍氣橫大荒，戰酣日將入。", "長風金鼓動，白露鐵衣濕。", "四起愁邊聲，南庭時佇立。", "斷蓬孤自轉，寒雁飛相及。", "萬里雲沙漲，平原冰霰澀。", "惟聞漢使還，獨向刀環泣。"]'),
('de4a1ec9-b488-4b00-bb31-469028426436','少年行二首 一','王昌齡','唐','唐诗','tang','','[]','西陵俠少年，送客短長亭。',48,'全唐诗/poet.tang.6000.json','["西陵俠少年，送客短長亭。", "青槐夾兩道，白馬如流星。", "聞道羽書急，單于寇井陘。", "氣高輕赴難，誰顧燕山銘。"]'),
('9f4352c5-c777-414c-8645-c3912a704f85','少年行二首 二','王昌齡','唐','唐诗','tang','','[]','走馬遠相尋，西樓下夕陰。',48,'全唐诗/poet.tang.6000.json','["走馬遠相尋，西樓下夕陰。", "結交期一劒，留意贈千金。", "高閣歌聲遠，重門柳色深。", "夜闌須盡飲，莫負百年心。"]'),
('b48f64cf-d565-4964-a258-f44b07512fd8','長歌行','王昌齡','唐','唐诗','tang','','[]','曠野饒悲風，颼颼黃蒿草。',96,'全唐诗/poet.tang.6000.json','["曠野饒悲風，颼颼黃蒿草。", "繫馬倚白楊，誰知我懷抱。", "所是同袍者，相逢盡衰老。", "北登漢家陵，南望長安道。", "下有枯樹根，上有鼯鼠窠。", "高皇子孫盡，千載無人過。", "寶玉頻發掘，精靈其奈何？", "人生須達命，有酒且長歌。"]'),
('164b3169-b72d-46ec-9302-bfb37d1f5295','悲哉行','王昌齡','唐','唐诗','tang','','[]','勿聽白頭吟，人間易憂怨。',84,'全唐诗/poet.tang.6000.json','["勿聽白頭吟，人間易憂怨。", "若非滄浪子，安得從所願。", "北上太行山，臨風閱吹萬。", "長雲數千里，倏忽還膚寸。", "觀其微滅時，精意莫能論。", "百年不容息，是處生意蔓。", "始悟海上人，辭君永飛遯。"]'),
('4bb7dd4c-9726-4ca3-aa8b-8f764f039848','古意','王昌齡','唐','唐诗','tang','','[]','桃花四面發，桃葉一枝開。',36,'全唐诗/poet.tang.6000.json','["桃花四面發，桃葉一枝開。", "欲暮黃鸝囀，傷心玉鏡臺。", "清箏向明月，半夜春風來。"]'),
('7cdb8ee8-f0b9-4e0b-9db3-10fc92b26ebb','放歌行','王昌齡','唐','唐诗','tang','','[]','南渡洛陽津，西望十二樓。',144,'全唐诗/poet.tang.6000.json','["南渡洛陽津，西望十二樓。", "明堂坐天子，月朔朝諸侯。", "清樂動千門，皇風被九州。", "慶雲從東來，泱漭抱日流。", "昇平貴論道，文墨將何求？", "有詔徵草澤，微誠將獻謀。", "冠冕如星羅，拜揖曹與周。", "望塵非吾事，入賦且遲留。", "幸蒙國士識，因脫負薪裘。", "今者放歌行，以慰梁甫愁。", "但營數斗祿，奉養每豐羞。", "若得金膏遂，飛雲亦何儔。"]'),
('53f1aab9-1c67-48a4-a0ed-cc777a10c389','越女','王昌齡','唐','唐诗','tang','','[]','越女作桂舟，還將桂爲楫。',48,'全唐诗/poet.tang.6000.json','["越女作桂舟，還將桂爲楫。", "湖上水渺漫，清江不可涉。", "摘取芙蓉花，莫摘芙蓉葉。", "將歸問夫壻，顏色何如妾。"]'),
('d41ca296-73e6-4e8f-8a05-36809d471157','鄭縣宿陶太公館中贈馮六元二','王昌齡','唐','唐诗','tang','','["\u534e\u5c71"]','儒有輕王侯，脫略當事務。',192,'全唐诗/poet.tang.6000.json','["儒有輕王侯，脫略當事務。", "本家藍田下，非爲漁弋故。", "無何困躬耕，且欲馳永路。", "幽居與君近，出谷同所騖。", "昨日辭石門，五年變秋露。", "雲龍未相感，干謁亦已屢。", "子爲黃綬羈，余忝蓬山顧。", "京門望西嶽，百里見郊樹。", "飛雨祠上來，靄然關中暮。", "驅車鄭城宿，秉燭論往素。", "山月出華陰，開此河渚霧。", "清光比故人，豁達展心晤。", "馮公尚戢翼，元子仍跼步。", "拂衣易爲高，淪跡難有趣。", "張范善終始，吾等豈不慕。", "罷酒當涼風，屈伸備冥數。"]'),
('50043733-c059-4f9e-9897-5522f30348a1','聽彈風入松闋贈楊補闕','王昌齡','唐','唐诗','tang','','[]','商風入我絃，夜竹深有露。',72,'全唐诗/poet.tang.6000.json','["商風入我絃，夜竹深有露。", "絃悲與林寂，清景不可度。", "寥落幽居心，颼飀青松樹。", "松風吹草白，溪水寒日暮。", "聲意去復還，九變待一顧。", "空山多雨雪，獨立君始悟。"]'),
('cd5fc55a-6d76-446a-93e0-523b016a6aea','緱氏尉沈興宗置酒南谿留贈','王昌齡','唐','唐诗','tang','','[]','林色與溪古，深篁引幽翠。',144,'全唐诗/poet.tang.6000.json','["林色與溪古，深篁引幽翠。", "山尊在漁舟，棹月情已醉。", "始窮清源口，壑絕人境異。", "春泉滴空崖，萌草拆陰地。", "久之風榛寂，遠聞樵聲至。", "海雁時獨飛，永然滄洲意。", "古時青冥客，滅跡淪一尉。", "吾子躊躇心，豈其紛埃事。", "緱峯信所剋，濟北余乃遂。", "齊物意已會，息肩理猶未。", "卷舒形性表，脫略賢哲議。", "仲月期角巾，飯僧嵩陽寺。"]'),
('c4f49265-6689-4a47-a119-6f8bba4272ba','爲張僓贈閻使臣','王昌齡','唐','唐诗','tang','','[]','哀哀獻玉人，楚國同悲辛。',48,'全唐诗/poet.tang.6000.json','["哀哀獻玉人，楚國同悲辛。", "泣盡繼以血，何由辨其真。", "賴承琢磨惠，復使光輝新。", "猶畏讒口疾，棄之如埃塵。"]'),
('cb6d873b-73c8-4668-bdb9-7b6b3e989b51','贈史昭','王昌齡','唐','唐诗','tang','','[]','東林月未升，廓落星與漢。',72,'全唐诗/poet.tang.6000.json','["東林月未升，廓落星與漢。", "是夕鴻始來，齋中起長歎。", "懷哉望南浦，眇然夜將半。", "但有秋水聲，愁使心神亂。", "握中何爲贈，瑤草已衰散。", "海鱗未化時，各在天一岸。"]'),
('7bd15cbf-8fd9-46e6-9b4b-d193cefacad4','秋山寄陳讜言','王昌齡','唐','唐诗','tang','','[]','巖間寒事早，衆山木已黃。',72,'全唐诗/poet.tang.6000.json','["巖間寒事早，衆山木已黃。", "北風何蕭蕭，茲夕露爲霜。", "感激未能寐，中宵時慨慷。", "黃蟲初悲鳴，玄鳥去我梁。", "獨臥時易晚，離羣情更傷。", "思君若不及，鴻雁今南翔。"]'),
('b5bb6013-e22e-47f6-ac1b-1cfb231eb73f','出郴山口至疊石灣野人室中寄張十一','王昌齡','唐','唐诗','tang','','[]','櫧柟無冬春，柯葉連峯稠。',204,'全唐诗/poet.tang.6000.json','["櫧柟無冬春，柯葉連峯稠。", "陰壁下蒼黑，煙含清江樓。", "景開獨沿曳，響答隨興酬。", "旦夕望吾友，如何迅孤舟。", "疊沙積爲崗，崩剝雨露幽。", "石脉盡橫亙，潛潭何時流。", "既見萬古色，頗盡一物由。", "永與世人遠，氣還草木收。", "盈縮理無餘，今往何必憂。", "郴土羣山高，耆老如中州。", "孰云議舛降，豈是娛宦遊。", "陰火昔所伏，丹砂將爾謀。", "昨臨蘇耽井，復向衡陽求。", "同疚來相依，脫身當有籌。", "數月乃離居，風湍成阻脩。", "野人善竹器，童子能谿謳。", "寒夜波蕩漾，羇鴻去悠悠。"]'),
('09ce19c2-d94c-4d26-898a-6ad89bcba2d5','宿灞上寄侍御璵弟','王昌齡','唐','唐诗','tang','','[]','獨飲灞上亭，寒山青門外。',288,'全唐诗/poet.tang.6000.json','["獨飲灞上亭，寒山青門外。", "長雲驟落日，桑棗寂已晦。", "古人驅馳者，宿此凡幾代。", "佐邑由東南，豈不知進退。", "吾宗秉全璞，楚得璆琳最。", "茅山就一徵，柏署起三載。", "道契非物理，神交無留礙。", "知我滄溟心，脫略腐儒輩。", "孟冬鑾輿出，陽谷羣臣會。", "半夜馳道喧，五侯擁軒蓋。", "是時燕齊客，獻術蓬瀛內。", "甚悅我皇心，得與王母對。", "賤臣欲干謁，稽首期殞碎。", "哲弟感我情，問易窮否泰。", "良馬足尚踠，寶刀光未淬。", "昨聞羽書飛，兵氣連朔塞。", "諸將多失律，廟堂始追悔。", "安能召書生，願得論要害。", "戎夷非草木，侵逐使狼狽。", "雖有屠城功，亦有降虜輩。", "兵糧如山積，恩澤如雨霈。", "羸卒不可興，磧地無足愛。", "若用匹夫策，坐令軍圍潰。", "不費黃金資，寧求白璧賚。"]'),
('a9e083a1-454a-4c43-ba9e-d14f55b3b05c','次汝中寄河南陳贊府','王昌齡','唐','唐诗','tang','','[]','汝山方聯延，伊水纔明滅。',72,'全唐诗/poet.tang.6000.json','["汝山方聯延，伊水纔明滅。", "遙見入楚雲，又此空館月。", "紛然馳夢想，不謂遠離別。", "京邑多歡娛，衡湘蹔沿越。", "明湖春草遍，秋桂白花發。", "豈惟長思君，日夕在魏闕。"]'),
('e2fec465-cea1-4829-b12d-3ba37a267562','同從弟銷南齋玩月憶山陰崔少府','王昌齡','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u6708\u4eae", "\u6000\u4eba"]','高臥南齋時，開帷月初吐。',60,'全唐诗/poet.tang.6000.json','["高臥南齋時，開帷月初吐。", "清輝淡水木，演漾在窗戶。", "苒苒幾盈虛，澄澄變今古。", "美人清江畔，是夜越吟苦。", "千里其如何，微風吹蘭杜。"]'),
('d5fdfac2-f74d-41d3-bcae-536c540185f2','代扶風主人答','王昌齡','唐','唐诗','tang','','["\u6292\u60c5", "\u6218\u4e89", "\u5199\u666f"]','殺氣凝不流，風悲日彩寒。',228,'全唐诗/poet.tang.6000.json','["殺氣凝不流，風悲日彩寒。", "浮埃起四遠，遊子彌不歡。", "依然宿扶風，沽酒聊自寬。", "寸心亦未理，長鋏誰能彈。", "主人就我飲，對我還慨歎。", "便泣數行淚，因歌行路難。", "十五役邊地，三回討樓蘭。", "連年不解甲，積日無所餐。", "將軍降匈奴，國使沒桑乾。", "去時三十萬，獨自還長安。", "不信沙場苦，君看刀箭瘢。", "鄉親悉零落，冢墓亦摧殘。", "仰攀青松枝，慟絕傷心肝。", "禽獸悲不去，路傍誰忍看。", "幸逢休明代，寰宇靜波瀾。", "老馬思伏櫪，長鳴力已殫。", "少年與運會，何事發悲端。", "天子初封禪，賢良刷羽翰。", "三邊悉如此，否泰亦須觀。"]'),
('6c8adce2-b817-4ee1-84ee-b9fd7c85c705','酬鴻臚裴主簿雨後北樓見贈','王昌齡','唐','唐诗','tang','','[]','暮霞照新晴，歸雲猶相逐。',120,'全唐诗/poet.tang.6000.json','["暮霞照新晴，歸雲猶相逐。", "有懷晨昏暇，想見登眺目。", "問禮侍彤襜，題詩訪茅屋。", "高樓多古今，陳事滿陵谷。", "地久微子封，臺餘孝王築。", "裴回顧霄漢，豁達俯川陸。", "遠水對孤城，長天向喬木。", "公門何清靜，列戟森已肅。", "不歎攜手稀，常思著鞭速。", "終當拂羽翰，輕舉隨鴻鵠。"]'),
('05a34af3-82f7-444f-8efc-b52e111e3b9c','送任五之桂林','王昌齡','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u5199\u666f"]','楚客醉孤舟，越水將引棹。',48,'全唐诗/poet.tang.6000.json','["楚客醉孤舟，越水將引棹。", "山爲兩鄉別，月帶千里貌。", "羇譴同繒綸，僻幽聞虎豹。", "桂林寒色在，苦節知所效。"]'),
('d1d0f9ec-2d44-404b-bcbf-a58ced75163c','山中別龐十','王昌齡','唐','唐诗','tang','','[]','幽娟松篠徑，月出寒蟬鳴。',48,'全唐诗/poet.tang.6000.json','["幽娟松篠徑，月出寒蟬鳴。", "散髮臥其下，誰知孤隱情。", "吟時白雲合，釣處玄潭清。", "瓊樹方杳靄，鳳兮保其貞。"]'),
('d290d360-9e99-4762-ad6e-7d138c6f8f14','留別伊闕張少府郭大都尉','王昌齡','唐','唐诗','tang','','[]','遷客就一醉，主人空金罍。',96,'全唐诗/poet.tang.6000.json','["遷客就一醉，主人空金罍。", "江湖青山底，欲去仍裴回。", "郭侯未相識，策馬伊川來。", "把手相勸勉，不應老塵埃。", "孟陽逢山舊，仙館留清才。", "日晚勸趣別，風長雲逐開。", "幸隨板輿遠，負譴何憂哉。", "唯有仗忠信，音書報雲雷。"]'),
('ad0dd3dc-9c4b-4e80-aee4-2f9d52a7b3e5','送韋十二兵曹','王昌齡','唐','唐诗','tang','','[]','縣職如長纓，終日檢我身。',132,'全唐诗/poet.tang.6000.json','["縣職如長纓，終日檢我身。", "平明趨郡府，不得展故人。", "故人念江湖，富貴如埃塵。", "迹在戎府掾，心遊天台春。", "獨立浦邊鶴，白雲長相親。", "南風忽至吳，分散還入秦。", "寒夜天光白，海淨月色真。", "對坐論歲暮，絃悲豈無因。", "平生馳驅分，非謂桮酒仁。", "出處兩不合，忠貞何由伸。", "看君孤舟去，且欲歌垂綸。"]'),
('43e802aa-a927-4265-913c-71934873c8da','東京府縣諸公與綦毋潛李頎相送至白馬寺宿','王昌齡','唐','唐诗','tang','','[]','鞍馬上東門，裴回入孤舟。',84,'全唐诗/poet.tang.6000.json','["鞍馬上東門，裴回入孤舟。", "賢豪相追送，即櫂千里流。", "赤岸落日在，空波微煙收。", "薄宦忘機括，醉來即淹留。", "月明見古寺，林外登高樓。", "南風開長廊，夏夜如涼秋。", "江月照吳縣，西歸夢中遊。"]'),
('f5c07ab4-d299-42a6-84c7-632a10972653','送東林廉上人歸廬山','王昌齡','唐','唐诗','tang','','["\u5e90\u5c71"]','石溪流已亂，苔徑人漸微。',60,'全唐诗/poet.tang.6000.json','["石溪流已亂，苔徑人漸微。", "日暮東林下，山僧還獨歸。", "昔爲廬峰意，況與遠公違。", "道性深寂寞，世情多是非。", "會尋名山去，豈復望清輝。"]'),
('f964804f-ca79-4a0f-9848-59fb38ef25fe','留別武陵袁丞','王昌齡','唐','唐诗','tang','','[]','皇恩暫遷謫，待罪逢知己。',48,'全唐诗/poet.tang.6000.json','["皇恩暫遷謫，待罪逢知己。", "從此武陵溪，孤舟二千里。", "桃花遺古岸，金澗流春水。", "誰識馬將軍，忠貞抱生死。"]'),
('b11d2370-bbb9-4b88-a7be-8ccffa020353','別劉諝','王昌齡','唐','唐诗','tang','','[]','天地寒更雨，蒼茫楚城陰。',72,'全唐诗/poet.tang.6000.json','["天地寒更雨，蒼茫楚城陰。", "一尊廣陵酒，十載衡陽心。", "倚仗不可料，悲歡豈易尋。", "相逢成遠別，後會何如今。", "身在江海上，雲連京國深。", "行當務功業，策馬何駸駸。"]'),
('6b160db2-46d2-46ad-8770-f69b92f0f5d9','岳陽別李十七越賓','王昌齡','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','相逢楚水寒，舟在洞庭驛。',120,'全唐诗/poet.tang.6000.json','["相逢楚水寒，舟在洞庭驛。", "具陳江波事，不異淪棄跡。", "杉上秋雨聲，悲切蒹葭夕。", "彈琴收餘響，來送千里客。", "平明孤帆心，歲晚濟代策。", "時在身未充，瀟湘不盈畫。", "湖小洲渚聯，澹淡煙景碧。", "魚鱉自有性，龜龍無能易。", "譴黜同所安，風土任所適。", "閉門觀玄化，攜手遺損益。"]'),
('419db4f0-72c6-4a05-aa1f-d5865f9cea66','留別岑參兄弟','王昌齡','唐','唐诗','tang','','[]','江城建業樓，山盡滄海頭。',144,'全唐诗/poet.tang.6000.json','["江城建業樓，山盡滄海頭。", "副職守茲縣，東南櫂孤舟。", "長安故人宅，秣馬經前秋。", "便以風雪暮，還爲縱飲留。", "貂蟬七葉貴，鴻鵠萬里遊。", "何必念鐘鼎，所在烹肥牛。", "爲君嘯一曲，且莫彈箜篌。", "徒見枯者豔，誰言直如鉤。", "岑家雙瓊樹，騰光難爲儔。", "誰言青門悲，俯期吳山幽。", "日西石門嶠，月吐金陵洲。", "追隨探靈怪，豈不驕王侯。"]'),
('4d6dee47-6ddd-441f-b9d8-6db3ebad15ce','送劉眘虛歸取宏詞解','王昌齡','唐','唐诗','tang','','[]','太清聞海鶴，遊子引鄉眄。',48,'全唐诗/poet.tang.6000.json','["太清聞海鶴，遊子引鄉眄。", "聲隨羽儀遠，勢與歸雲便。", "青桂春再榮，白雲暮來變。", "遷飛在禮儀，豈復淚如霰。"]'),
('ef29aec7-ca2f-4211-a43f-0c8f911b4a40','巴陵別劉處士','王昌齡','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','劉生隱岳陽，心遠洞庭水。',72,'全唐诗/poet.tang.6000.json','["劉生隱岳陽，心遠洞庭水。", "偃帆入山郭，一宿楚雲裏。", "竹映秋館深，月寒江風起。", "煙波桂陽接，日夕數千里。", "嫋嫋清夜猿，孤舟坐如此。", "湘中有來鴈，雨雪候音旨。"]'),
('b33dda30-2f9e-4737-9b72-c46bca256ae7','宿裴氏山莊','王昌齡','唐','唐诗','tang','','[]','蒼蒼竹林暮，吾亦知所投。',48,'全唐诗/poet.tang.6000.json','["蒼蒼竹林暮，吾亦知所投。", "靜坐山齋月，清溪聞遠流。", "西峰下微雨，向曉白雲收。", "遂解塵中組，終南春可遊。"]'),
('04814106-730a-460e-8fb8-4fc831c69c19','淇上酬薛據兼寄郭微','王昌齡','唐','唐诗','tang','','[]','自從別京華，我心乃蕭索。',216,'全唐诗/poet.tang.6000.json','["自從別京華，我心乃蕭索。", "十年守章句，萬里空寥落。", "北上登薊門，茫茫見沙漠。", "倚劒對風塵，慨然思衞霍。", "拂衣去燕趙，驅馬悵不樂。", "天長滄洲路，日暮邯鄲郭。", "酒肆或淹留，漁澤屢棲泊。", "獨行備艱難，孰辭千鼎鑊。", "皇情念淳古，時俗何浮薄。", "理道須任賢，安人在求瘼。", "故交負奇才，逸氣包謇諤。", "隱軫經濟策，縱橫建安作。", "才望忽先鳴，風期無宿諾。", "飄颻勞州縣，迢遞限言謔。", "東馳眇貝丘，西顧彌虢略。", "淇水徒自深，浮雲不堪託。", "吾謀適可用，天道豈遼廓。", "不然買山田，一身與耕鑿。"]'),
('23ac0351-1020-42fc-bdc8-bfef10d6884d','詠史','王昌齡','唐','唐诗','tang','','[]','荷畚至洛陽，杖策遊北門。',96,'全唐诗/poet.tang.6000.json','["荷畚至洛陽，杖策遊北門。", "天下盡兵甲，豺狼滿中原。", "明夷方遘患，顧我徒崩犇。", "自慙菲薄才，誤蒙國士恩。", "位重任亦重，時危志彌敦。", "西北未及終，東南不可吞。", "進則耻保躬，退乃爲觸藩。", "歎息嵩山老，而後知其尊。"]'),
('1239be59-986f-4e78-bf47-05890b138c78','雜興','王昌齡','唐','唐诗','tang','','[]','握中銅匕首，粉剉楚山鐵。',72,'全唐诗/poet.tang.6000.json','["握中銅匕首，粉剉楚山鐵。", "義士頻報讎，殺人不曾缺。", "可悲燕丹事，終被狼虎滅。", "一舉無兩全，荆軻遂爲血。", "誠知匹夫勇，何取萬人傑。", "無道吞諸侯，坐見九州裂。"]'),
('57a79dc1-1257-4ed3-a9ed-73dc32a3b9f2','秋興','王昌齡','唐','唐诗','tang','','[]','日暮西北堂，涼風洗脩木。',48,'全唐诗/poet.tang.6000.json','["日暮西北堂，涼風洗脩木。", "著書在南窗，門館常肅肅。", "苔草延古意，視聽轉幽獨。", "或問余所營，刈黍就寒谷。"]'),
('c6a5ec30-5c21-45b2-948d-19a9fd188b08','齋心','王昌齡','唐','唐诗','tang','','[]','女蘿覆石壁，溪水幽濛朧。',60,'全唐诗/poet.tang.6000.json','["女蘿覆石壁，溪水幽濛朧。", "紫葛蔓黃花，娟娟寒露中。", "朝飲花上露，夜臥松下風。", "雲英化爲水，光采與我同。", "日月蕩精魄，寥寥天宇空。"]'),
('6769d8dd-8a90-4329-8745-1cb2913e2c6b','獨遊','王昌齡','唐','唐诗','tang','','[]','林臥情每閒，獨遊景常晏。',84,'全唐诗/poet.tang.6000.json','["林臥情每閒，獨遊景常晏。", "時從灞陵下，垂釣往南澗。", "手攜雙鯉魚，目送千里鴈。", "悟彼飛有適，知此罹憂患。", "放之清冷泉，因得省疎慢。", "永懷青岑客，廻首白雲間。", "神超物無違，豈繫名與宦。"]'),
('90d156d0-52f7-4ad1-b2ee-cc00e8c71d0c','香積寺禮拜萬廻平等二聖僧塔','王昌齡','唐','唐诗','tang','','[]','真無御化來，借有乘化歸。',84,'全唐诗/poet.tang.6000.json','["真無御化來，借有乘化歸。", "如彼雙塔內，孰能知是非。", "愚也駭蒼生，聖哉爲帝師。", "當爲時世出，不由天地資。", "萬廻主此方，平等性無違。", "今我一禮心，億劫同不移。", "肅肅松柏下，諸天來有時。"]'),
('c0667b06-7bbd-4535-bd82-674f80de66e8','就道士問周易參同契','王昌齡','唐','唐诗','tang','','[]','仙人騎白鹿，髮短耳何長。',60,'全唐诗/poet.tang.6000.json','["仙人騎白鹿，髮短耳何長。", "時余采菖蒲，忽見嵩之陽。", "稽首求丹經，乃出懷中方。", "披讀了不悟，歸來問嵇康。", "嗟余無道骨，發我入太行。"]'),
('6c707d94-cd1d-4d2c-9e43-f01c4c833bf5','諸官遊招隱寺','王昌齡','唐','唐诗','tang','','[]','山館人已空，青蘿換風雨。',96,'全唐诗/poet.tang.6000.json','["山館人已空，青蘿換風雨。", "自從永明世，月向龍宮吐。", "鑿井長幽泉，白雲今如古。", "應真坐松柏，錫杖挂窗戶。", "口云七十餘，能救諸有苦。", "回指巖樹花，如聞道場鼓。", "金色身壤滅，真如性無主。", "僚友同一心，清光遣誰取。"]'),
('a278c8c6-278f-4915-a5be-445f4510fcfc','宴南亭','王昌齡','唐','唐诗','tang','','[]','寒江暎村林，亭上納鮮潔。',72,'全唐诗/poet.tang.6000.json','["寒江暎村林，亭上納鮮潔。", "楚客共閑飲，靜坐金管闋。", "酣竟日入山，暝來雲歸穴。", "城樓空杳靄，猿鳥備清切。", "物狀如絲綸，上心爲予決。", "訪君東溪事，早晚樵路絕。"]'),
('2baab2c0-0277-404b-b393-f2ded40154e9','何九於客舍集','王昌齡','唐','唐诗','tang','','[]','客有住桂陽，亦如巢林鳥。',60,'全唐诗/poet.tang.6000.json','["客有住桂陽，亦如巢林鳥。", "罍觴且終宴，功業曾未了。", "山月空霽時，江明高樓曉。", "門前泊舟檝，行次入松篠。", "此意投贈君，滄波風褭褭。"]'),
('c91fabc9-f344-41bb-8737-233d0063b9f3','洛陽尉劉晏與府掾諸公茶集天宮寺岸道上人房','王昌齡','唐','唐诗','tang','','[]','良友呼我宿，月明懸天宮。',72,'全唐诗/poet.tang.6000.json','["良友呼我宿，月明懸天宮。", "道安風塵外，灑掃青林中。", "削去府縣理，豁然神機空。", "自從三湘還，始得今夕同。", "舊居太行北，遠宦滄溟東。", "各有四方事，白雲處處通。"]'),
('282a0ad4-b2d4-466d-af04-cdda44a7a75d','觀江淮名勝圖','王昌齡','唐','唐诗','tang','','[]','刻意吟雲山，尤知隱淪妙。',132,'全唐诗/poet.tang.6000.json','["刻意吟雲山，尤知隱淪妙。", "遠公何爲者，再詣臨海嶠。", "而我高其風，披圖得遺照。", "援毫無逃境，遂展千里眺。", "淡掃荆門煙，明標赤城燒。", "青葱林間嶺，隱見淮海徼。", "但指香爐頂，無聞白猿嘯。", "沙門既云滅，獨往豈殊調。", "感對懷拂衣，胡寧事漁釣。", "安期始遺舃，千古謝榮耀。", "投跡庶可齊，滄浪有孤棹。"]'),
('e2e47b92-21d8-42c9-ba84-3812c4f83be9','灞上閒居','王昌齡','唐','唐诗','tang','','[]','鴻都有歸客，偃臥滋陽村。',84,'全唐诗/poet.tang.6000.json','["鴻都有歸客，偃臥滋陽村。", "軒冕無枉顧，清川照我門。", "空林網夕陽，寒鳥赴荒園。", "廓落時得意，懷哉莫與言。", "庭前有孤鶴，欲啄常翩翻。", "爲我銜素書，弔彼顏與原。", "二君既不朽，所以慰其魂。"]'),
('9385e47f-e958-4a76-8886-fe62c5fa353a','風涼原上作','王昌齡','唐','唐诗','tang','','[]','陰岑宿雲歸，烟霧濕松柏。',96,'全唐诗/poet.tang.6000.json','["陰岑宿雲歸，烟霧濕松柏。", "風淒日初曉，下嶺望川澤。", "遠山無晦明，秋水千里白。", "佳氣盤未央，聖人在凝碧。", "關門阻天下，信是帝王宅。", "海內方晏然，廟堂有奇策。", "時貞守全運，罷去遊說客。", "予忝蘭臺人，幽尋免貽責。"]'),
('00fc6fd0-df00-4284-8c21-b5428b3fbfe3','裴六書堂','王昌齡','唐','唐诗','tang','','[]','閑堂閉空陰，竹林但清響。',36,'全唐诗/poet.tang.6000.json','["閑堂閉空陰，竹林但清響。", "窗下長嘯客，區中無遺想。", "經綸精微言，兼濟當獨往。"]'),
('a8cfc3c2-8ee8-414b-bc14-ca88cbc074d9','江上聞笛','王昌齡','唐','唐诗','tang','','[]','橫笛怨江月，扁舟何處尋。',96,'全唐诗/poet.tang.6000.json','["橫笛怨江月，扁舟何處尋。", "聲長楚山外，曲繞胡關深。", "相去萬餘里，遙傳此夜心。", "寥寥浦漵寒，響盡惟幽林。", "不知誰家子，復奏邯鄲音。", "水客皆擁棹，空霜遂盈襟。", "羸馬望北走，遷人悲越吟。", "何當邊草白，旌節隴城陰。"]'),
('4b44bc27-50b9-4144-be84-410f7941e8e6','太湖秋夕','王昌齡','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','水宿煙雨寒，洞庭霜落微。',36,'全唐诗/poet.tang.6000.json','["水宿煙雨寒，洞庭霜落微。", "月明移舟去，夜靜魂夢歸。", "暗覺海風度，蕭蕭聞鴈飛。"]'),
('a529e61e-b9c4-4457-b11f-e1a8adb0dc3e','趙十四兄見訪','王昌齡','唐','唐诗','tang','','[]','客來舒長簟，開閤延清風。',72,'全唐诗/poet.tang.6000.json','["客來舒長簟，開閤延清風。", "但有無絃琴，共君盡尊中。", "晚來常讀易，頃者欲還嵩。", "世事何須道，黃精且養蒙。", "嵇康殊寡識，張翰獨知終。", "忽憶鱸魚鱠，扁舟往江東。"]'),
('60afe2ef-0e28-4455-bac8-24aa00cd1a74','過華陰','王昌齡','唐','唐诗','tang','','["\u534e\u5c71"]','雲起太華山，雲山互明滅。',84,'全唐诗/poet.tang.6000.json','["雲起太華山，雲山互明滅。", "東峯始含景，了了見松雪。", "羇人感幽棲，窅暎轉奇絕。", "欣然忘所疲，永望吟不輟。", "信宿百餘里，出關玩新月。", "何意昨來心，遇物遂遷別。", "人生屢如此，何以肆愉悅。"]'),
('1e928c12-d3b1-4840-8867-576663f81d93','九江口作','王昌齡','唐','唐诗','tang','','[]','漭漭江勢闊，雨開潯陽秋。',72,'全唐诗/poet.tang.6000.json','["漭漭江勢闊，雨開潯陽秋。", "驛門是高岸，望盡黃蘆洲。", "水與五谿合，心期萬里遊。", "明時無棄才，謫去隨孤舟。", "鷙鳥立寒木，丈夫佩吳鉤。", "何當報君恩，却繫單于頭。"]'),
('d460a10d-224c-41e0-9665-a35da5b44b74','大梁途中作','王昌齡','唐','唐诗','tang','','[]','怏怏步長道，客行渺無端。',48,'全唐诗/poet.tang.6000.json','["怏怏步長道，客行渺無端。", "郊原欲下雪，天地稜稜寒。", "當時每酣醉，不覺行路難。", "今日無酒錢，悽惶向誰歎。"]'),
('855dcf8e-3e27-4525-8560-7d6d8d0e87f8','途中作','王昌齡','唐','唐诗','tang','','[]','遊人愁歲晏，早起遵王畿。',96,'全唐诗/poet.tang.6000.json','["遊人愁歲晏，早起遵王畿。", "墜葉吹未曉，疎林月微微。", "驚禽棲不定，寒獸相因依。", "歎此霜露下，復聞鴻雁飛。", "渺然江南意，惜與中途違。", "羇旅悲壯髮，別離念征衣。", "永圖豈勞止，明節期所歸。", "寧厭楚山曲，無人長掩扉。"]'),
('ed95661a-f947-4d65-a60e-3bd852c3e8b5','山行入涇州','王昌齡','唐','唐诗','tang','','[]','倦此山路長，停驂問賓御。',96,'全唐诗/poet.tang.6000.json','["倦此山路長，停驂問賓御。", "林巒信回惑，白日落何處。", "徙倚望長風，滔滔引歸慮。", "微雨隨雲收，濛濛傍山去。", "西臨有邊邑，北走盡亭戍。", "涇水橫白烟，州城隱寒樹。", "所嗟異風俗，已自少情趣。", "豈伊懷土多，觸目忻所遇。"]'),
('5f9ae5aa-5395-44d6-ae8a-17ea0d9b686f','小敷谷龍潭祠作','王昌齡','唐','唐诗','tang','','[]','崖谷歕疾流，地中有雷集。',144,'全唐诗/poet.tang.6000.json','["崖谷歕疾流，地中有雷集。", "百泉勢相蕩，巨石皆却立。", "跳波沸崢嶸，深處不可挹。", "昏爲蛟龍怒，清見雲雨入。", "靈怪祟偏祠，廢興自茲邑。", "沈淫頃多昧，檐宇遂不葺。", "吾聞被明典，盛德惟世及。", "生人載山川，血食報原隰。", "豈伊駭微險，將以循甿揖。", "口飛振呂梁，忠信亦我習。", "波流浸已廣，悔吝在所汲。", "谿水有清源，褰裳靡沾濕。"]'),
('6ad65b95-a0ca-4c3e-8e61-5c30f3982fcb','段宥廰孤桐','王昌齡','唐','唐诗','tang','','[]','鳳皇所宿處，月暎孤桐寒。',48,'全唐诗/poet.tang.6000.json','["鳳皇所宿處，月暎孤桐寒。", "槁葉零落盡，空柯蒼翠殘。", "虛心誰能見，直影非無端。", "響發調尚苦，清商勞一彈。"]'),
('d96acefe-8efc-46bc-b85e-6e4ad42098f9','琴','王昌齡','唐','唐诗','tang','','[]','孤桐秘虛鳴，樸素傳幽真。',48,'全唐诗/poet.tang.6000.json','["孤桐秘虛鳴，樸素傳幽真。", "髣髴絃指外，遂見初古人。", "意遠風雪苦，時來江山春。", "高宴未終曲，誰能辨經綸。"]'),
('3ffb7a6f-2fa1-4d50-bd51-830cede927b1','初日','王昌齡','唐','唐诗','tang','','[]','初日淨金閨，先照牀前暖。',36,'全唐诗/poet.tang.6000.json','["初日淨金閨，先照牀前暖。", "斜光入羅幕，稍稍親絲管。", "雲髮不能梳，楊花更吹滿。"]'),
('635319ce-1936-4ca2-8eff-6d074e7f23b3','失題','王昌齡','唐','唐诗','tang','','[]','姦雄乃得志，遂使羣心搖。',36,'全唐诗/poet.tang.6000.json','["姦雄乃得志，遂使羣心搖。", "赤風蕩中原，烈火無遺巢。", "一人計不用，萬里空蕭條。"]'),
('69419d0e-57f6-415c-a9dc-3af999ba4af1','贈宇文中丞','王昌齡','唐','唐诗','tang','','[]','僕本濩落人，辱當州郡使。',96,'全唐诗/poet.tang.6000.json','["僕本濩落人，辱當州郡使。", "量力頗及早，謝歸今即已。", "蕭蕭若凌虛，衿帶頃消靡。", "車服卒然來，涔陽作遊子。", "鬱鬱寡開顏，默默獨行李。", "忽逢平生友，一笑方在此。", "秋清寧風日，楚思浩雲水。", "爲語弋林者，冥冥鴻遠矣。"]'),
('b3e4a490-0aea-4eae-84c7-9698ae1ae112','箜篌引','王昌齡','唐','唐诗','tang','','[]','盧谿郡南夜泊舟，夜聞兩岸羌戎謳。',336,'全唐诗/poet.tang.6000.json','["盧谿郡南夜泊舟，夜聞兩岸羌戎謳。", "其時月黑猿啾啾，微雨霑衣令人愁。", "有一遷客登高樓，不言不寐彈箜篌。", "彈作薊門桑葉秋，風沙颯颯青冢頭。", "將軍鐵驄汗血流，深入匈奴戰未休。", "黃旗一點兵馬收，亂殺胡人積如丘。", "瘡病驅來配邊州，仍披漠北羔羊裘。", "顏色飢枯掩面羞，眼眶淚滴深兩眸。", "思還本鄉食犛牛，欲語不得指咽喉。", "或有強壯能吚嚘，意說被他邊將讎。", "五世屬藩漢主留，碧毛氈帳河曲遊。", "橐駞五萬部落稠，勅賜飛鳳金兜鍪。", "爲君百戰如過籌，靜掃陰山無鳥投。", "家藏鐵券特承優，黃金千斤不稱求。", "九族分離作楚囚，深谿寂寞絃苦幽。", "草木悲感聲颼飀，僕本東山爲國憂。", "明光殿前論九疇，簏讀兵書盡冥搜。", "爲君掌上施權謀，洞曉山川無與儔。", "紫宸詔發遠懷柔，搖筆飛霜如奪鉤。", "鬼神不得知其由，憐愛蒼生比蚍蜉。", "朔河屯兵須漸抽，盡遣降來拜御溝。"]'),
('a2c9541f-6f63-4982-9b55-a1db3d69074c','烏棲曲','王昌齡','唐','唐诗','tang','','[]','白馬逐朱車，黃昏入狹邪。',42,'全唐诗/poet.tang.6000.json','["白馬逐朱車，黃昏入狹邪。", "柳樹烏爭宿，爭枝未得飛上屋。", "東房少婦壻從軍，每聽烏啼知夜分。"]'),
('d9aeead3-57a1-45a0-a5bc-11c95f29d912','城傍曲','王昌齡','唐','唐诗','tang','','[]','秋風鳴桑條，草白狐兔驕。',44,'全唐诗/poet.tang.6000.json','["秋風鳴桑條，草白狐兔驕。", "邯鄲飲來酒未消，城北原平掣皂鵰。", "射殺空營兩騰虎，廻身却月佩弓弰。"]'),
('6a64d7ec-1335-4ce5-b62c-32df33b30023','行路難','王昌齡','唐','唐诗','tang','','[]','雙絲作綆繫銀瓶，百尺寒泉轆轤上。',155,'全唐诗/poet.tang.6000.json','["雙絲作綆繫銀瓶，百尺寒泉轆轤上。", "懸絲一絕不可望，似妾傾心在君掌。", "人生意氣好遷捐，只重狂花不重賢。", "宴罷調箏奏離鶴，廻嬌轉盼泣君前。", "君不見眼前事，豈保須臾心勿異。", "西山日下雨足稀，側有浮雲無所寄。", "但願莫忘前者言，剉骨黃塵亦無愧。", "行路難，勸君酒，莫辭煩，美酒千鍾猶可盡，心中片愧何可論。", "一聞漢主思故劍，使妾長嗟萬古魂。"]'),
('a434b036-2f84-4c96-9c2c-69220136bc26','奉贈張荆州','王昌齡','唐','唐诗','tang','','[]','祝融之峯紫雲銜，翠如何其雪嶄嵓。',64,'全唐诗/poet.tang.6000.json','["祝融之峯紫雲銜，翠如何其雪嶄嵓。", "邑西有路緣石壁，我欲從之臥穹嵌。", "魚有心兮脫網罟，江無人兮鳴楓杉。", "王君飛舄仍未去，蘇耽宅中意遙緘。"]'),
('c4fa2499-efbe-4dbe-923e-595d1287d1f7','駕出長安','王昌齡','唐','唐诗','tang','','[]','聖德超千古，皇風扇九圍。',48,'全唐诗/poet.tang.6000.json','["聖德超千古，皇風扇九圍。", "天廻萬象出，駕動六龍飛。", "淑氣來黃道，祥雲覆紫微。", "太平多扈從，文物有光輝。"]'),
('6330cca9-54a6-4827-a2c1-de8220f9c496','駕幸河東','王昌齡','唐','唐诗','tang','','[]','晉水千廬合，汾橋萬國從。',48,'全唐诗/poet.tang.6000.json','["晉水千廬合，汾橋萬國從。", "開唐天業盛，入沛聖恩濃。", "下輦廻三象，題碑任六龍。", "睿明懸日月，千歲此時逢。"]'),
('81f5afd8-0601-4111-a7cb-5d51c7e3ce1e','胡笳曲','王昌齡','唐','唐诗','tang','','[]','城南虜已合，一夜幾重圍。',48,'全唐诗/poet.tang.6000.json','["城南虜已合，一夜幾重圍。", "自有金笳引，能霑出塞衣。", "聽臨關月苦，清入海風微。", "三奏高樓曉，胡人掩涕歸。"]'),
('fe4f6fe3-9d6e-4cc3-8b19-519690162ee1','潞府客亭寄崔鳳童','王昌齡','唐','唐诗','tang','','[]','蕭條郡城閉，旅館空寒烟。',48,'全唐诗/poet.tang.6000.json','["蕭條郡城閉，旅館空寒烟。", "秋月對愁客，山鐘搖暮天。", "新知偶相訪，斗酒情依然。", "一宿阻長會，清風徒滿川。"]'),
('a3f81284-82d4-45a4-a5b7-1459a14ee51f','和振上人秋夜懷士會','王昌齡','唐','唐诗','tang','','[]','白露傷草木，山風吹夜寒。',48,'全唐诗/poet.tang.6000.json','["白露傷草木，山風吹夜寒。", "遙林夢親友，高興發雲端。", "郭外秋聲急，城邊月色殘。", "瑤琴多遠思，更爲客中彈。"]'),
('3b3591a3-51fc-40fa-aff4-58931f659018','送李擢遊江東','王昌齡','唐','唐诗','tang','','[]','清洛日夜漲，微風引孤舟。',48,'全唐诗/poet.tang.6000.json','["清洛日夜漲，微風引孤舟。", "離腸便千里，遠夢生江樓。", "楚國橙橘暗，吳門煙雨愁。", "東南具今古，歸望山雲秋。"]'),
('e367588d-d1a1-4835-81ca-93e11c86b416','沙苑南渡頭','王昌齡','唐','唐诗','tang','','[]','秋霧連雲白，歸心浦漵懸。',36,'全唐诗/poet.tang.6000.json','["秋霧連雲白，歸心浦漵懸。", "津人空守纜，村館復臨川。", "篷隔蒼茫雨，波連演漾田。"]'),
('acf02553-a3dc-433d-800c-f7b1df696fe4','客廣陵','王昌齡','唐','唐诗','tang','','[]','樓頭廣陵近，九月在南徐。',48,'全唐诗/poet.tang.6000.json','["樓頭廣陵近，九月在南徐。", "秋色明海縣，寒烟生里閭。", "夜帆歸楚客，昨日度江書。", "爲問易名叟，垂綸不見魚。"]'),
('31f007fa-da7e-4b7a-9531-c55b74675814','靜法師東齋','王昌齡','唐','唐诗','tang','','[]','築室在人境，遂得真隱情。',48,'全唐诗/poet.tang.6000.json','["築室在人境，遂得真隱情。", "春盡草木變，雨來池館清。", "琴書全雅道，視聽已無生。", "閉戶脫三界，白雲自虛盈。"]'),
('f67f7764-1321-4c2e-acdd-ee0b70946616','素上人影塔','王昌齡','唐','唐诗','tang','','[]','物化同枯木，希夷明月珠。',48,'全唐诗/poet.tang.6000.json','["物化同枯木，希夷明月珠。", "本來生滅盡，何者是虛無。", "一坐看如故，千齡獨向隅。", "至人非別有，方外不應殊。"]'),
('494d0e6c-6ba8-4675-8346-f2d3c2dc31e1','遇薛明府謁聰上人','王昌齡','唐','唐诗','tang','','[]','欣逢柏梁故，共謁聰公禪。',48,'全唐诗/poet.tang.6000.json','["欣逢柏梁故，共謁聰公禪。", "石室無人到，繩牀見虎眠。", "陰崖常抱雪，枯澗爲生泉。", "出處雖雲異，同歡在法筵。"]');
